/* AUTO-GENERATED — Montana Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["MT"] = {"code":"MT","name":"Montana","agency":"Montana MVD","agencyShort":"MVD","handbook":"https://mvdmt.gov/wp-content/uploads/2026/03/Montana-CDL-Manual-2026.pdf","links":{},"en":[{"q":"On Montana highways, what is the maximum legal width of a commercial vehicle and its load without an oversize permit?","options":["8 feet 0 inches (96 inches)","9 feet 0 inches (108 inches)","10 feet 0 inches (120 inches)","8 feet 6 inches (102 inches)"],"answer":3,"explanation":"Montana limits total outside vehicle width to 102 inches (8 feet 6 inches), per MCA 61-10-102 and the Montana Commercial Vehicle Size and Weight and Safety Trucker's Handbook ('Legal Dimensions'). Loads wider than this require a permit.","handbook":"","hbref":""},{"q":"What is the maximum legal height of a vehicle, unladen or with load, on Montana highways?","options":["13 feet 6 inches","14 feet","15 feet","15 feet 6 inches"],"answer":1,"explanation":"Under MCA 61-10-103 and the Montana Trucker's Handbook, a vehicle (unladen or loaded) may not exceed 14 feet in height. Greater heights require an over-dimensional permit.","handbook":"","hbref":""},{"q":"Without a permit, what is the maximum length of a semitrailer in a truck tractor-semitrailer combination in Montana?","options":["48 feet","57 feet","53 feet","60 feet"],"answer":2,"explanation":"MCA 61-10-104 and the Montana Trucker's Handbook set the maximum semitrailer length at 53 feet (excluding portions not designed to carry load). A term permit can extend this to 57 feet under MCA 61-10-124.","handbook":"","hbref":""},{"q":"In Montana, what is the maximum gross weight allowed on a single axle without an overweight permit?","options":["20,000 pounds","18,000 pounds","22,400 pounds","34,000 pounds"],"answer":0,"explanation":"Per MCA 61-10-107 and the Montana Trucker's Handbook, the total weight on one or more axles whose centers are not more than 40 inches apart may not exceed 20,000 pounds. This matches the federal Interstate single-axle limit.","handbook":"","hbref":""},{"q":"What is the maximum gross weight allowed on a tandem axle group in Montana without an overweight permit?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"answer":1,"explanation":"MCA 61-10-107 and the Montana Trucker's Handbook state that no two consecutive axles more than 40 inches but less than 96 inches apart may carry a load over 34,000 pounds.","handbook":"","hbref":""},{"q":"How does Montana define a 'tandem axle' for weight-limit purposes?","options":["Two axles exactly 40 inches apart","Two consecutive axles more than 40 inches and less than 96 inches apart","Any two axles within 120 inches of each other","Two axles more than 96 inches apart"],"answer":1,"explanation":"MCA 61-10-107 (cited in the Montana Trucker's Handbook) defines a tandem axle as two consecutive axles more than 40 inches but less than 96 inches apart; such a group is limited to 34,000 pounds.","handbook":"","hbref":""},{"q":"What is the Montana bridge formula used to calculate the maximum allowable gross weight on a group of axles?","options":["W = 1000((LN/(N+1)) + 10N + 20)","W = 250((LN/(N-1)) + 6N + 18)","W = 500((LN/(N+1)) + 12N + 12)","W = 500((LN/(N-1)) + 12N + 36)"],"answer":3,"explanation":"The Montana bridge formula (matching the federal Bridge Formula B) is W = 500((LN/(N-1)) + 12N + 36), where L is the distance in feet between the outer axles of a group and N is the number of axles, per MCA 61-10-107 and the Montana Trucker's Handbook.","handbook":"","hbref":""},{"q":"In Montana, when do the single- and tandem-axle weight limits override (supersede) the bridge formula result?","options":["For all axles more than 120 inches apart","Only on the Interstate System","For all axles not more than 96 inches apart","Never; the bridge formula always controls"],"answer":2,"explanation":"The Montana Trucker's Handbook explains that single- or tandem-axle weight limits supersede the bridge formula limits for all axles not more than 96 inches apart (MCA 61-10-107).","handbook":"","hbref":""},{"q":"What is the maximum gross weight Montana allows for a vehicle combination hauling reducible (divisible) loads?","options":["80,000 pounds","105,500 pounds","131,060 pounds","129,000 pounds"],"answer":2,"explanation":"Per MCA 61-10-107 and the Montana Gross Vehicle Weight Chart in the Trucker's Handbook, the maximum gross weight for reducible loads is 131,060 pounds.","handbook":"","hbref":""},{"q":"How are steering (front) axle weights limited under Montana rules?","options":["To the tire manufacturer's rated capacity, not to exceed 20,000 pounds","To exactly 12,000 pounds in all cases","To 34,000 pounds like a tandem","There is no limit on the steering axle"],"answer":0,"explanation":"The Montana Trucker's Handbook notes that steering axles are limited to the manufacturer's rated capacity stamped on the tire sidewall, not to exceed 20,000 pounds (MCA 61-10-107).","handbook":"","hbref":""},{"q":"Without a permit, what is the maximum overall combination length for vehicle combinations not otherwise specified on Montana highways?","options":["65 feet","75 feet","80 feet","70 feet"],"answer":1,"explanation":"MCA 61-10-104 and the Montana Trucker's Handbook limit such combinations to 75 feet overall (except combinations allowed greater length, such as tractors pulling a 53-foot trailer, which have no overall-length limit).","handbook":"","hbref":""},{"q":"A tractor pulling a single 53-foot (or shorter) trailer in Montana is subject to which length rule?","options":["It must still stay within 65 feet overall","It always requires a single-trip permit","No overall length permit is required regardless of total length","It is capped at 70 feet overall"],"answer":2,"explanation":"The Montana Trucker's Handbook states that no over-length permit is required for a tractor pulling a 53-foot (or shorter) trailer, regardless of overall combination length (MCA 61-10-104).","handbook":"","hbref":""},{"q":"Which Montana agency section issues oversize and overweight permits and gross-vehicle-weight fees for commercial vehicles?","options":["The Montana Highway Patrol licensing desk","The Motor Carrier Services (MCS) Division Permitting Section of MDT","The county sheriff's office","The Federal Motor Carrier Safety Administration"],"answer":1,"explanation":"Per the Montana Trucker's Handbook, the Motor Carrier Services (MCS) Division Permitting Section of the Montana Department of Transportation issues size/weight permits; carriers may also self-issue online (ePART / eTRIPS).","handbook":"","hbref":""},{"q":"An over-dimensional load that is only a single trip and not licensed for Montana requires which kind of permit?","options":["A permanent term permit only","A custom combine permit","No permit, since it is a one-time move","A single-trip over-dimensional permit, void upon leaving the state"],"answer":3,"explanation":"The Montana Trucker's Handbook provides that operators on a temporary trip basis must obtain a single-trip over-dimensional permit (for loads over 8'6\" wide, 14' high, 75' long, or single unit over 55'); the permit is void upon leaving the state.","handbook":"","hbref":""},{"q":"What minimum liability insurance does Montana require for issuance of an oversize/overweight (special) permit?","options":["$300,000 combined single limit","$500,000 combined single limit","$1,000,000 combined single limit per occurrence","$750,000 combined single limit"],"answer":2,"explanation":"The Montana Trucker's Handbook's General Oversize Permit Requirements specify a minimum of $1,000,000 combined single limit bodily injury and property damage liability per occurrence.","handbook":"","hbref":""},{"q":"Montana's Winter Weight Term Permit allows how much excess weight, and on which roads?","options":["10% excess on non-Interstate highways, December 1 through March 7","20% excess on all highways, year-round","10% excess on Interstate highways only","15% excess on non-Interstate highways, November 1 through April 1"],"answer":0,"explanation":"The Montana Trucker's Handbook states the Winter Weight Term Permit allows 10% excess weight on non-Interstate highways from December 1 through March 7, and can be suspended during early thaws.","handbook":"","hbref":""},{"q":"A non-resident custom combine operation in Montana may pay a special permit fee in lieu of GVW fees and oversize permits of how much per unit?","options":["$20 per unit","$35 per unit","$105 per unit","$40 per unit"],"answer":3,"explanation":"Under MCA 15-24-301 and 61-10-130 (and ARM 18.8.426), the Montana Trucker's Handbook provides that a non-resident custom combine operation may pay a $40 special permit fee per unit (residents pay 35% GVW fees plus $20 per unit).","handbook":"","hbref":""},{"q":"On the Montana Interstate System, what is the federal single-axle weight limit that also applies in Montana?","options":["20,000 pounds","18,000 pounds","21,000 pounds","24,000 pounds"],"answer":0,"explanation":"The Montana Trucker's Handbook expressly notes the federal single-axle weight limit on the Interstate System is 20,000 pounds, consistent with Montana's general single-axle limit under MCA 61-10-107.","handbook":"","hbref":""},{"q":"For hay or straw transport incidental to farming, Montana allows a vehicle height up to what maximum, and within what distance?","options":["15 feet 6 inches, for no more than 25 miles","16 feet, for no more than 50 miles","14 feet 6 inches, for no more than 10 miles","15 feet, for no more than 100 miles"],"answer":0,"explanation":"MCA 61-10-103 provides a farm exception: an implement of husbandry or vehicle hauling hay or straw may reach 15 feet 6 inches if traveling no more than 25 miles incidental to farming and not passing under obstacles 17 feet or lower.","handbook":"","hbref":""},{"q":"A non-divisible load that exceeds the bridge formula limit but does NOT exceed legal axle weights is charged a Montana permit fee based on what?","options":["A flat $200 annual fee regardless of distance","The vehicle's registered gross weight only","10% of the cargo's value","Trip mileage (e.g., $10 up to 100 miles, $30 for 101-199, $50 for 200+ miles)"],"answer":3,"explanation":"The Montana Trucker's Handbook ('Overweight On Bridge - Legal Axle Weights - Non-Divisible Loads,' MCA 61-10-107) charges $10 up to 100 miles, $30 for 101-199 miles, and $50 for 200 miles and over.","handbook":"","hbref":""},{"q":"In Montana, which CDL class is required to operate a combination of vehicles with a gross combination weight rating (GCWR) of 26,001 pounds or more, when the unit(s) being towed exceed 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"Per the Montana CDL Manual (Classifications, MT-2), a Class A combination vehicle has a GCWR of 11,794 kg (26,001 lbs) or more provided the unit(s) towed exceed 4,536 kg (10,000 lbs). Source: Montana CDL Manual, Rev. June 2026 (MVD/DOJ).","handbook":"","hbref":""},{"q":"A single 'heavy heavy straight vehicle' in Montana with a GVWR of 26,001 pounds or more that is not towing anything over 10,000 pounds requires which CDL class?","options":["Class A","Class B","Class C","Class M"],"answer":1,"explanation":"The Montana CDL Manual (Classifications, MT-2) defines Class B as any single vehicle with a GVWR of 26,001 lbs or more, or such a vehicle towing a unit not over 10,000 lbs. Source: Montana CDL Manual, Rev. June 2026 (MVD/DOJ).","handbook":"","hbref":""},{"q":"In Montana, a vehicle that does not meet the Class A or B weight definitions but is designed to transport 16 or more passengers (including the driver) or is used to haul placarded hazardous materials requires which CDL class?","options":["Class A","Class B","Class C","Class D"],"answer":2,"explanation":"The Montana CDL Manual (Classifications, MT-2) defines Class C as a single vehicle or combination meeting neither Class A nor B but designed to carry 16+ passengers including the driver, or used to transport placardable hazardous materials. Source: Montana CDL Manual, Rev. June 2026 (MVD/DOJ).","handbook":"","hbref":""},{"q":"Under Montana CDL rules, what is the minimum number of passengers (including the driver) a vehicle must be designed to carry before a Passenger (P) endorsement is required?","options":["8 passengers","10 passengers","15 passengers","16 passengers"],"answer":3,"explanation":"The Montana CDL Manual (MT-3) states a Passenger Vehicle (P) endorsement is required for Class A, B, or C vehicles designed to transport 16 or more passengers including the driver. Source: Montana CDL Manual, Rev. June 2026 (MVD/DOJ).","handbook":"","hbref":""},{"q":"Which Montana CDL endorsement is required to operate a commercial vehicle pulling double or triple trailers?","options":["N endorsement","T endorsement","X endorsement","H endorsement"],"answer":1,"explanation":"The Montana CDL Manual (MT-2/MT-3) states the Double/Triple Trailers (T) endorsement is required for drivers who pull double or triple trailers in Class A or B. Source: Montana CDL Manual, Rev. June 2026 (MVD/DOJ).","handbook":"","hbref":""},{"q":"According to the Montana CDL Manual, the Tanker (N) endorsement is required when transporting liquid or gaseous materials in a tank that has a rated capacity of at least how much?","options":["119 gallons","500 gallons","1,000 gallons","3,500 gallons"],"answer":2,"explanation":"The Montana CDL Manual (MT-3) defines the Tank Vehicle (N) endorsement as required for a tank with a rated capacity of 1,000 gallons or more, or multiple tanks with an aggregate rated capacity of 1,000 gallons. Source: Montana CDL Manual, Rev. June 2026 (MVD/DOJ).","handbook":"","hbref":""},{"q":"What is the minimum age to apply for an INTRASTATE (Montana-only) Commercial Driver License?","options":["16 years old","18 years old","19 years old","21 years old"],"answer":1,"explanation":"The Montana CDL Manual (Minimum Driver Ages, MT-3) states an intrastate (Montana only) applicant must meet the Montana qualifications and be at least 18 years old. Source: Montana CDL Manual, Rev. June 2026 (MVD/DOJ).","handbook":"","hbref":""},{"q":"What is the minimum age to apply for an INTERSTATE Commercial Driver License in Montana?","options":["18 years old","19 years old","21 years old","25 years old"],"answer":2,"explanation":"The Montana CDL Manual (Minimum Driver Ages, MT-3) states that to apply for an interstate license you must be at least 21 years old and able to meet the qualifications for a CDL. Source: Montana CDL Manual, Rev. June 2026 (MVD/DOJ).","handbook":"","hbref":""},{"q":"Before taking the CDL skills (pre-trip, basic control, and road) test in Montana, a Commercial Learner Permit must be held for a minimum of how long?","options":["7 days","10 days","14 days","30 days"],"answer":2,"explanation":"The Montana CDL Manual (CLP definition, MT-2) states all CLP permits must be held for a minimum of 14 days before taking the pre-trip, basic skills, and road test (driver may test on the 15th day). This reflects the federal CLP rule. Source: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); 49 CFR 383.25.","handbook":"","hbref":""},{"q":"Before a Montana CDL with a Hazardous Materials (H) endorsement can be issued, renewed, or transferred, federal law requires the driver to pass which screening?","options":["A DOT drug and alcohol test only","A TSA Security Threat Assessment (fingerprint-based background check)","An FBI polygraph examination","A state vision and reflex screening"],"answer":1,"explanation":"The Montana CDL Manual (Hazardous Materials, MT-2) states that in compliance with federal law, drivers wishing to obtain, transfer, or renew a HazMat endorsement must first have a Security Threat Assessment (STA) completed by the TSA, including fingerprinting and a criminal background check. Source: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); 49 CFR 1572.","handbook":"","hbref":""},{"q":"A Montana driver who completed a TSA Security Threat Assessment for a HazMat endorsement is generally NOT required to complete another STA when renewing or transferring if the prior assessment occurred within the past how many years?","options":["1 year","2 years","5 years","7 years"],"answer":1,"explanation":"The Montana CDL Manual (MT-2) states that those who have previously had a security threat assessment within the past two years of applying to renew or transfer their CDL may not be required to complete another STA. Source: Montana CDL Manual, Rev. June 2026 (MVD/DOJ).","handbook":"","hbref":""},{"q":"Under federal Entry-Level Driver Training (ELDT) rules adopted in Montana, a first-time applicant must complete ELDT from a provider listed where before testing?","options":["The Montana DOT contractor list","The FMCSA Training Provider Registry (TPR)","The AAMVA driver school directory","Any state-approved trade school"],"answer":1,"explanation":"ELDT requires training from a provider listed on the FMCSA Training Provider Registry (TPR). Montana references this requirement in its CDL Manual (MT-2). Source: FMCSA ELDT rule (49 CFR 380, effective Feb 7, 2022); Montana CDL Manual, Rev. June 2026 (MVD/DOJ).","handbook":"","hbref":""},{"q":"Federal ELDT requirements apply to first-time applicants for a Class A or B CDL and to first-time applicants for which set of endorsements?","options":["N (Tanker) and T (Doubles/Triples)","P (Passenger), S (School Bus), and H (HazMat)","T (Doubles/Triples) and S (School Bus) only","Only H (HazMat)"],"answer":1,"explanation":"Under the FMCSA ELDT rule (effective Feb 7, 2022), training is required for first-time Class A/B CDLs and for first-time Passenger (P), School Bus (S), and Hazardous Materials (H) endorsements. Montana adopted these requirements (CDL Manual, MT-2/MT-3). Source: 49 CFR 380; Montana CDL Manual, Rev. June 2026 (MVD/DOJ).","handbook":"","hbref":""},{"q":"Which of the following is one of the four self-certification categories a Montana CDL applicant must choose to indicate the type of commerce they operate in?","options":["Interstate non-excepted","Federal contract carrier","Recreational interstate","Limited commercial waiver"],"answer":0,"explanation":"The Montana CDL Manual (Self-Certification, MT-3) lists the four categories as Interstate non-excepted, Interstate excepted, Intrastate non-excepted, and Intrastate excepted. Source: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); 49 CFR 383.71.","handbook":"","hbref":""},{"q":"A Montana CDL applicant who self-certifies as 'Interstate non-excepted' is making which statement about medical requirements?","options":["They are exempt from holding a medical examiner's certificate","They must meet the federal medical (MEC) requirements","They only need a Montana intrastate medical waiver","They need no medical certification at all"],"answer":1,"explanation":"The Montana CDL Manual (Self-Certification, MT-3) states an Interstate non-excepted driver must meet the federal Medical Examiner's Certificate (MEC) requirements. Source: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); 49 CFR 383.71.","handbook":"","hbref":""},{"q":"All applicants for a Montana commercial driver license must provide documents from how many distinct categories of proof?","options":["Two: identity and residence","Three: authorized presence, identity, and Montana residence","Four: identity, residence, SSN card, and citizenship","One: a single REAL ID-compliant document"],"answer":1,"explanation":"The Montana CDL Manual (Proof of Authorized Presence, Identity, and Residence, MT-7/MT-8) requires documents from three categories: proof of authorized presence, proof of identity, and proof of Montana residence. Source: Montana CDL Manual, Rev. June 2026 (MVD/DOJ).","handbook":"","hbref":""},{"q":"Regarding a Social Security number on a Montana CDL application, what does the state require?","options":["The SSN must match the number on file with the Social Security Administration","No SSN is ever needed for a CDL","Only the last four digits are recorded and never verified","A notarized affidavit replaces the SSN"],"answer":0,"explanation":"The Montana CDL Manual (Proof of Social Security Number and Identity Confirmation, MT-2) states the name, birth date, and SSN used on the CDL application must match what is on file with the Social Security Administration, and the SSN is checked with the SSA. Source: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); FMCSR 383.153.","handbook":"","hbref":""},{"q":"If a Montana commercial driver continues to drive after being placed out-of-service, the first such offense results in a CDL suspension of how long?","options":["30 days","90 days","6 months","3 years"],"answer":2,"explanation":"The Montana CDL Manual (Driver Disqualifications, MT-5) states that if you drive after being placed out-of-service, your CDL will be suspended for six months for a first offense (and longer for subsequent offenses). Source: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Montana's Restricted Seasonal CDL for qualified farm-related service employees is valid during which seasonal window each calendar year?","options":["January 1 through June 30","March 15 through September 10","April 1 through October 1","May 1 through November 30"],"answer":1,"explanation":"The Montana CDL Manual (Restricted Seasonal CDL, MT-5) states a Seasonal CDL is valid only for the period of March 15 through September 10 of a calendar year and permits operation within a 150-mile radius of the place of business or farm. Source: Montana CDL Manual, Rev. June 2026 (MVD/DOJ).","handbook":"","hbref":""},{"q":"In Montana, what is the blood alcohol concentration (BAC) at or above which a person is considered to be illegally operating a commercial motor vehicle (CMV)?","options":["0.08","0.04","0.02","0.10"],"answer":1,"explanation":"Montana follows the federal CMV standard: operating a CMV with an alcohol concentration of 0.04 or more is a major offense. Source: MCA 61-8-802 and the Montana CDL Manual (Section 1, Disqualifications); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Montana's implied-consent law, by operating any vehicle in the state a driver is deemed to have already consented to which of the following?","options":["A test of blood, breath, or urine for alcohol or drugs","A search of the vehicle without a warrant","An annual medical examination","A vision screening at every traffic stop"],"answer":0,"explanation":"Montana's implied-consent law provides that anyone operating a vehicle in the state has given consent to a test of blood, breath, or urine to determine alcohol concentration or the presence of drugs. Source: Montana implied-consent statute (MCA 61-8-1016, formerly 61-8-402) and the Montana CDL Manual.","handbook":"","hbref":""},{"q":"A Montana CDL holder commits a first major offense (such as DUI) while NOT transporting hazardous materials. For how long is the CDL disqualified?","options":["6 months","1 year","3 years","60 days"],"answer":1,"explanation":"A first major offense results in a 1-year disqualification of the CDL. Source: MCA 61-8-802(1) and the Montana CDL Manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"If a Montana CDL holder's first major offense occurs while operating a CMV that is transporting placardable hazardous materials, the disqualification period is increased to:","options":["1 year","2 years","3 years","Lifetime"],"answer":2,"explanation":"When a first major offense occurs while operating a CMV transporting placardable hazardous materials, the disqualification is 3 years instead of 1 year. Source: MCA 61-8-802(1) and the Montana CDL Manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the disqualification period in Montana for a driver convicted of a SECOND major offense (from a separate incident) during their lifetime?","options":["3 years","5 years","10 years","Lifetime"],"answer":3,"explanation":"A second major offense results in a lifetime disqualification, though Montana may allow reinstatement under federal rules after a minimum 10-year period. Source: MCA 61-8-802 and the Montana CDL Manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A Montana CMV driver is lawfully asked to submit to a breath test for alcohol and refuses. How is this refusal treated for CDL purposes?","options":["As a serious traffic violation (60-day penalty)","As a major offense, with the same disqualification as a failed test","As a non-reportable administrative matter","As an out-of-service order violation"],"answer":1,"explanation":"Refusing a required alcohol/drug test under implied consent is a major offense and carries the same disqualification as testing 0.04 or above: 1 year (3 years for hazmat) for a first refusal, lifetime for a second. Source: MCA 61-8-802 and the Montana CDL Manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A Montana CMV driver who has any detectable amount of alcohol below 0.04 is not disqualified, but must be placed out of service for how long?","options":["1 hour","8 hours","24 hours","72 hours"],"answer":2,"explanation":"A CMV driver with a detectable alcohol concentration under 0.04 must be placed out of service for 24 hours. Source: Montana CDL Manual; 49 CFR 392.5 / 383.51.","handbook":"","hbref":""},{"q":"Which of the following is classified as a SERIOUS traffic violation for a Montana CDL holder?","options":["Driving 15 mph or more over the posted speed limit","A first DUI in a CMV","Refusing an alcohol test","Driving while a license is suspended for a DUI"],"answer":0,"explanation":"Excessive speeding (15 mph or more over the limit) is a serious traffic violation. DUI and test refusal are major offenses, not serious violations. Source: Montana CDL Manual (Disqualifications); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"How many serious traffic violations within a 3-year period trigger a 60-day disqualification of a Montana CDL?","options":["One","Two","Three","Four"],"answer":1,"explanation":"A second serious traffic violation within a 3-year period results in a 60-day disqualification. Source: Montana CDL Manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A Montana CDL holder is convicted of THREE serious traffic violations within a 3-year period. What is the minimum disqualification?","options":["60 days","90 days","120 days","180 days"],"answer":2,"explanation":"Three serious traffic violations in a 3-year period result in a 120-day disqualification. Source: Montana CDL Manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which of these is NOT counted as a serious traffic violation for a Montana CDL holder?","options":["Following too closely","Improper or erratic lane changes","Reckless driving","Driving 5 mph over the speed limit"],"answer":3,"explanation":"Serious violations include reckless driving, improper/erratic lane changes, following too closely, and speeding 15+ mph over the limit. Minor speeding (e.g., 5 mph over) is not a serious violation. Source: Montana CDL Manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Using a hand-held mobile phone while driving a CMV is, for Montana CDL purposes, classified as which type of violation?","options":["A major offense","A serious traffic violation","An out-of-service violation","A railroad-crossing violation"],"answer":1,"explanation":"Using a hand-held mobile phone while driving a CMV is a serious traffic violation under the federal rule applied in Montana. Source: Montana CDL Manual; 49 CFR 392.82 and 383.51.","handbook":"","hbref":""},{"q":"Texting while driving a CMV is prohibited for Montana CDL drivers. A second conviction for texting/hand-held phone use within 3 years results in what disqualification?","options":["No disqualification","60 days","120 days","1 year"],"answer":1,"explanation":"Texting/hand-held phone use is a serious violation. A first conviction carries no disqualification, but a second within 3 years results in a 60-day disqualification (120 days for a third). Source: Montana CDL Manual; 49 CFR 392.80/392.82 and 383.51.","handbook":"","hbref":""},{"q":"What is the minimum disqualification for a Montana CDL holder's FIRST railroad-highway grade crossing violation committed while driving a CMV?","options":["30 days","60 days","120 days","1 year"],"answer":1,"explanation":"A first railroad-highway grade crossing violation results in a minimum 60-day disqualification. Source: Montana CDL Manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"For a SECOND railroad-grade crossing violation within a 3-year period, a Montana CDL is disqualified for at least:","options":["60 days","120 days","180 days","1 year"],"answer":1,"explanation":"A second railroad-grade crossing violation in a 3-year period results in a minimum 120-day disqualification. Source: Montana CDL Manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A THIRD railroad-grade crossing violation within a 3-year period disqualifies a Montana CDL for at least:","options":["120 days","180 days","1 year","3 years"],"answer":2,"explanation":"A third railroad-grade crossing violation in a 3-year period results in a minimum 1-year disqualification. Source: Montana CDL Manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A Montana CMV driver violates an out-of-service order for the FIRST time (not carrying hazmat or passengers). What is the minimum disqualification?","options":["30 days","90 days","180 days","1 year"],"answer":2,"explanation":"A first conviction for violating an out-of-service order results in a disqualification of at least 180 days. Source: Montana CDL Manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the minimum disqualification for a SECOND out-of-service order violation (separate incidents) within a 10-year period for a Montana CDL holder?","options":["180 days","1 year","2 years","3 years"],"answer":2,"explanation":"A second out-of-service order violation in separate incidents within 10 years results in a minimum 2-year disqualification (3 years for a third). Source: Montana CDL Manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"If a Montana CMV driver violates an out-of-service order for the first time while transporting placardable hazardous materials OR while operating a vehicle designed to carry 16 or more passengers, the minimum disqualification is:","options":["60 days","180 days","1 year","2 years"],"answer":1,"explanation":"A first out-of-service order violation while hauling placarded hazmat or carrying 16+ passengers (including the driver) results in a minimum 180-day disqualification, with at least 3 years for a subsequent violation. Source: Montana CDL Manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A Montana CDL holder receives a DUI in their PERSONAL (non-commercial) vehicle. How does this affect their CDL?","options":["It has no effect because it was not in a CMV","It is treated as a major offense and disqualifies the CDL","It only adds points but no disqualification","It results in a 24-hour out-of-service order only"],"answer":1,"explanation":"Major offenses such as DUI disqualify the CDL even when committed in a personal vehicle; a first offense is a 1-year disqualification. Source: MCA 61-8-802 and the Montana CDL Manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"On a Montana federal-aid interstate highway outside an urbanized area, a loaded semi (truck of more than 1 ton rated capacity) may lawfully travel up to what maximum speed?","options":["65 mph at all times","80 mph, the same as cars","70 mph at all times","75 mph day, 65 mph night"],"answer":2,"explanation":"Montana sets a separate truck limit: a truck/truck tractor over 1 ton rated capacity is capped at 70 mph on the interstate, even though cars may run 80 mph on rural interstates. Source: MCA 61-8-312 (special speed limitations on trucks) and 61-8-303; raised by HB393 (2019).","handbook":"","hbref":""},{"q":"On a Montana two-lane public highway that is NOT an interstate, the maximum speed for a truck of more than 1 ton rated capacity is:","options":["70 mph day, 65 mph night","60 mph day, 55 mph night","65 mph, day and night","55 mph at all times"],"answer":2,"explanation":"On non-interstate highways the truck limit is a flat 65 mph day and night. The older split 60 day/55 night figures were repealed in 2019. Source: MCA 61-8-312; HB393 (2019).","handbook":"","hbref":""},{"q":"Under Montana's railroad-crossing rule for buses and placarded hazmat vehicles required to stop, where there is no painted stop line, the driver must stop within what distance of the nearest rail?","options":["No closer than 15 feet and no farther than 50 feet","No closer than 10 feet and no farther than 40 feet","No closer than 25 feet and no farther than 75 feet","No closer than 5 feet and no farther than 30 feet"],"answer":0,"explanation":"Montana follows the 15-to-50-foot rule: vehicles required to stop must halt no closer than 15 feet and no more than 50 feet from the nearest rail of the nearest track. Source: Montana CDL Manual, Section 2.15 (Railroad-highway Crossings).","handbook":"","hbref":""},{"q":"Which commercial vehicles must ALWAYS make a full stop at a Montana railroad-highway grade crossing (absent a green signal or police direction)?","options":["All combination vehicles over 26,001 pounds","Only triple-trailer combinations","Any truck registered out of state","Passenger-carrying buses and vehicles required to be placarded for hazardous materials"],"answer":3,"explanation":"Montana's manual states that all passenger-carrying (bus) and hazmat-placarded vehicles are required to stop at the crossing; ordinary loaded trucks are not unless cargo or law requires it. Source: Montana CDL Manual, Section 2.15.2 and 2.15.4.","handbook":"","hbref":""},{"q":"Under Montana's school-bus law, when a school bus is stopped on the roadway with its red lights flashing, an approaching driver must stop not less than approximately how far from the bus?","options":["20 feet","50 feet","30 feet","10 feet"],"answer":2,"explanation":"Montana requires drivers approaching from either direction to stop not less than approximately 30 feet from a school bus displaying flashing red lights, and to remain stopped until the red lights cease. Source: MCA 61-8-351 (meeting or passing school bus).","handbook":"","hbref":""},{"q":"On a Montana highway with separate roadways (e.g., a divided highway with the opposing direction on a physically separate roadway), a driver meeting a school bus stopped on the OTHER roadway must:","options":["Stop, because all approaching traffic must always stop","Stop only if the median is narrower than 30 feet","Not stop — vehicles on a different roadway need not stop","Slow to 10 mph but need not come to a full stop"],"answer":2,"explanation":"Montana's exception: a driver on a highway with separate roadways need not stop upon meeting or passing a school bus that is on a different roadway. The exception is keyed to 'separate roadways,' not merely a painted center line. Source: MCA 61-8-351.","handbook":"","hbref":""},{"q":"When a Montana school bus has actuated only its FLASHING AMBER (yellow) lights, an approaching driver is required to:","options":["Slow to a reasonable speed and be prepared to stop","Come to a complete stop at least 30 feet away immediately","Maintain speed because amber lights carry no duty","Stop only if children are visible at the roadside"],"answer":0,"explanation":"Flashing amber means the bus is preparing to stop; Montana law requires drivers to slow to a reasonable speed and be prepared to stop. The duty to stop arises when the red lights activate. Source: MCA 61-8-351.","handbook":"","hbref":""},{"q":"Under Montana's Move Over law, when approaching a stationary emergency or highway-worker vehicle on an INTERSTATE and a lane change IS possible, the driver must reduce speed to at least how far below the posted limit?","options":["10 mph below the posted limit","30 mph below the posted limit","20 mph below the posted limit","5 mph below the posted limit"],"answer":2,"explanation":"MCA 61-8-388 requires reducing speed to 20 mph below the posted limit on an interstate when a lane change is possible (and moving to a non-adjacent lane). If a lane change is unsafe, the driver must slow to one-half the posted limit. Source: MCA 61-8-388.","handbook":"","hbref":""},{"q":"Under Montana's Move Over law, on a STATE HIGHWAY or COUNTY ROAD where a lane change is possible, the required speed reduction when passing a stationary emergency vehicle is at least:","options":["20 mph below the posted limit","15 mph below the posted limit","10 mph below the posted limit","30 mph below the posted limit"],"answer":3,"explanation":"On a state highway or county road, MCA 61-8-388 requires slowing to 30 mph below the posted limit when a lane change is possible; if a lane change is unsafe, slow to one-half the posted limit. Source: MCA 61-8-388.","handbook":"","hbref":""},{"q":"Under Montana's Move Over law, if the driver is UNABLE to safely change lanes when approaching a stationary emergency vehicle, what speed must the driver reduce to?","options":["One-half the posted speed limit","20 mph regardless of the posted limit","A complete stop until the scene clears","10 mph below the posted limit"],"answer":0,"explanation":"When a lane change cannot be made safely, MCA 61-8-388 requires reducing to one-half the posted speed limit while proceeding with caution. Source: MCA 61-8-388.","handbook":"","hbref":""},{"q":"On a Montana multi-lane highway, the Move Over law's primary requirement when approaching a stationary emergency vehicle (where a posted temporary limit is absent) is to:","options":["Stop completely in the right lane","Move into a lane not adjacent to the stopped vehicle, if it can be done safely","Sound your horn continuously while passing","Drive onto the shoulder to give maximum room"],"answer":1,"explanation":"MCA 61-8-388 directs drivers on a multi-lane highway to vacate the lane adjacent to the stationary emergency or highway-worker vehicle when it is safe; if that is not possible, slow as required and pass with caution. Source: MCA 61-8-388.","handbook":"","hbref":""},{"q":"If a Montana CDL driver must stop on the shoulder of a road, within how many minutes must warning devices be placed?","options":["Within 5 minutes","Within 10 minutes","Within 15 minutes","Within 30 minutes"],"answer":1,"explanation":"A stopped truck or bus must put out emergency warning devices within 10 minutes of stopping on a road or shoulder. Source: Montana CDL Manual, Section 2.5 (Communicating / warning devices).","handbook":"","hbref":""},{"q":"When a Montana CDL driver is stopped on a ONE-WAY or DIVIDED highway, where are the three warning devices placed?","options":["10 ft, 50 ft, and 150 ft toward the approaching traffic","10 ft, 100 ft, and 200 ft toward the approaching traffic","10 ft, 100 ft ahead and 100 ft behind the vehicle","15 ft, 50 ft, and 100 ft toward the approaching traffic"],"answer":1,"explanation":"On a one-way or divided highway, place warning devices at 10 feet, 100 feet, and 200 feet toward the approaching traffic. Source: Montana CDL Manual, Section 2.5 (warning device placement).","handbook":"","hbref":""},{"q":"On an undivided two-way Montana road carrying traffic in both directions, the three reflective triangles for a stopped CMV are placed at:","options":["Within 10 ft of the vehicle, and 100 ft to the front and 100 ft to the rear","10 ft, 100 ft, and 200 ft, all behind the vehicle","50 ft, 100 ft, and 200 ft toward oncoming traffic only","Within 10 ft, and 200 ft to the front and 200 ft to the rear"],"answer":0,"explanation":"On a two-lane two-way or undivided road, place one device within 10 feet of the vehicle and one 100 feet ahead and one 100 feet behind, in the lane/shoulder where you stopped. Source: Montana CDL Manual, Section 2.5.","handbook":"","hbref":""},{"q":"How many red reflective triangles must a Montana CDL vehicle carry as required emergency warning devices?","options":["Two","Three","Four","Six"],"answer":1,"explanation":"Required warning equipment is three red reflective triangles (or alternatives such as 6 fuses or 3 liquid-burning flares). Source: Montana CDL Manual, Section 2.1 (vehicle inspection) and Section 2.5.","handbook":"","hbref":""},{"q":"On a Montana road where a hill or curve blocks the view of a stopped CMV within 500 feet, the driver should:","options":["Place all three triangles within 10 feet of the bumper","Move the rear-most triangle back down the road beyond the obstruction so traffic gets warning","Leave the triangles in standard positions and rely on flashers","Place a triangle exactly 500 feet ahead of the obstruction"],"answer":1,"explanation":"If a hill, curve, or obstruction prevents drivers from seeing the vehicle within 500 feet, move the rear-most warning device back beyond the obstruction so approaching traffic is warned in time. Source: Montana CDL Manual, Section 2.5.","handbook":"","hbref":""},{"q":"A Montana school-bus driver approaching a railroad crossing should activate the bus's hazard lights at approximately what distance before the crossing?","options":["About 50 feet before the crossing","About 500 feet before the crossing","Only after stopping at the crossing","About 200 feet before the crossing"],"answer":3,"explanation":"Montana's school-bus procedures call for activating hazard lights about 200 feet before the crossing, then stopping 15 to 50 feet from the nearest rail. Source: Montana CDL Manual, Section 10 (School Buses), crossing procedures.","handbook":"","hbref":""},{"q":"On a Montana interstate within an urbanized area of 50,000 or more people, the speed limit for passenger vehicles is:","options":["80 mph at all times","75 mph day, 65 mph night","55 mph at all times","65 mph at all times"],"answer":3,"explanation":"While rural interstates allow cars 80 mph, the limit drops to 65 mph on interstate sections within an urbanized area of 50,000+ population. Source: MCA 61-8-303 (speed restrictions).","handbook":"","hbref":""},{"q":"Where the Move Over law applies, Montana also requires drivers to obey which of the following if present at the scene?","options":["A flagger's directions or a posted temporary speed-limit signboard","Only the dispatcher's radio instructions","Nothing further once one lane is changed","A mandatory full stop at every emergency scene"],"answer":0,"explanation":"MCA 61-8-388 requires drivers to follow the directions of any flagger or a posted temporary speed-limit signboard; the statutory mph reductions apply only when no temporary limit is posted. Source: MCA 61-8-388.","handbook":"","hbref":""},{"q":"A Montana Class A CDL issued after a skills test in a combination connected with a pintle hook (not a fifth wheel) carries which restriction?","options":["A 'K' restriction limiting the driver to intrastate only","An 'L' restriction for vehicles without air brakes","A 'Z' restriction for partial air-brake systems","An 'O' restriction prohibiting operation of a fifth-wheel tractor/semitrailer combination"],"answer":3,"explanation":"Montana places an 'O' restriction on a Class A license when the skills test is taken in a combination connected by a pintle hook or other non-fifth-wheel coupling, barring operation of a fifth-wheel tractor/semitrailer. Source: Montana CDL Manual (license restrictions/endorsements section).","handbook":"","hbref":""},{"q":"Which Montana agency actually issues the commercial driver license (CDL) and processes the application at a county office?","options":["The Federal Motor Carrier Safety Administration (FMCSA)","The Montana Motor Vehicle Division (MVD)","The Montana Department of Transportation (MDT)","The Montana Highway Patrol"],"answer":1,"explanation":"In Montana the CDL is issued by the Motor Vehicle Division (MVD), and applicants finish the process at a county Driver's License office. MDT (Transportation) runs the skills exam program and ELDT, but the license itself is issued by MVD. Source: Montana MVD CDL pages and MDT 'Ten Easy Steps to a CDL.'","handbook":"","hbref":""},{"q":"After you pass the CDL skills test in Montana, where must you go to actually have the commercial license issued?","options":["To the MDT skills examiner, who prints it on the spot","To the FMCSA Training Provider Registry website","Back to the county MVD office to have the license issued","It is automatically mailed with no further visit required"],"answer":2,"explanation":"Montana's MDT 'Ten Easy Steps to a CDL' states the examiner transmits the skills-test results to MVD, but the applicant MUST return to the county MVD to have the new commercial license issued. Source: MDT 'Ten Easy Steps to a CDL,' Step 10.","handbook":"","hbref":""},{"q":"Under federal rules adopted in Montana, how long must you hold a Commercial Learner's Permit (CLP) before you may take the CDL skills (road) test?","options":["At least 14 days","At least 7 days","At least 30 days","At least 60 days"],"answer":0,"explanation":"FMCSA rules applied by Montana require holding the CLP for a minimum of 14 days before taking the skills test, even when an existing CDL holder is merely upgrading. Source: MDT 'Ten Easy Steps to a CDL,' Steps 4F and 9.","handbook":"","hbref":""},{"q":"For how long is a Montana Commercial Learner's Permit (CLP) valid?","options":["90 days","60 days","1 year","180 days"],"answer":3,"explanation":"A Montana CLP is valid for 180 days and may be renewed one time before it expires. Source: Montana MVD 'Getting a New CDL in Montana.'","handbook":"","hbref":""},{"q":"How many times may a Montana CLP be renewed before it expires?","options":["Once","It cannot be renewed","Twice","Three times"],"answer":0,"explanation":"Montana allows the 180-day CLP to be renewed one time before expiration. Source: Montana MVD 'Getting a New CDL in Montana.'","handbook":"","hbref":""},{"q":"Before a first-time Class A or Class B applicant can take the Montana skills test, what training must be completed and recorded on the FMCSA Training Provider Registry?","options":["A defensive driving course approved by the county","Entry-Level Driver Training (ELDT)","A Montana Highway Patrol ride-along program","An air-brake endorsement class"],"answer":1,"explanation":"Since February 7, 2022, ELDT from a provider listed on FMCSA's Training Provider Registry is required before an eligible applicant can take the CDL skills test. MDT itself is a registered training provider. Source: MDT 'Ten Easy Steps to a CDL,' Step 5; MDT ELDT page.","handbook":"","hbref":""},{"q":"Montana's CDL skills test is administered in three parts. Which set correctly names those three parts?","options":["Written exam, vision screening, and on-road driving","Pre-trip inspection, air-brake test, and night driving","Pre-trip inspection, basic vehicle control, and on-road driving","Backing, coupling, and a written endorsement test"],"answer":2,"explanation":"Like all states, Montana's three-part skills test consists of the pre-trip vehicle inspection, basic vehicle control (backing) maneuvers, and the on-road driving test. Source: Montana CDL Manual; MDT 'Ten Easy Steps to a CDL,' Steps 6-9.","handbook":"","hbref":""},{"q":"How long is a standard Montana CDL valid before it must be renewed (for a typical driver aged 21 to 70)?","options":["8 years","5 years","2 years","4 years"],"answer":3,"explanation":"A Montana commercial driver license is issued for 4 years, a shorter cycle than the standard 8-year non-commercial Montana license. Source: MDT 'Ten Easy Steps to a CDL,' Step 10; Montana MVD CDL renewal page.","handbook":"","hbref":""},{"q":"How many self-certification categories of operation must a Montana CDL applicant choose from when declaring their type of driving?","options":["Two","Four","Three","Six"],"answer":1,"explanation":"Montana uses the four federal self-certification categories: non-excepted interstate, excepted interstate, non-excepted intrastate (Montana-only), and excepted intrastate. Source: Montana MVD CDL Self-Certification Classification and Medical Documentation form; MCA 61-5-141.","handbook":"","hbref":""},{"q":"A Montana driver who crosses state lines and must meet all federal physical qualification standards self-certifies under which category?","options":["Non-excepted interstate","Excepted interstate","Non-excepted intrastate","Excepted intrastate"],"answer":0,"explanation":"A driver operating in interstate commerce who is subject to 49 CFR Part 391 physical qualification standards self-certifies as non-excepted interstate and must keep a current medical examiner's certificate on file. Source: Montana MVD self-certification form; MCA 61-5-141.","handbook":"","hbref":""},{"q":"Which self-certification category requires the driver to provide and maintain a valid DOT medical examiner's certificate with the State of Montana?","options":["Excepted interstate","Excepted intrastate","Non-excepted interstate","Government-fleet excepted"],"answer":2,"explanation":"Non-excepted interstate drivers must meet 49 CFR Part 391 and submit a current Medical Examiner's Certificate; 'excepted' categories do not require a medical card on file. (Non-excepted intrastate also requires a card or a Montana medical statement.) Source: Montana MVD self-certification form; MCA 61-5-141.","handbook":"","hbref":""},{"q":"When a Montana non-excepted CDL holder obtains a new DOT medical examiner's certificate, how is it submitted to the state?","options":["It is filed only with the driver's employer","It is given to the county MVD, which scans it into the driving record","It is mailed directly to the FMCSA national office in Washington","No submission is needed; the doctor's signature is sufficient"],"answer":1,"explanation":"Non-excepted Montana drivers must submit the medical certificate to their county MVD when obtained and at each renewal; MVD scans a copy into the driving record. Source: MDT 'Ten Easy Steps to a CDL,' Step 4B; MCA 61-5-141.","handbook":"","hbref":""},{"q":"A standard DOT medical examiner's certificate used to keep a Montana CDL valid may be issued for a maximum of how long?","options":["Up to 12 months","Up to 36 months","Up to 24 months","Up to 6 months"],"answer":2,"explanation":"A DOT physical is valid for up to 24 months; an examiner may issue a shorter certificate to monitor a medical condition. Source: MDT 'Ten Easy Steps to a CDL,' Step 2; Montana CDL medical guidance.","handbook":"","hbref":""},{"q":"Under MCA 61-5-141, what happens to a Montana CDL if the holder fails to submit a current medical certificate by its expiration date?","options":["The full driver license is immediately revoked","Nothing changes until the next 4-year renewal","The driver is fined but keeps full CDL privileges","MVD downgrades the commercial license to a base (non-CDL) license"],"answer":3,"explanation":"MCA 61-5-141 directs the department to mark the CDLIS record 'not certified' and downgrade the commercial license to a base license if a current certificate is not on file. Source: MCA 61-5-141, Self-certification of operation status.","handbook":"","hbref":""},{"q":"Under Montana's self-certification statute, within how many days must MVD act to downgrade a CDL after a medical certificate lapses?","options":["10 days","30 days","60 days","90 days"],"answer":0,"explanation":"MCA 61-5-141 requires the department to act within 10 days of the certificate becoming invalid to mark the record not certified, downgrade the license, and notify the driver. Source: MCA 61-5-141.","handbook":"","hbref":""},{"q":"How long do passed Montana CDL written knowledge test results remain valid if the applicant has not yet obtained the CDL?","options":["Six months from the date passed","One year from the date passed","Two years from the date passed","180 days from the date passed"],"answer":1,"explanation":"Montana knowledge-test results stay valid for one year from the date passed; if the CDL is not obtained within that year, all written tests must be retaken. Source: MDT 'Ten Easy Steps to a CDL,' Step 4D.","handbook":"","hbref":""},{"q":"In Montana, when may an applicant who fails a CDL written knowledge test attempt that test again?","options":["Only after a 7-day waiting period","Only after 14 days","The next day","Only after 30 days"],"answer":2,"explanation":"Montana allows a failed written knowledge test to be retaken the next day. Source: MDT 'Ten Easy Steps to a CDL,' Step 4D.","handbook":"","hbref":""},{"q":"On test day, how much time does a Montana applicant have to complete the pre-trip vehicle inspection portion of the skills test?","options":["30 minutes","60 minutes","20 minutes","45 minutes"],"answer":3,"explanation":"Montana allots 45 minutes to complete the pre-trip inspection on test day; improperly performing the brake check results in a failure. Source: MDT 'Ten Easy Steps to a CDL,' Step 6A.","handbook":"","hbref":""},{"q":"A CDL applicant in Montana who already holds a standard Montana (non-CDL) driver license must still present which of the following at the appointment?","options":["A new birth certificate every time","Proof of Montana residency again","A valid DOT physical (medical examiner's) certificate","A Montana Highway Patrol clearance form"],"answer":2,"explanation":"Applicants who already hold a Montana standard license must provide proof of Social Security number, proof of authorized presence, and a valid DOT physical (medical examiner's) certificate; proof of identity/residency was already on file. Source: MDT 'Ten Easy Steps to a CDL,' Required Documents.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Montana CDL for intrastate (Montana-only) commercial driving versus interstate driving?","options":["21 for intrastate and 25 for interstate","18 for both intrastate and interstate","16 for intrastate and 18 for interstate","18 for intrastate and 21 for interstate"],"answer":3,"explanation":"Montana requires an applicant to be at least 18 to drive a commercial vehicle intrastate (within Montana) and at least 21 to drive interstate. Source: Montana CDL Manual; Montana MVD CDL requirements.","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная разрешённая ширина коммерческого транспортного средства вместе с грузом на дорогах штата Монтана без разрешения на негабаритный груз?","options":["8 футов 0 дюймов (96 inches)","9 футов 0 дюймов (108 inches)","10 футов 0 дюймов (120 inches)","8 футов 6 дюймов (102 inches)"],"explanation":"Монтана ограничивает общую наружную ширину транспортного средства до 102 inches (8 футов 6 дюймов) согласно MCA 61-10-102 и руководству Montana Commercial Vehicle Size and Weight and Safety Trucker's Handbook (раздел «Legal Dimensions»). Грузы шире этого значения требуют разрешения."},"1":{"q":"Какова максимальная разрешённая высота транспортного средства, без груза или с грузом, на дорогах штата Монтана?","options":["13 футов 6 дюймов","14 футов","15 футов","15 футов 6 дюймов"],"explanation":"Согласно MCA 61-10-103 и Montana Trucker's Handbook транспортное средство (без груза или с грузом) не может превышать 14 футов в высоту. Большая высота требует разрешения на сверхгабаритный груз."},"2":{"q":"Без разрешения, какова максимальная длина полуприцепа в составе автопоезда тягач-полуприцеп в штате Монтана?","options":["48 футов","57 футов","53 фута","60 футов"],"explanation":"MCA 61-10-104 и Montana Trucker's Handbook устанавливают максимальную длину полуприцепа в 53 фута (исключая части, не предназначенные для перевозки груза). Срочное разрешение (term permit) может увеличить её до 57 футов согласно MCA 61-10-124."},"3":{"q":"В штате Монтана какова максимальная полная масса, допустимая на одиночную ось без разрешения на превышение веса?","options":["20,000 pounds","18,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"Согласно MCA 61-10-107 и Montana Trucker's Handbook суммарная масса на одной или нескольких осях, центры которых расположены не более чем на 40 inches друг от друга, не может превышать 20,000 pounds. Это соответствует федеральному пределу для одиночной оси на межштатной системе."},"4":{"q":"Какова максимальная полная масса, допустимая на группу сдвоенных осей (tandem axle) в штате Монтана без разрешения на превышение веса?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"MCA 61-10-107 и Montana Trucker's Handbook устанавливают, что никакие две последовательные оси, расположенные на расстоянии более 40 inches, но менее 96 inches друг от друга, не могут нести нагрузку свыше 34,000 pounds."},"5":{"q":"Как штат Монтана определяет «сдвоенную ось» (tandem axle) для целей ограничения веса?","options":["Две оси, расположенные ровно на расстоянии 40 inches друг от друга","Две последовательные оси на расстоянии более 40 inches, но менее 96 inches друг от друга","Любые две оси в пределах 120 inches друг от друга","Две оси на расстоянии более 96 inches друг от друга"],"explanation":"MCA 61-10-107 (упоминаемая в Montana Trucker's Handbook) определяет сдвоенную ось как две последовательные оси на расстоянии более 40 inches, но менее 96 inches друг от друга; такая группа ограничена 34,000 pounds."},"6":{"q":"Какая формула моста (bridge formula) используется в штате Монтана для расчёта максимально допустимой полной массы на группу осей?","options":["W = 1000((LN/(N+1)) + 10N + 20)","W = 250((LN/(N-1)) + 6N + 18)","W = 500((LN/(N+1)) + 12N + 12)","W = 500((LN/(N-1)) + 12N + 36)"],"explanation":"Формула моста штата Монтана (соответствующая федеральной Bridge Formula B) имеет вид W = 500((LN/(N-1)) + 12N + 36), где L — расстояние в футах между крайними осями группы, а N — количество осей, согласно MCA 61-10-107 и Montana Trucker's Handbook."},"7":{"q":"В штате Монтана когда пределы веса для одиночной и сдвоенной осей имеют приоритет (заменяют) результат формулы моста?","options":["Для всех осей на расстоянии более 120 inches друг от друга","Только на межштатной системе (Interstate System)","Для всех осей на расстоянии не более 96 inches друг от друга","Никогда; формула моста всегда определяющая"],"explanation":"Montana Trucker's Handbook поясняет, что пределы веса для одиночной или сдвоенной оси заменяют пределы формулы моста для всех осей на расстоянии не более 96 inches друг от друга (MCA 61-10-107)."},"8":{"q":"Какую максимальную полную массу разрешает штат Монтана для автопоезда, перевозящего делимый (reducible/divisible) груз?","options":["80,000 pounds","105,500 pounds","131,060 pounds","129,000 pounds"],"explanation":"Согласно MCA 61-10-107 и таблице Montana Gross Vehicle Weight Chart в Trucker's Handbook максимальная полная масса для делимых грузов составляет 131,060 pounds."},"9":{"q":"Как ограничивается вес на управляемую (переднюю) ось согласно правилам штата Монтана?","options":["До номинальной грузоподъёмности, указанной производителем шин, но не более 20,000 pounds","До ровно 12,000 pounds во всех случаях","До 34,000 pounds, как у сдвоенной оси","На управляемую ось нет ограничения"],"explanation":"Montana Trucker's Handbook отмечает, что управляемые оси ограничены номинальной грузоподъёмностью производителя, указанной на боковине шины, но не более 20,000 pounds (MCA 61-10-107)."},"10":{"q":"Без разрешения, какова максимальная общая длина автопоезда для комбинаций транспортных средств, особо не оговорённых иным образом, на дорогах штата Монтана?","options":["65 футов","75 футов","80 футов","70 футов"],"explanation":"MCA 61-10-104 и Montana Trucker's Handbook ограничивают такие комбинации общей длиной 75 футов (за исключением комбинаций, которым разрешена большая длина, например тягачей с 53-футовым прицепом, для которых нет ограничения по общей длине)."},"11":{"q":"Тягач, тянущий один прицеп длиной 53 фута (или короче), в штате Монтана подпадает под какое правило длины?","options":["Он всё равно должен оставаться в пределах 65 футов общей длины","Он всегда требует разрешения на одиночную поездку (single-trip permit)","Разрешение по общей длине не требуется независимо от суммарной длины","Он ограничен 70 футами общей длины"],"explanation":"Montana Trucker's Handbook устанавливает, что разрешение на превышение длины не требуется для тягача, тянущего прицеп длиной 53 фута (или короче), независимо от общей длины комбинации (MCA 61-10-104)."},"12":{"q":"Какое подразделение ведомства штата Монтана выдаёт разрешения на негабаритные и сверхтяжёлые грузы, а также сборы по полной массе транспортного средства для коммерческих автомобилей?","options":["Лицензионная стойка Montana Highway Patrol","Permitting Section подразделения Motor Carrier Services (MCS) при MDT","Офис окружного шерифа","Federal Motor Carrier Safety Administration"],"explanation":"Согласно Montana Trucker's Handbook разрешения на габариты/вес выдаёт Permitting Section подразделения Motor Carrier Services (MCS) при Montana Department of Transportation; перевозчики также могут оформить их самостоятельно онлайн (ePART / eTRIPS)."},"13":{"q":"Сверхгабаритный груз, который перевозится только в рамках одной поездки и не зарегистрирован для штата Монтана, требует какого вида разрешения?","options":["Только постоянное срочное разрешение (term permit)","Разрешение на индивидуальный комбайн (custom combine permit)","Никакого разрешения, поскольку это одноразовое перемещение","Разрешение на одиночную поездку для сверхгабаритного груза (single-trip over-dimensional permit), недействительное после выезда из штата"],"explanation":"Montana Trucker's Handbook предусматривает, что операторы, работающие на временной основе по поездкам, должны получить разрешение на одиночную поездку для сверхгабаритного груза (для грузов шире 8'6\", выше 14', длиннее 75' или одиночного транспортного средства длиннее 55'); разрешение становится недействительным после выезда из штата."},"14":{"q":"Какую минимальную страховку ответственности требует штат Монтана для выдачи специального разрешения на негабаритный/сверхтяжёлый груз?","options":["$300,000 единого совокупного лимита (combined single limit)","$500,000 единого совокупного лимита (combined single limit)","$1,000,000 единого совокупного лимита (combined single limit) на один случай","$750,000 единого совокупного лимита (combined single limit)"],"explanation":"Раздел General Oversize Permit Requirements в Montana Trucker's Handbook определяет минимум в $1,000,000 единого совокупного лимита (combined single limit) ответственности за телесные повреждения и материальный ущерб на один случай."},"15":{"q":"Зимнее срочное разрешение по весу (Winter Weight Term Permit) штата Монтана допускает какое превышение веса и на каких дорогах?","options":["10% превышения на дорогах вне межштатной системы, с December 1 по March 7","20% превышения на всех дорогах круглый год","10% превышения только на межштатных дорогах (Interstate)","15% превышения на дорогах вне межштатной системы, с November 1 по April 1"],"explanation":"Montana Trucker's Handbook устанавливает, что Winter Weight Term Permit допускает 10% превышения веса на дорогах вне межштатной системы с December 1 по March 7 и может быть приостановлено в период ранних оттепелей."},"16":{"q":"Иногородняя операция по индивидуальной уборке комбайном (custom combine) в штате Монтана может уплатить специальный сбор за разрешение взамен сборов GVW и разрешений на негабарит в размере какой суммы за единицу?","options":["$20 за единицу","$35 за единицу","$105 за единицу","$40 за единицу"],"explanation":"Согласно MCA 15-24-301 и 61-10-130 (а также ARM 18.8.426) Montana Trucker's Handbook предусматривает, что иногородняя операция по индивидуальной уборке комбайном может уплатить специальный сбор за разрешение в размере $40 за единицу (резиденты платят 35% сборов GVW плюс $20 за единицу)."},"17":{"q":"На межштатной системе (Interstate System) штата Монтана какой федеральный предел веса на одиночную ось также применяется в Монтане?","options":["20,000 pounds","18,000 pounds","21,000 pounds","24,000 pounds"],"explanation":"Montana Trucker's Handbook прямо отмечает, что федеральный предел веса на одиночную ось на межштатной системе (Interstate System) составляет 20,000 pounds, что соответствует общему пределу штата Монтана для одиночной оси согласно MCA 61-10-107."},"18":{"q":"Для перевозки сена или соломы, сопутствующей сельскохозяйственной деятельности, штат Монтана допускает высоту транспортного средства до какого максимума и в пределах какого расстояния?","options":["15 футов 6 дюймов, на расстояние не более 25 miles","16 футов, на расстояние не более 50 miles","14 футов 6 дюймов, на расстояние не более 10 miles","15 футов, на расстояние не более 100 miles"],"explanation":"MCA 61-10-103 предусматривает сельскохозяйственное исключение: сельскохозяйственная техника или транспортное средство, перевозящее сено или солому, может достигать 15 футов 6 дюймов, если оно проезжает не более 25 miles в рамках сельскохозяйственной деятельности и не проходит под препятствиями высотой 17 футов или ниже."},"19":{"q":"Неделимый груз, превышающий предел формулы моста, но НЕ превышающий разрешённые осевые нагрузки, облагается сбором за разрешение в штате Монтана на основании чего?","options":["Фиксированный годовой сбор $200 независимо от расстояния","Только зарегистрированная полная масса транспортного средства","10% от стоимости груза","Пробег поездки (например, $10 до 100 miles, $30 за 101-199, $50 за 200+ miles)"],"explanation":"Montana Trucker's Handbook (раздел «Overweight On Bridge - Legal Axle Weights - Non-Divisible Loads», MCA 61-10-107) взимает $10 до 100 miles, $30 за 101-199 miles и $50 за 200 miles и более."},"20":{"q":"В штате Монтана какой класс CDL требуется для управления составом транспортных средств с номинальной полной массой автопоезда (GCWR) 26,001 pounds или более, когда буксируемое(ые) транспортное(ые) средство(а) превышает(ют) 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"explanation":"Согласно Montana CDL Manual (Classifications, MT-2) составное транспортное средство Class A имеет GCWR 11,794 kg (26,001 lbs) или более при условии, что буксируемое(ые) транспортное(ые) средство(а) превышает(ют) 4,536 kg (10,000 lbs). Источник: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"21":{"q":"Одиночное «особо тяжёлое прямое транспортное средство» (heavy heavy straight vehicle) в штате Монтана с GVWR 26,001 pounds или более, которое не буксирует ничего тяжелее 10,000 pounds, требует какого класса CDL?","options":["Class A","Class B","Class C","Class M"],"explanation":"Montana CDL Manual (Classifications, MT-2) определяет Class B как любое одиночное транспортное средство с GVWR 26,001 lbs или более, либо такое транспортное средство, буксирующее единицу не тяжелее 10,000 lbs. Источник: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"22":{"q":"В штате Монтана транспортное средство, которое не соответствует определениям по весу Class A или B, но предназначено для перевозки 16 или более пассажиров (включая водителя) либо используется для перевозки опасных грузов, требующих маркировки (placards), требует какого класса CDL?","options":["Class A","Class B","Class C","Class D"],"explanation":"Montana CDL Manual (Classifications, MT-2) определяет Class C как одиночное транспортное средство или состав, не соответствующий ни Class A, ни Class B, но предназначенный для перевозки 16 и более пассажиров, включая водителя, либо используемый для перевозки опасных грузов, требующих маркировки. Источник: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"23":{"q":"Согласно правилам CDL штата Монтана, на какое минимальное число пассажиров (включая водителя) должно быть рассчитано транспортное средство, прежде чем потребуется пассажирская отметка (P)?","options":["8 пассажиров","10 пассажиров","15 пассажиров","16 пассажиров"],"explanation":"Montana CDL Manual (MT-3) устанавливает, что отметка о пассажирском транспортном средстве (P) требуется для транспортных средств Class A, B или C, предназначенных для перевозки 16 или более пассажиров, включая водителя. Источник: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"24":{"q":"Какая отметка CDL штата Монтана требуется для управления коммерческим транспортным средством, тянущим двойные или тройные прицепы?","options":["Отметка N","Отметка T","Отметка X","Отметка H"],"explanation":"Montana CDL Manual (MT-2/MT-3) устанавливает, что отметка о двойных/тройных прицепах (T) требуется для водителей, которые тянут двойные или тройные прицепы в Class A или B. Источник: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"25":{"q":"Согласно Montana CDL Manual, отметка о цистерне (N) требуется при перевозке жидких или газообразных материалов в цистерне с номинальной вместимостью не менее какого значения?","options":["119 gallons","500 gallons","1,000 gallons","3,500 gallons"],"explanation":"Montana CDL Manual (MT-3) определяет, что отметка о транспортном средстве с цистерной (N) требуется для цистерны с номинальной вместимостью 1,000 gallons или более, либо нескольких цистерн с совокупной номинальной вместимостью 1,000 gallons. Источник: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"26":{"q":"Каков минимальный возраст для подачи заявления на ВНУТРИШТАТНУЮ (только в пределах Монтаны) коммерческую водительскую лицензию?","options":["16 лет","18 лет","19 лет","21 год"],"explanation":"Montana CDL Manual (Minimum Driver Ages, MT-3) устанавливает, что заявитель на внутриштатную лицензию (только Монтана) должен соответствовать требованиям штата Монтана и быть не моложе 18 лет. Источник: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"27":{"q":"Каков минимальный возраст для подачи заявления на МЕЖШТАТНУЮ коммерческую водительскую лицензию в штате Монтана?","options":["18 лет","19 лет","21 год","25 лет"],"explanation":"Montana CDL Manual (Minimum Driver Ages, MT-3) устанавливает, что для подачи заявления на межштатную лицензию вы должны быть не моложе 21 года и способны соответствовать требованиям для получения CDL. Источник: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"28":{"q":"Перед сдачей экзамена CDL на навыки (предрейсовый осмотр, базовое управление и вождение по дороге) в штате Монтана необходимо иметь коммерческое ученическое разрешение (Commercial Learner Permit) минимум сколько времени?","options":["7 days","10 days","14 days","30 days"],"explanation":"Montana CDL Manual (определение CLP, MT-2) устанавливает, что все разрешения CLP должны находиться на руках минимум 14 days перед сдачей предрейсового осмотра, базовых навыков и вождения по дороге (водитель может сдавать на 15-й день). Это отражает федеральное правило CLP. Источник: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); 49 CFR 383.25."},"29":{"q":"Прежде чем CDL штата Монтана с отметкой об опасных грузах (H) может быть выдан, продлён или передан, федеральный закон требует, чтобы водитель прошёл какую проверку?","options":["Только тест DOT на наркотики и алкоголь","Оценку угрозы безопасности TSA (Security Threat Assessment, проверка биографии по отпечаткам пальцев)","Проверку на полиграфе FBI","Проверку зрения и реакции на уровне штата"],"explanation":"Montana CDL Manual (Hazardous Materials, MT-2) устанавливает, что в соответствии с федеральным законом водители, желающие получить, передать или продлить отметку HazMat, должны сначала пройти оценку угрозы безопасности (Security Threat Assessment, STA), проводимую TSA, включая снятие отпечатков пальцев и проверку на наличие судимостей. Источник: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); 49 CFR 1572."},"30":{"q":"От водителя штата Монтана, прошедшего оценку угрозы безопасности TSA для отметки HazMat, как правило, НЕ требуется проходить ещё одну STA при продлении или передаче, если предыдущая оценка проводилась в течение последних скольких лет?","options":["1 года","2 лет","5 лет","7 лет"],"explanation":"Montana CDL Manual (MT-2) устанавливает, что от тех, кто ранее проходил оценку угрозы безопасности в течение последних двух лет до подачи заявления на продление или передачу CDL, может не требоваться прохождение ещё одной STA. Источник: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"31":{"q":"Согласно федеральным правилам обучения водителей начального уровня (Entry-Level Driver Training, ELDT), принятым в штате Монтана, заявитель, подающий впервые, должен пройти ELDT у поставщика, указанного где, прежде чем сдавать экзамен?","options":["Список подрядчиков Montana DOT","Реестр поставщиков обучения FMCSA (Training Provider Registry, TPR)","Каталог автошкол AAMVA","Любая утверждённая штатом профессиональная школа"],"explanation":"ELDT требует прохождения обучения у поставщика, указанного в Реестре поставщиков обучения FMCSA (Training Provider Registry, TPR). Монтана ссылается на это требование в своём CDL Manual (MT-2). Источник: правило FMCSA ELDT (49 CFR 380, вступило в силу Feb 7, 2022); Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"32":{"q":"Федеральные требования ELDT применяются к заявителям, подающим впервые на CDL Class A или B, а также к заявителям, подающим впервые на какой набор отметок?","options":["N (цистерна) и T (двойные/тройные прицепы)","P (пассажирская), S (школьный автобус) и H (HazMat)","Только T (двойные/тройные прицепы) и S (школьный автобус)","Только H (HazMat)"],"explanation":"Согласно правилу FMCSA ELDT (вступило в силу Feb 7, 2022) обучение требуется для впервые получаемых CDL Class A/B и для впервые получаемых отметок Passenger (P), School Bus (S) и Hazardous Materials (H). Монтана приняла эти требования (CDL Manual, MT-2/MT-3). Источник: 49 CFR 380; Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"33":{"q":"Что из перечисленного является одной из четырёх категорий самосертификации, которую заявитель на CDL штата Монтана должен выбрать, чтобы указать тип коммерческой деятельности, в которой он работает?","options":["Межштатная без исключений (Interstate non-excepted)","Федеральный контрактный перевозчик","Рекреационная межштатная","Ограниченное коммерческое освобождение"],"explanation":"Montana CDL Manual (Self-Certification, MT-3) перечисляет четыре категории: межштатная без исключений (Interstate non-excepted), межштатная с исключениями (Interstate excepted), внутриштатная без исключений (Intrastate non-excepted) и внутриштатная с исключениями (Intrastate excepted). Источник: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); 49 CFR 383.71."},"34":{"q":"Заявитель на CDL штата Монтана, который самосертифицируется как «Interstate non-excepted», делает какое заявление относительно медицинских требований?","options":["Он освобождён от наличия медицинского заключения (medical examiner's certificate)","Он должен соответствовать федеральным медицинским требованиям (MEC)","Ему нужно лишь внутриштатное медицинское освобождение Монтаны","Ему вообще не нужна медицинская сертификация"],"explanation":"Montana CDL Manual (Self-Certification, MT-3) устанавливает, что водитель Interstate non-excepted должен соответствовать требованиям федерального медицинского заключения (Medical Examiner's Certificate, MEC). Источник: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); 49 CFR 383.71."},"35":{"q":"Все заявители на коммерческую водительскую лицензию штата Монтана должны предоставить документы из скольких различных категорий подтверждения?","options":["Две: личность и место жительства","Три: законное присутствие, личность и место жительства в Монтане","Четыре: личность, место жительства, карточка SSN и гражданство","Одна: единый документ, соответствующий REAL ID"],"explanation":"Montana CDL Manual (Proof of Authorized Presence, Identity, and Residence, MT-7/MT-8) требует документы из трёх категорий: подтверждение законного присутствия, подтверждение личности и подтверждение места жительства в Монтане. Источник: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"36":{"q":"Что касается номера социального страхования (Social Security number) в заявлении на CDL штата Монтана, что требует штат?","options":["SSN должен совпадать с номером, имеющимся в Social Security Administration","SSN никогда не нужен для CDL","Записываются только последние четыре цифры и никогда не проверяются","Нотариально заверенный аффидевит заменяет SSN"],"explanation":"Montana CDL Manual (Proof of Social Security Number and Identity Confirmation, MT-2) устанавливает, что имя, дата рождения и SSN, используемые в заявлении на CDL, должны совпадать с тем, что имеется в Social Security Administration, и SSN сверяется с SSA. Источник: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); FMCSR 383.153."},"37":{"q":"Если коммерческий водитель штата Монтана продолжает движение после того, как ему предписан вывод из эксплуатации (out-of-service), первое такое нарушение приводит к приостановке CDL на какой срок?","options":["30 days","90 days","6 месяцев","3 года"],"explanation":"Montana CDL Manual (Driver Disqualifications, MT-5) устанавливает, что если вы продолжаете движение после предписания о выводе из эксплуатации, ваш CDL будет приостановлен на шесть месяцев за первое нарушение (и дольше за последующие). Источник: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); 49 CFR 383.51."},"38":{"q":"Ограниченный сезонный CDL штата Монтана для квалифицированных работников сельскохозяйственного обслуживания действителен в течение какого сезонного периода в каждом календарном году?","options":["С January 1 по June 30","С March 15 по September 10","С April 1 по October 1","С May 1 по November 30"],"explanation":"Montana CDL Manual (Restricted Seasonal CDL, MT-5) устанавливает, что сезонный CDL действителен только в период с March 15 по September 10 календарного года и разрешает работу в радиусе 150-mile от места работы или фермы. Источник: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"39":{"q":"В штате Монтана какова концентрация алкоголя в крови (BAC), при которой или выше которой человек считается незаконно управляющим коммерческим транспортным средством (CMV)?","options":["0.08","0.04","0.02","0.10"],"explanation":"Монтана следует федеральному стандарту для CMV: управление CMV с концентрацией алкоголя 0.04 или более является тяжким нарушением (major offense). Источник: MCA 61-8-802 и Montana CDL Manual (Section 1, Disqualifications); 49 CFR 383.51."},"40":{"q":"Согласно закону штата Монтана о подразумеваемом согласии (implied-consent), управляя любым транспортным средством в штате, водитель считается уже давшим согласие на что из следующего?","options":["Тест крови, дыхания или мочи на алкоголь или наркотики","Обыск транспортного средства без ордера","Ежегодное медицинское обследование","Проверку зрения при каждой остановке"],"explanation":"Закон штата Монтана о подразумеваемом согласии предусматривает, что любой, кто управляет транспортным средством в штате, дал согласие на тест крови, дыхания или мочи для определения концентрации алкоголя или присутствия наркотиков. Источник: статут штата Монтана о подразумеваемом согласии (MCA 61-8-1016, ранее 61-8-402) и Montana CDL Manual."},"41":{"q":"Держатель CDL штата Монтана совершает первое тяжкое нарушение (например, DUI), НЕ перевозя при этом опасные грузы. На какой срок дисквалифицируется CDL?","options":["6 месяцев","1 год","3 года","60 days"],"explanation":"Первое тяжкое нарушение влечёт дисквалификацию CDL на 1 год. Источник: MCA 61-8-802(1) и Montana CDL Manual; 49 CFR 383.51."},"42":{"q":"Если первое тяжкое нарушение держателя CDL штата Монтана совершается во время управления CMV, перевозящим опасные грузы, требующие маркировки (placardable), срок дисквалификации увеличивается до:","options":["1 года","2 лет","3 лет","Пожизненной"],"explanation":"Когда первое тяжкое нарушение совершается во время управления CMV, перевозящим опасные грузы, требующие маркировки, дисквалификация составляет 3 года вместо 1 года. Источник: MCA 61-8-802(1) и Montana CDL Manual; 49 CFR 383.51."},"43":{"q":"Каков срок дисквалификации в штате Монтана для водителя, осуждённого за ВТОРОЕ тяжкое нарушение (по отдельному инциденту) в течение жизни?","options":["3 года","5 лет","10 лет","Пожизненно"],"explanation":"Второе тяжкое нарушение влечёт пожизненную дисквалификацию, хотя Монтана может разрешить восстановление согласно федеральным правилам после минимального 10-летнего периода. Источник: MCA 61-8-802 и Montana CDL Manual; 49 CFR 383.51."},"44":{"q":"Водителя CMV штата Монтана на законных основаниях просят пройти тест дыхания на алкоголь, и он отказывается. Как расценивается этот отказ для целей CDL?","options":["Как серьёзное нарушение правил дорожного движения (штраф 60 days)","Как тяжкое нарушение, с той же дисквалификацией, что и при проваленном тесте","Как не подлежащий отчётности административный вопрос","Как нарушение предписания о выводе из эксплуатации (out-of-service)"],"explanation":"Отказ от обязательного теста на алкоголь/наркотики в рамках подразумеваемого согласия является тяжким нарушением и влечёт ту же дисквалификацию, что и тест с результатом 0.04 или выше: 1 год (3 года для опасных грузов) за первый отказ, пожизненно за второй. Источник: MCA 61-8-802 и Montana CDL Manual; 49 CFR 383.51."},"45":{"q":"Водитель CMV штата Монтана, у которого обнаружено любое определяемое количество алкоголя ниже 0.04, не дисквалифицируется, но должен быть выведен из эксплуатации (out of service) на какой срок?","options":["1 hour","8 hours","24 hours","72 hours"],"explanation":"Водитель CMV с определяемой концентрацией алкоголя ниже 0.04 должен быть выведен из эксплуатации на 24 hours. Источник: Montana CDL Manual; 49 CFR 392.5 / 383.51."},"46":{"q":"Что из следующего классифицируется как СЕРЬЁЗНОЕ нарушение правил дорожного движения для держателя CDL штата Монтана?","options":["Движение со скоростью на 15 mph или более выше установленного ограничения","Первое DUI в CMV","Отказ от теста на алкоголь","Управление при лицензии, приостановленной за DUI"],"explanation":"Чрезмерное превышение скорости (на 15 mph или более выше ограничения) является серьёзным нарушением правил дорожного движения. DUI и отказ от теста являются тяжкими нарушениями, а не серьёзными нарушениями. Источник: Montana CDL Manual (Disqualifications); 49 CFR 383.51."},"47":{"q":"Сколько серьёзных нарушений правил дорожного движения в течение 3-летнего периода влекут 60-дневную дисквалификацию CDL штата Монтана?","options":["Одно","Два","Три","Четыре"],"explanation":"Второе серьёзное нарушение правил дорожного движения в течение 3-летнего периода влечёт 60-дневную дисквалификацию. Источник: Montana CDL Manual; 49 CFR 383.51."},"48":{"q":"Держатель CDL штата Монтана осуждён за ТРИ серьёзных нарушения правил дорожного движения в течение 3-летнего периода. Какова минимальная дисквалификация?","options":["60 days","90 days","120 days","180 days"],"explanation":"Три серьёзных нарушения правил дорожного движения за 3-летний период влекут 120-дневную дисквалификацию. Источник: Montana CDL Manual; 49 CFR 383.51."},"49":{"q":"Что из перечисленного НЕ считается серьёзным нарушением правил дорожного движения для держателя CDL штата Монтана?","options":["Движение со слишком малой дистанцией (following too closely)","Неправильная или беспорядочная смена полосы движения","Безрассудное вождение (reckless driving)","Движение со скоростью на 5 mph выше ограничения"],"explanation":"Серьёзные нарушения включают безрассудное вождение, неправильную/беспорядочную смену полосы, движение со слишком малой дистанцией и превышение скорости на 15+ mph выше ограничения. Незначительное превышение скорости (например, на 5 mph) не является серьёзным нарушением. Источник: Montana CDL Manual; 49 CFR 383.51."},"50":{"q":"Использование ручного мобильного телефона во время управления CMV для целей CDL штата Монтана классифицируется как какой тип нарушения?","options":["Тяжкое нарушение","Серьёзное нарушение правил дорожного движения","Нарушение предписания о выводе из эксплуатации (out-of-service)","Нарушение на железнодорожном переезде"],"explanation":"Использование ручного мобильного телефона во время управления CMV является серьёзным нарушением правил дорожного движения согласно федеральному правилу, применяемому в штате Монтана. Источник: Montana CDL Manual; 49 CFR 392.82 и 383.51."},"51":{"q":"Отправка текстовых сообщений во время управления CMV запрещена для водителей CDL штата Монтана. Второе осуждение за отправку сообщений/использование ручного телефона в течение 3 лет влечёт какую дисквалификацию?","options":["Никакой дисквалификации","60 days","120 days","1 год"],"explanation":"Отправка сообщений/использование ручного телефона является серьёзным нарушением. Первое осуждение не влечёт дисквалификации, но второе в течение 3 лет влечёт 60-дневную дисквалификацию (120 days за третье). Источник: Montana CDL Manual; 49 CFR 392.80/392.82 и 383.51."},"52":{"q":"Какова минимальная дисквалификация за ПЕРВОЕ нарушение на железнодорожно-автомобильном переезде, совершённое держателем CDL штата Монтана во время управления CMV?","options":["30 days","60 days","120 days","1 год"],"explanation":"Первое нарушение на железнодорожно-автомобильном переезде влечёт минимальную 60-дневную дисквалификацию. Источник: Montana CDL Manual; 49 CFR 383.51."},"53":{"q":"За ВТОРОЕ нарушение на железнодорожном переезде в течение 3-летнего периода CDL штата Монтана дисквалифицируется не менее чем на:","options":["60 days","120 days","180 days","1 год"],"explanation":"Второе нарушение на железнодорожном переезде за 3-летний период влечёт минимальную 120-дневную дисквалификацию. Источник: Montana CDL Manual; 49 CFR 383.51."},"54":{"q":"ТРЕТЬЕ нарушение на железнодорожном переезде в течение 3-летнего периода дисквалифицирует CDL штата Монтана не менее чем на:","options":["120 days","180 days","1 год","3 года"],"explanation":"Третье нарушение на железнодорожном переезде за 3-летний период влечёт минимальную 1-летнюю дисквалификацию. Источник: Montana CDL Manual; 49 CFR 383.51."},"55":{"q":"Водитель CMV штата Монтана нарушает предписание о выводе из эксплуатации (out-of-service) ВПЕРВЫЕ (не перевозя опасные грузы или пассажиров). Какова минимальная дисквалификация?","options":["30 days","90 days","180 days","1 год"],"explanation":"Первое осуждение за нарушение предписания о выводе из эксплуатации влечёт дисквалификацию не менее 180 days. Источник: Montana CDL Manual; 49 CFR 383.51."},"56":{"q":"Какова минимальная дисквалификация за ВТОРОЕ нарушение предписания о выводе из эксплуатации (отдельные инциденты) в течение 10-летнего периода для держателя CDL штата Монтана?","options":["180 days","1 год","2 года","3 года"],"explanation":"Второе нарушение предписания о выводе из эксплуатации по отдельным инцидентам в течение 10 лет влечёт минимальную 2-летнюю дисквалификацию (3 года за третье). Источник: Montana CDL Manual; 49 CFR 383.51."},"57":{"q":"Если водитель CMV штата Монтана нарушает предписание о выводе из эксплуатации впервые, перевозя опасные грузы, требующие маркировки (placardable), ЛИБО управляя транспортным средством, рассчитанным на перевозку 16 или более пассажиров, минимальная дисквалификация составляет:","options":["60 days","180 days","1 год","2 года"],"explanation":"Первое нарушение предписания о выводе из эксплуатации при перевозке маркированных опасных грузов или перевозке 16+ пассажиров (включая водителя) влечёт минимальную 180-дневную дисквалификацию, с не менее чем 3 годами за последующее нарушение. Источник: Montana CDL Manual; 49 CFR 383.51."},"58":{"q":"Держатель CDL штата Монтана получает DUI в своём ЛИЧНОМ (некоммерческом) транспортном средстве. Как это влияет на его CDL?","options":["Это не имеет последствий, поскольку было не в CMV","Это расценивается как тяжкое нарушение и дисквалифицирует CDL","Это лишь добавляет штрафные баллы, но без дисквалификации","Это влечёт только 24-часовое предписание о выводе из эксплуатации"],"explanation":"Тяжкие нарушения, такие как DUI, дисквалифицируют CDL, даже когда они совершены в личном транспортном средстве; первое нарушение влечёт дисквалификацию на 1 год. Источник: MCA 61-8-802 и Montana CDL Manual; 49 CFR 383.51."},"59":{"q":"На федеральной междуштатной автомагистрали (interstate) в Монтане за пределами городской зоны загруженный седельный тягач (грузовик с номинальной грузоподъёмностью более 1 тонны) может законно двигаться с какой максимальной скоростью?","options":["65 mph в любое время","80 mph, так же как легковые автомобили","70 mph в любое время","75 mph днём, 65 mph ночью"],"explanation":"Монтана устанавливает отдельный лимит для грузовиков: грузовик/седельный тягач с номинальной грузоподъёмностью более 1 тонны ограничен 70 mph на междуштатной автомагистрали, хотя легковые автомобили могут двигаться со скоростью 80 mph на сельских участках. Источник: MCA 61-8-312 (особые ограничения скорости для грузовиков) и 61-8-303; повышено законом HB393 (2019)."},"60":{"q":"На двухполосной общественной дороге Монтаны, которая НЕ является междуштатной автомагистралью, максимальная скорость для грузовика с номинальной грузоподъёмностью более 1 тонны составляет:","options":["70 mph днём, 65 mph ночью","60 mph днём, 55 mph ночью","65 mph днём и ночью","55 mph в любое время"],"explanation":"На дорогах, не являющихся междуштатными автомагистралями, лимит для грузовиков составляет ровно 65 mph днём и ночью. Прежние раздельные значения 60 днём/55 ночью были отменены в 2019 году. Источник: MCA 61-8-312; HB393 (2019)."},"61":{"q":"Согласно правилу Монтаны о железнодорожных переездах для автобусов и автомобилей с обязательными плакатами HazMat, которые обязаны останавливаться, в случае отсутствия нанесённой стоп-линии водитель должен остановиться в пределах какого расстояния от ближайшего рельса?","options":["Не ближе 15 футов и не дальше 50 футов","Не ближе 10 футов и не дальше 40 футов","Не ближе 25 футов и не дальше 75 футов","Не ближе 5 футов и не дальше 30 футов"],"explanation":"Монтана следует правилу «от 15 до 50 футов»: транспортные средства, обязанные остановиться, должны остановиться не ближе 15 футов и не дальше 50 футов от ближайшего рельса ближайшего пути. Источник: Руководство CDL Монтаны, раздел 2.15 (Железнодорожные переезды)."},"62":{"q":"Какие коммерческие транспортные средства ВСЕГДА обязаны полностью останавливаться на железнодорожном переезде в одном уровне в Монтане (при отсутствии зелёного сигнала или указаний полиции)?","options":["Все составные транспортные средства массой более 26 001 фунта","Только составы с тройными прицепами","Любой грузовик, зарегистрированный за пределами штата","Автобусы, перевозящие пассажиров, и транспортные средства, обязанные иметь плакаты для опасных грузов"],"explanation":"В руководстве Монтаны указано, что все пассажирские (автобусы) и транспортные средства с плакатами HazMat обязаны останавливаться на переезде; обычные загруженные грузовики не обязаны, если этого не требует груз или закон. Источник: Руководство CDL Монтаны, разделы 2.15.2 и 2.15.4."},"63":{"q":"Согласно закону Монтаны о школьных автобусах, когда школьный автобус остановлен на проезжей части с мигающими красными огнями, приближающийся водитель должен остановиться не менее чем приблизительно на каком расстоянии от автобуса?","options":["20 футов","50 футов","30 футов","10 футов"],"explanation":"Монтана требует, чтобы водители, приближающиеся с любого направления, останавливались не менее чем приблизительно за 30 футов от школьного автобуса с мигающими красными огнями и оставались на месте, пока красные огни не погаснут. Источник: MCA 61-8-351 (встреча или обгон школьного автобуса)."},"64":{"q":"На дороге Монтаны с раздельными проезжими частями (например, разделённая магистраль, где встречное направление находится на физически отдельной проезжей части) водитель, встречающий школьный автобус, остановившийся на ДРУГОЙ проезжей части, должен:","options":["Остановиться, потому что весь приближающийся транспорт всегда обязан останавливаться","Остановиться, только если разделительная полоса уже 30 футов","Не останавливаться — транспортные средства на другой проезжей части останавливаться не обязаны","Снизить скорость до 10 mph, но полностью останавливаться не обязан"],"explanation":"Исключение Монтаны: водитель на дороге с раздельными проезжими частями не обязан останавливаться при встрече или обгоне школьного автобуса, находящегося на другой проезжей части. Исключение привязано к «раздельным проезжим частям», а не просто к нанесённой осевой линии. Источник: MCA 61-8-351."},"65":{"q":"Когда школьный автобус в Монтане включил только МИГАЮЩИЕ ЖЁЛТЫЕ (янтарные) огни, приближающийся водитель обязан:","options":["Снизить скорость до разумной и быть готовым остановиться","Немедленно полностью остановиться не менее чем за 30 футов","Сохранять скорость, потому что янтарные огни не несут никакой обязанности","Остановиться, только если у обочины видны дети"],"explanation":"Мигающие янтарные огни означают, что автобус готовится к остановке; закон Монтаны требует, чтобы водители снизили скорость до разумной и были готовы остановиться. Обязанность остановиться возникает при включении красных огней. Источник: MCA 61-8-351."},"66":{"q":"Согласно закону Монтаны «Move Over», при приближении к неподвижному аварийному транспортному средству или транспортному средству дорожных рабочих на МЕЖДУШТАТНОЙ автомагистрали, когда смена полосы ВОЗМОЖНА, водитель должен снизить скорость не менее чем насколько ниже установленного лимита?","options":["На 10 mph ниже установленного лимита","На 30 mph ниже установленного лимита","На 20 mph ниже установленного лимита","На 5 mph ниже установленного лимита"],"explanation":"MCA 61-8-388 требует снижения скорости до 20 mph ниже установленного лимита на междуштатной автомагистрали, когда смена полосы возможна (с переходом на несмежную полосу). Если смена полосы небезопасна, водитель должен снизить скорость до половины установленного лимита. Источник: MCA 61-8-388."},"67":{"q":"Согласно закону Монтаны «Move Over», на ШТАТНОЙ ТРАССЕ или ОКРУЖНОЙ ДОРОГЕ, где смена полосы возможна, требуемое снижение скорости при проезде мимо неподвижного аварийного транспортного средства составляет не менее:","options":["20 mph ниже установленного лимита","15 mph ниже установленного лимита","10 mph ниже установленного лимита","30 mph ниже установленного лимита"],"explanation":"На штатной трассе или окружной дороге MCA 61-8-388 требует снижения скорости до 30 mph ниже установленного лимита, когда смена полосы возможна; если смена полосы небезопасна, снизьте скорость до половины установленного лимита. Источник: MCA 61-8-388."},"68":{"q":"Согласно закону Монтаны «Move Over», если водитель НЕ может безопасно сменить полосу при приближении к неподвижному аварийному транспортному средству, до какой скорости водитель должен снизиться?","options":["До половины установленного лимита скорости","До 20 mph независимо от установленного лимита","До полной остановки, пока место происшествия не освободится","До 10 mph ниже установленного лимита"],"explanation":"Когда смену полосы нельзя выполнить безопасно, MCA 61-8-388 требует снижения скорости до половины установленного лимита скорости с продолжением движения с осторожностью. Источник: MCA 61-8-388."},"69":{"q":"На многополосной дороге Монтаны основное требование закона «Move Over» при приближении к неподвижному аварийному транспортному средству (когда временный установленный лимит отсутствует) состоит в том, чтобы:","options":["Полностью остановиться в правой полосе","Перестроиться на полосу, не смежную с остановившимся транспортным средством, если это можно сделать безопасно","Непрерывно сигналить во время проезда","Съехать на обочину, чтобы дать максимум пространства"],"explanation":"MCA 61-8-388 предписывает водителям на многополосной дороге освободить полосу, смежную с неподвижным аварийным транспортным средством или транспортным средством дорожных рабочих, когда это безопасно; если это невозможно, снизить скорость согласно требованиям и проехать с осторожностью. Источник: MCA 61-8-388."},"70":{"q":"Если водитель CDL в Монтане вынужден остановиться на обочине дороги, в течение скольких минут должны быть выставлены предупреждающие устройства?","options":["В течение 5 минут","В течение 10 минут","В течение 15 минут","В течение 30 минут"],"explanation":"Остановившийся грузовик или автобус должен выставить аварийные предупреждающие устройства в течение 10 минут после остановки на дороге или обочине. Источник: Руководство CDL Монтаны, раздел 2.5 (Оповещение / предупреждающие устройства)."},"71":{"q":"Когда водитель CDL в Монтане остановился на дороге с ОДНОСТОРОННИМ движением или РАЗДЕЛЁННОЙ магистрали, где размещаются три предупреждающих устройства?","options":["В 10 ft, 50 ft и 150 ft в сторону приближающегося транспорта","В 10 ft, 100 ft и 200 ft в сторону приближающегося транспорта","В 10 ft, в 100 ft впереди и в 100 ft позади транспортного средства","В 15 ft, 50 ft и 100 ft в сторону приближающегося транспорта"],"explanation":"На дороге с односторонним движением или разделённой магистрали разместите предупреждающие устройства в 10 футах, 100 футах и 200 футах в сторону приближающегося транспорта. Источник: Руководство CDL Монтаны, раздел 2.5 (размещение предупреждающих устройств)."},"72":{"q":"На неразделённой двусторонней дороге Монтаны с движением в обоих направлениях три светоотражающих треугольника для остановившегося коммерческого транспортного средства размещаются:","options":["В пределах 10 ft от транспортного средства, а также в 100 ft спереди и в 100 ft сзади","В 10 ft, 100 ft и 200 ft, все позади транспортного средства","В 50 ft, 100 ft и 200 ft только в сторону встречного транспорта","В пределах 10 ft, а также в 200 ft спереди и в 200 ft сзади"],"explanation":"На двухполосной двусторонней или неразделённой дороге разместите одно устройство в пределах 10 футов от транспортного средства, одно — в 100 футах впереди и одно — в 100 футах позади, в полосе/на обочине, где вы остановились. Источник: Руководство CDL Монтаны, раздел 2.5."},"73":{"q":"Сколько красных светоотражающих треугольников транспортное средство CDL в Монтане обязано иметь в качестве обязательных аварийных предупреждающих устройств?","options":["Два","Три","Четыре","Шесть"],"explanation":"Обязательное предупреждающее оборудование — три красных светоотражающих треугольника (или альтернативы, такие как 6 факелов или 3 жидкотопливных сигнальных огня). Источник: Руководство CDL Монтаны, раздел 2.1 (осмотр транспортного средства) и раздел 2.5."},"74":{"q":"На дороге Монтаны, где холм или поворот закрывает обзор остановившегося коммерческого транспортного средства в пределах 500 футов, водитель должен:","options":["Разместить все три треугольника в пределах 10 футов от бампера","Передвинуть самый дальний треугольник дальше по дороге за препятствие, чтобы транспорт получил предупреждение","Оставить треугольники в стандартных позициях и полагаться на аварийную сигнализацию","Разместить треугольник ровно в 500 футах перед препятствием"],"explanation":"Если холм, поворот или препятствие мешают водителям увидеть транспортное средство в пределах 500 футов, передвиньте самое дальнее предупреждающее устройство за препятствие, чтобы приближающийся транспорт был предупреждён вовремя. Источник: Руководство CDL Монтаны, раздел 2.5."},"75":{"q":"Водитель школьного автобуса в Монтане, приближающийся к железнодорожному переезду, должен включить аварийную сигнализацию автобуса приблизительно на каком расстоянии до переезда?","options":["Примерно за 50 футов до переезда","Примерно за 500 футов до переезда","Только после остановки на переезде","Примерно за 200 футов до переезда"],"explanation":"Процедуры Монтаны для школьных автобусов предписывают включать аварийную сигнализацию примерно за 200 футов до переезда, а затем останавливаться в 15–50 футах от ближайшего рельса. Источник: Руководство CDL Монтаны, раздел 10 (Школьные автобусы), процедуры на переездах."},"76":{"q":"На междуштатной автомагистрали Монтаны в пределах городской зоны с населением 50 000 человек или более лимит скорости для легковых транспортных средств составляет:","options":["80 mph в любое время","75 mph днём, 65 mph ночью","55 mph в любое время","65 mph в любое время"],"explanation":"Хотя на сельских участках междуштатных автомагистралей легковым автомобилям разрешено 80 mph, лимит снижается до 65 mph на участках в пределах городской зоны с населением 50 000+ человек. Источник: MCA 61-8-303 (ограничения скорости)."},"77":{"q":"Там, где применяется закон «Move Over», Монтана также требует, чтобы водители подчинялись чему из перечисленного, если оно присутствует на месте?","options":["Указаниям регулировщика (флагмана) или выставленному временному щиту с ограничением скорости","Только радиоинструкциям диспетчера","Ничему более, как только сменена одна полоса","Обязательной полной остановке на каждом месте аварии"],"explanation":"MCA 61-8-388 требует, чтобы водители следовали указаниям любого регулировщика (флагмана) или выставленному временному щиту с ограничением скорости; установленные законом снижения в mph применяются только тогда, когда временный лимит не выставлен. Источник: MCA 61-8-388."},"78":{"q":"CDL класса A в Монтане, выданный после сдачи экзамена по навыкам на составе, соединённом сцепным крюком (pintle hook), а не седельно-сцепным устройством (fifth wheel), имеет какое ограничение?","options":["Ограничение «K», ограничивающее водителя только внутриштатными перевозками","Ограничение «L» для транспортных средств без пневматических тормозов","Ограничение «Z» для частичных пневматических тормозных систем","Ограничение «O», запрещающее управление составом тягач/полуприцеп с седельно-сцепным устройством"],"explanation":"Монтана накладывает ограничение «O» на лицензию класса A, когда экзамен по навыкам сдаётся на составе, соединённом сцепным крюком или другим устройством, не являющимся седельно-сцепным, запрещая управление тягачом/полуприцепом с седельно-сцепным устройством. Источник: Руководство CDL Монтаны (раздел ограничений/допусков лицензии)."},"79":{"q":"Какое ведомство Монтаны фактически выдаёт коммерческую водительскую лицензию (CDL) и обрабатывает заявление в окружном офисе?","options":["Федеральное управление безопасности грузоперевозок (FMCSA)","Управление транспортных средств Монтаны (Montana MVD)","Департамент транспорта Монтаны (MDT)","Дорожный патруль Монтаны"],"explanation":"В Монтане CDL выдаётся Управлением транспортных средств (MVD), и заявители завершают процесс в окружном офисе водительских лицензий. MDT (транспорт) ведёт программу экзамена по навыкам и ELDT, но сама лицензия выдаётся MVD. Источник: страницы CDL Montana MVD и MDT «Ten Easy Steps to a CDL»."},"80":{"q":"После того как вы сдали экзамен по навыкам CDL в Монтане, куда вы должны обратиться, чтобы коммерческая лицензия была фактически выдана?","options":["К экзаменатору по навыкам MDT, который печатает её на месте","На веб-сайт реестра поставщиков обучения FMCSA (Training Provider Registry)","Обратно в окружной офис MVD, чтобы лицензия была выдана","Она автоматически отправляется по почте без необходимости дополнительного визита"],"explanation":"MDT «Ten Easy Steps to a CDL» Монтаны указывает, что экзаменатор передаёт результаты экзамена по навыкам в MVD, но заявитель ОБЯЗАН вернуться в окружной MVD, чтобы новая коммерческая лицензия была выдана. Источник: MDT «Ten Easy Steps to a CDL», шаг 10."},"81":{"q":"Согласно федеральным правилам, принятым в Монтане, как долго вы должны иметь Коммерческое ученическое разрешение (CLP), прежде чем сможете сдавать экзамен по навыкам CDL (дорожный тест)?","options":["Не менее 14 дней","Не менее 7 дней","Не менее 30 дней","Не менее 60 дней"],"explanation":"Правила FMCSA, применяемые Монтаной, требуют иметь CLP минимум 14 дней, прежде чем сдавать экзамен по навыкам, даже когда действующий обладатель CDL просто повышает категорию. Источник: MDT «Ten Easy Steps to a CDL», шаги 4F и 9."},"82":{"q":"В течение какого срока действительно Коммерческое ученическое разрешение (CLP) Монтаны?","options":["90 дней","60 дней","1 год","180 дней"],"explanation":"CLP Монтаны действителен в течение 180 дней и может быть продлён один раз до истечения срока. Источник: Montana MVD «Getting a New CDL in Montana»."},"83":{"q":"Сколько раз CLP в Монтане может быть продлён до истечения его срока?","options":["Один раз","Он не может быть продлён","Два раза","Три раза"],"explanation":"Монтана позволяет продлить 180-дневный CLP один раз до истечения срока. Источник: Montana MVD «Getting a New CDL in Montana»."},"84":{"q":"Прежде чем впервые подающий заявление на класс A или класс B сможет сдать экзамен по навыкам в Монтане, какое обучение должно быть завершено и зарегистрировано в реестре поставщиков обучения FMCSA (Training Provider Registry)?","options":["Курс безопасного вождения, одобренный округом","Обучение водителей начального уровня (ELDT)","Программа совместных поездок с Дорожным патрулём Монтаны","Класс допуска на пневматические тормоза"],"explanation":"С 7 февраля 2022 года ELDT от поставщика, указанного в реестре поставщиков обучения FMCSA, требуется до того, как имеющий право заявитель сможет сдать экзамен по навыкам CDL. Сам MDT является зарегистрированным поставщиком обучения. Источник: MDT «Ten Easy Steps to a CDL», шаг 5; страница MDT ELDT."},"85":{"q":"Экзамен по навыкам CDL в Монтане проводится в три части. В каком наборе правильно названы эти три части?","options":["Письменный экзамен, проверка зрения и вождение по дороге","Предрейсовый осмотр, тест пневматических тормозов и ночное вождение","Предрейсовый осмотр, базовое управление транспортным средством и вождение по дороге","Движение задним ходом, сцепка и письменный тест на допуск"],"explanation":"Как и во всех штатах, экзамен по навыкам в Монтане из трёх частей состоит из предрейсового осмотра транспортного средства, манёвров базового управления транспортным средством (движение задним ходом) и дорожного теста. Источник: Руководство CDL Монтаны; MDT «Ten Easy Steps to a CDL», шаги 6–9."},"86":{"q":"В течение какого срока действителен стандартный CDL Монтаны до того, как его необходимо продлить (для типичного водителя в возрасте от 21 до 70 лет)?","options":["8 лет","5 лет","2 года","4 года"],"explanation":"Коммерческая водительская лицензия Монтаны выдаётся на 4 года — более короткий цикл, чем стандартная 8-летняя некоммерческая лицензия Монтаны. Источник: MDT «Ten Easy Steps to a CDL», шаг 10; страница продления CDL Montana MVD."},"87":{"q":"Из скольких категорий самосертификации деятельности должен выбрать заявитель на CDL в Монтане при декларировании своего типа вождения?","options":["Двух","Четырёх","Трёх","Шести"],"explanation":"Монтана использует четыре федеральные категории самосертификации: non-excepted interstate, excepted interstate, non-excepted intrastate (только Монтана) и excepted intrastate. Источник: форма Montana MVD CDL Self-Certification Classification and Medical Documentation; MCA 61-5-141."},"88":{"q":"Водитель в Монтане, который пересекает границы штатов и должен соответствовать всем федеральным стандартам физической квалификации, самосертифицируется по какой категории?","options":["Non-excepted interstate","Excepted interstate","Non-excepted intrastate","Excepted intrastate"],"explanation":"Водитель, осуществляющий межштатные перевозки и подпадающий под стандарты физической квалификации 49 CFR Part 391, самосертифицируется как non-excepted interstate и обязан хранить действующий медицинский сертификат экзаменатора. Источник: форма самосертификации Montana MVD; MCA 61-5-141."},"89":{"q":"Какая категория самосертификации требует от водителя предоставить и поддерживать действующий медицинский сертификат экзаменатора DOT в штате Монтана?","options":["Excepted interstate","Excepted intrastate","Non-excepted interstate","Excepted для государственного автопарка"],"explanation":"Водители категории non-excepted interstate должны соответствовать 49 CFR Part 391 и предоставить действующий медицинский сертификат экзаменатора; категории «excepted» не требуют наличия медицинской карты в деле. (Non-excepted intrastate также требует карты или медицинского заявления Монтаны.) Источник: форма самосертификации Montana MVD; MCA 61-5-141."},"90":{"q":"Когда обладатель CDL категории non-excepted в Монтане получает новый медицинский сертификат экзаменатора DOT, как он подаётся в штат?","options":["Он подаётся только работодателю водителя","Он передаётся в окружной MVD, который сканирует его в водительскую запись","Он отправляется напрямую в национальный офис FMCSA в Вашингтоне","Подача не требуется; подписи врача достаточно"],"explanation":"Водители категории non-excepted в Монтане должны подавать медицинский сертификат в свой окружной MVD при его получении и при каждом продлении; MVD сканирует копию в водительскую запись. Источник: MDT «Ten Easy Steps to a CDL», шаг 4B; MCA 61-5-141."},"91":{"q":"Стандартный медицинский сертификат экзаменатора DOT, используемый для поддержания действительности CDL в Монтане, может быть выдан на максимальный срок до:","options":["До 12 месяцев","До 36 месяцев","До 24 месяцев","До 6 месяцев"],"explanation":"Медосмотр DOT действителен на срок до 24 месяцев; экзаменатор может выдать сертификат на меньший срок для наблюдения за медицинским состоянием. Источник: MDT «Ten Easy Steps to a CDL», шаг 2; медицинские указания CDL Монтаны."},"92":{"q":"Согласно MCA 61-5-141, что происходит с CDL в Монтане, если обладатель не подаёт действующий медицинский сертификат к дате истечения его срока?","options":["Вся водительская лицензия немедленно аннулируется","Ничего не меняется до следующего 4-летнего продления","Водителя штрафуют, но он сохраняет полные привилегии CDL","MVD понижает коммерческую лицензию до базовой (не-CDL) лицензии"],"explanation":"MCA 61-5-141 предписывает департаменту отметить запись CDLIS как «not certified» и понизить коммерческую лицензию до базовой, если действующий сертификат отсутствует в деле. Источник: MCA 61-5-141, Самосертификация статуса деятельности."},"93":{"q":"Согласно закону Монтаны о самосертификации, в течение скольких дней MVD должен действовать, чтобы понизить CDL после истечения срока медицинского сертификата?","options":["10 дней","30 дней","60 дней","90 дней"],"explanation":"MCA 61-5-141 требует, чтобы департамент действовал в течение 10 дней с момента, когда сертификат становится недействительным, чтобы отметить запись как «not certified», понизить лицензию и уведомить водителя. Источник: MCA 61-5-141."},"94":{"q":"Как долго результаты сданного письменного теста знаний CDL в Монтане остаются действительными, если заявитель ещё не получил CDL?","options":["Шесть месяцев с даты сдачи","Один год с даты сдачи","Два года с даты сдачи","180 дней с даты сдачи"],"explanation":"Результаты теста знаний в Монтане остаются действительными в течение одного года с даты сдачи; если CDL не получен в течение этого года, все письменные тесты необходимо пересдать. Источник: MDT «Ten Easy Steps to a CDL», шаг 4D."},"95":{"q":"В Монтане когда заявитель, не сдавший письменный тест знаний CDL, может снова попытаться сдать этот тест?","options":["Только после 7-дневного периода ожидания","Только через 14 дней","На следующий день","Только через 30 дней"],"explanation":"Монтана позволяет пересдать несданный письменный тест знаний на следующий день. Источник: MDT «Ten Easy Steps to a CDL», шаг 4D."},"96":{"q":"В день экзамена сколько времени даётся заявителю в Монтане на выполнение части предрейсового осмотра транспортного средства экзамена по навыкам?","options":["30 минут","60 минут","20 минут","45 минут"],"explanation":"Монтана выделяет 45 минут на выполнение предрейсового осмотра в день экзамена; неправильное выполнение проверки тормозов приводит к провалу. Источник: MDT «Ten Easy Steps to a CDL», шаг 6A."},"97":{"q":"Заявитель на CDL в Монтане, который уже имеет стандартную (не-CDL) водительскую лицензию Монтаны, всё равно обязан предъявить что из перечисленного на приёме?","options":["Новое свидетельство о рождении каждый раз","Снова доказательство проживания в Монтане","Действующий медицинский сертификат DOT (экзаменатора)","Форму допуска Дорожного патруля Монтаны"],"explanation":"Заявители, которые уже имеют стандартную лицензию Монтаны, должны предоставить доказательство номера социального страхования, доказательство законного пребывания и действующий медицинский сертификат DOT (экзаменатора); доказательство личности/проживания уже было в деле. Источник: MDT «Ten Easy Steps to a CDL», Required Documents."},"98":{"q":"Каков минимальный возраст для получения CDL в Монтане для внутриштатного (только Монтана) коммерческого вождения по сравнению с межштатным вождением?","options":["21 для внутриштатного и 25 для межштатного","18 для обоих — внутриштатного и межштатного","16 для внутриштатного и 18 для межштатного","18 для внутриштатного и 21 для межштатного"],"explanation":"Монтана требует, чтобы заявителю было не менее 18 лет для управления коммерческим транспортным средством внутри штата (в пределах Монтаны) и не менее 21 года для межштатного вождения. Источник: Руководство CDL Монтаны; требования CDL Montana MVD."}},"tr":{"0":{"q":"Montana karayollarında, aşırı boyut izni olmadan bir ticari aracın ve yükünün izin verilen azami genişliği nedir?","options":["8 fit 0 inç (96 inç)","9 fit 0 inç (108 inç)","10 fit 0 inç (120 inç)","8 fit 6 inç (102 inç)"],"explanation":"Montana, MCA 61-10-102 ve Montana Ticari Araç Boyut, Ağırlık ve Güvenlik Sürücü El Kitabı ('Yasal Boyutlar') uyarınca aracın toplam dış genişliğini 102 inç (8 fit 6 inç) ile sınırlar. Bundan daha geniş yükler için izin gereklidir."},"1":{"q":"Montana karayollarında, yüklü veya yüksüz bir aracın izin verilen azami yüksekliği nedir?","options":["13 fit 6 inç","14 fit","15 fit","15 fit 6 inç"],"explanation":"MCA 61-10-103 ve Montana Sürücü El Kitabı uyarınca, bir araç (yüklü veya yüksüz) yükseklikte 14 fiti aşamaz. Daha büyük yükseklikler için aşırı boyut izni gereklidir."},"2":{"q":"İzin olmadan, Montana'da çekici-yarı römork kombinasyonundaki bir yarı römorkun azami uzunluğu nedir?","options":["48 fit","57 fit","53 fit","60 fit"],"explanation":"MCA 61-10-104 ve Montana Sürücü El Kitabı, azami yarı römork uzunluğunu 53 fit olarak belirler (yük taşımak için tasarlanmamış kısımlar hariç). Süreli izin ile bu, MCA 61-10-124 uyarınca 57 fite çıkarılabilir."},"3":{"q":"Montana'da, aşırı ağırlık izni olmadan tek bir aks üzerinde izin verilen azami brüt ağırlık nedir?","options":["20,000 pound","18,000 pound","22,400 pound","34,000 pound"],"explanation":"MCA 61-10-107 ve Montana Sürücü El Kitabı uyarınca, merkezleri birbirinden 40 inçten fazla olmayan bir veya daha fazla aks üzerindeki toplam ağırlık 20,000 poundu aşamaz. Bu, federal Eyaletlerarası tek aks sınırına denk gelir."},"4":{"q":"Montana'da, aşırı ağırlık izni olmadan bir ikiz aks grubunda izin verilen azami brüt ağırlık nedir?","options":["32,000 pound","34,000 pound","36,000 pound","40,000 pound"],"explanation":"MCA 61-10-107 ve Montana Sürücü El Kitabı, birbirinden 40 inçten fazla ancak 96 inçten az mesafedeki ardışık iki aksın 34,000 poundu aşan bir yük taşıyamayacağını belirtir."},"5":{"q":"Montana, ağırlık sınırı amaçları için 'ikiz aks'ı nasıl tanımlar?","options":["Birbirinden tam olarak 40 inç mesafedeki iki aks","Birbirinden 40 inçten fazla ve 96 inçten az mesafedeki ardışık iki aks","Birbirinden 120 inç içinde olan herhangi iki aks","Birbirinden 96 inçten fazla mesafedeki iki aks"],"explanation":"MCA 61-10-107 (Montana Sürücü El Kitabı'nda atıfta bulunulan) bir ikiz aksı, birbirinden 40 inçten fazla ancak 96 inçten az mesafedeki ardışık iki aks olarak tanımlar; böyle bir grup 34,000 pound ile sınırlıdır."},"6":{"q":"Bir aks grubu üzerindeki izin verilen azami brüt ağırlığı hesaplamak için kullanılan Montana köprü formülü nedir?","options":["W = 1000((LN/(N+1)) + 10N + 20)","W = 250((LN/(N-1)) + 6N + 18)","W = 500((LN/(N+1)) + 12N + 12)","W = 500((LN/(N-1)) + 12N + 36)"],"explanation":"Montana köprü formülü (federal Köprü Formülü B ile eşleşen) W = 500((LN/(N-1)) + 12N + 36) şeklindedir; burada L, bir grubun dış aksları arasındaki fit cinsinden mesafe ve N, aks sayısıdır; MCA 61-10-107 ve Montana Sürücü El Kitabı uyarınca."},"7":{"q":"Montana'da, tek ve ikiz aks ağırlık sınırları köprü formülü sonucunu ne zaman geçersiz kılar (öne geçer)?","options":["Birbirinden 120 inçten fazla mesafedeki tüm akslar için","Yalnızca Eyaletlerarası Sistemde","Birbirinden 96 inçten fazla olmayan tüm akslar için","Asla; köprü formülü her zaman geçerlidir"],"explanation":"Montana Sürücü El Kitabı, tek veya ikiz aks ağırlık sınırlarının, birbirinden 96 inçten fazla olmayan tüm akslar için köprü formülü sınırlarının önüne geçtiğini açıklar (MCA 61-10-107)."},"8":{"q":"Montana, indirgenebilir (bölünebilir) yük taşıyan bir araç kombinasyonu için hangi azami brüt ağırlığa izin verir?","options":["80,000 pound","105,500 pound","131,060 pound","129,000 pound"],"explanation":"MCA 61-10-107 ve Sürücü El Kitabı'ndaki Montana Brüt Araç Ağırlığı Çizelgesi uyarınca, indirgenebilir yükler için azami brüt ağırlık 131,060 pounddur."},"9":{"q":"Montana kuralları uyarınca direksiyon (ön) aks ağırlıkları nasıl sınırlandırılır?","options":["Lastik üreticisinin belirlediği kapasiteye kadar, 20,000 poundu aşmamak kaydıyla","Her durumda tam olarak 12,000 pound ile","İkiz aks gibi 34,000 pound ile","Direksiyon aksında sınır yoktur"],"explanation":"Montana Sürücü El Kitabı, direksiyon akslarının lastik yan duvarına basılı üreticinin belirlediği kapasiteyle, 20,000 poundu aşmamak kaydıyla sınırlandırıldığını belirtir (MCA 61-10-107)."},"10":{"q":"İzin olmadan, Montana karayollarında ayrıca belirtilmemiş araç kombinasyonları için azami toplam kombinasyon uzunluğu nedir?","options":["65 fit","75 fit","80 fit","70 fit"],"explanation":"MCA 61-10-104 ve Montana Sürücü El Kitabı, bu tür kombinasyonları toplamda 75 fit ile sınırlar (53 fitlik römork çeken çekiciler gibi daha fazla uzunluğa izin verilen kombinasyonlar hariç; bunların toplam uzunluk sınırı yoktur)."},"11":{"q":"Montana'da tek bir 53 fitlik (veya daha kısa) römork çeken bir çekici hangi uzunluk kuralına tabidir?","options":["Yine de toplamda 65 fit içinde kalmalıdır","Her zaman tek sefer izni gerektirir","Toplam uzunluğu ne olursa olsun toplam uzunluk izni gerekmez","Toplamda 70 fit ile sınırlıdır"],"explanation":"Montana Sürücü El Kitabı, 53 fitlik (veya daha kısa) römork çeken bir çekici için, toplam kombinasyon uzunluğu ne olursa olsun aşırı uzunluk izni gerekmediğini belirtir (MCA 61-10-104)."},"12":{"q":"Hangi Montana kurum bölümü ticari araçlar için aşırı boyut ve aşırı ağırlık izinleri ile brüt araç ağırlığı ücretleri verir?","options":["Montana Karayolu Polisi ruhsat masası","MDT'nin Motorlu Taşıyıcı Hizmetleri (MCS) Bölümü İzin Verme Bölümü","İlçe şerif ofisi","Federal Motorlu Taşıyıcı Güvenlik İdaresi"],"explanation":"Montana Sürücü El Kitabı uyarınca, Montana Ulaştırma Departmanı'nın Motorlu Taşıyıcı Hizmetleri (MCS) Bölümü İzin Verme Bölümü boyut/ağırlık izinleri verir; taşıyıcılar ayrıca çevrimiçi olarak kendileri de izin alabilir (ePART / eTRIPS)."},"13":{"q":"Yalnızca tek seferlik olan ve Montana için ruhsatlandırılmamış aşırı boyutlu bir yük ne tür bir izin gerektirir?","options":["Yalnızca kalıcı bir süreli izin","Özel bir biçerdöver izni","Tek seferlik bir hareket olduğu için izin gerekmez","Eyaletten ayrılınca geçersiz olan tek seferlik aşırı boyut izni"],"explanation":"Montana Sürücü El Kitabı, geçici sefer esasıyla çalışan operatörlerin tek seferlik aşırı boyut izni almaları gerektiğini öngörür (8'6\" genişlikten, 14' yükseklikten, 75' uzunluktan fazla yükler ya da 55'ten uzun tek üniteler için); bu izin eyaletten ayrılınca geçersiz olur."},"14":{"q":"Montana, aşırı boyut/aşırı ağırlık (özel) izninin verilmesi için hangi asgari sorumluluk sigortasını gerektirir?","options":["300,000 $ birleşik tek limit","500,000 $ birleşik tek limit","Her bir olay başına 1,000,000 $ birleşik tek limit","750,000 $ birleşik tek limit"],"explanation":"Montana Sürücü El Kitabı'nın Genel Aşırı Boyut İzni Gereklilikleri, her bir olay başına asgari 1,000,000 $ birleşik tek limit bedensel yaralanma ve maddi hasar sorumluluğu belirtir."},"15":{"q":"Montana'nın Kış Ağırlığı Süreli İzni ne kadar fazla ağırlığa ve hangi yollarda izin verir?","options":["1 Aralık - 7 Mart arası, Eyaletlerarası olmayan karayollarında %10 fazla","Yıl boyunca tüm karayollarında %20 fazla","Yalnızca Eyaletlerarası karayollarında %10 fazla","1 Kasım - 1 Nisan arası, Eyaletlerarası olmayan karayollarında %15 fazla"],"explanation":"Montana Sürücü El Kitabı, Kış Ağırlığı Süreli İzni'nin 1 Aralık - 7 Mart arasında Eyaletlerarası olmayan karayollarında %10 fazla ağırlığa izin verdiğini ve erken çözülmeler sırasında askıya alınabileceğini belirtir."},"16":{"q":"Montana'da yerleşik olmayan bir özel biçerdöver operasyonu, GVW ücretleri ve aşırı boyut izinleri yerine birim başına ne kadar özel izin ücreti ödeyebilir?","options":["Birim başına 20 $","Birim başına 35 $","Birim başına 105 $","Birim başına 40 $"],"explanation":"MCA 15-24-301 ve 61-10-130 (ve ARM 18.8.426) uyarınca, Montana Sürücü El Kitabı, yerleşik olmayan bir özel biçerdöver operasyonunun birim başına 40 $ özel izin ücreti ödeyebileceğini öngörür (yerleşikler %35 GVW ücretleri artı birim başına 20 $ öder)."},"17":{"q":"Montana Eyaletlerarası Sisteminde, Montana'da da geçerli olan federal tek aks ağırlık sınırı nedir?","options":["20,000 pound","18,000 pound","21,000 pound","24,000 pound"],"explanation":"Montana Sürücü El Kitabı, Eyaletlerarası Sistemdeki federal tek aks ağırlık sınırının 20,000 pound olduğunu açıkça belirtir; bu, MCA 61-10-107 uyarınca Montana'nın genel tek aks sınırıyla tutarlıdır."},"18":{"q":"Tarımla bağlantılı saman veya kuru ot taşımacılığı için Montana, hangi azami yüksekliğe ve hangi mesafe içinde izin verir?","options":["25 milden fazla olmamak kaydıyla 15 fit 6 inç","50 milden fazla olmamak kaydıyla 16 fit","10 milden fazla olmamak kaydıyla 14 fit 6 inç","100 milden fazla olmamak kaydıyla 15 fit"],"explanation":"MCA 61-10-103, bir tarım çiftlik araç-gerecinin ya da saman veya kuru ot taşıyan bir aracın, tarımla bağlantılı olarak 25 milden fazla yol kat etmemesi ve 17 fit veya daha alçak engellerin altından geçmemesi kaydıyla 15 fit 6 inçe ulaşabileceğine dair bir çiftlik istisnası sağlar."},"19":{"q":"Köprü formülü sınırını aşan ancak yasal aks ağırlıklarını AŞMAYAN bölünemez bir yük için Montana izin ücreti neye göre alınır?","options":["Mesafeye bakılmaksızın sabit 200 $ yıllık ücret","Yalnızca aracın tescilli brüt ağırlığı","Kargonun değerinin %10'u","Sefer mesafesi (örn. 100 mile kadar 10 $, 101-199 mil için 30 $, 200+ mil için 50 $)"],"explanation":"Montana Sürücü El Kitabı ('Köprüde Aşırı Ağırlık - Yasal Aks Ağırlıkları - Bölünemez Yükler', MCA 61-10-107) 100 mile kadar 10 $, 101-199 mil için 30 $ ve 200 mil ve üzeri için 50 $ ücret alır."},"20":{"q":"Montana'da, çekilen ünite(ler) 10,000 poundu aşarken brüt kombinasyon ağırlık derecesi (GCWR) 26,001 pound veya daha fazla olan bir araç kombinasyonunu kullanmak için hangi CDL sınıfı gereklidir?","options":["Sınıf A","Sınıf B","Sınıf C","Sınıf D"],"explanation":"Montana CDL El Kitabı (Sınıflandırmalar, MT-2) uyarınca, bir Sınıf A kombinasyon aracının GCWR'si, çekilen ünite(ler)in 4,536 kg (10,000 lbs) aşması kaydıyla 11,794 kg (26,001 lbs) veya daha fazladır. Kaynak: Montana CDL El Kitabı, Haz. 2026 Rev. (MVD/DOJ)."},"21":{"q":"Montana'da, GVWR'si 26,001 pound veya daha fazla olan ve 10,000 poundu aşan bir şey çekmeyen tek bir 'ağır ağır düz araç' hangi CDL sınıfını gerektirir?","options":["Sınıf A","Sınıf B","Sınıf C","Sınıf M"],"explanation":"Montana CDL El Kitabı (Sınıflandırmalar, MT-2), Sınıf B'yi GVWR'si 26,001 lbs veya daha fazla olan herhangi bir tek araç ya da 10,000 lbs'yi aşmayan bir ünite çeken böyle bir araç olarak tanımlar. Kaynak: Montana CDL El Kitabı, Haz. 2026 Rev. (MVD/DOJ)."},"22":{"q":"Montana'da, Sınıf A veya B ağırlık tanımlarını karşılamayan ancak 16 veya daha fazla yolcu (sürücü dahil) taşımak için tasarlanmış ya da plakartlanmış tehlikeli madde taşımak için kullanılan bir araç hangi CDL sınıfını gerektirir?","options":["Sınıf A","Sınıf B","Sınıf C","Sınıf D"],"explanation":"Montana CDL El Kitabı (Sınıflandırmalar, MT-2), Sınıf C'yi ne Sınıf A ne de Sınıf B'yi karşılayan ancak sürücü dahil 16+ yolcu taşımak için tasarlanmış ya da plakartlanabilir tehlikeli madde taşımak için kullanılan tek bir araç veya kombinasyon olarak tanımlar. Kaynak: Montana CDL El Kitabı, Haz. 2026 Rev. (MVD/DOJ)."},"23":{"q":"Montana CDL kuralları uyarınca, Yolcu (P) onayının gerekli olması için bir aracın taşıması için tasarlanması gereken asgari yolcu sayısı (sürücü dahil) kaçtır?","options":["8 yolcu","10 yolcu","15 yolcu","16 yolcu"],"explanation":"Montana CDL El Kitabı (MT-3), sürücü dahil 16 veya daha fazla yolcu taşımak için tasarlanmış Sınıf A, B veya C araçlar için Yolcu Aracı (P) onayının gerekli olduğunu belirtir. Kaynak: Montana CDL El Kitabı, Haz. 2026 Rev. (MVD/DOJ)."},"24":{"q":"Çift veya üç römork çeken bir ticari aracı kullanmak için hangi Montana CDL onayı gereklidir?","options":["N onayı","T onayı","X onayı","H onayı"],"explanation":"Montana CDL El Kitabı (MT-2/MT-3), Sınıf A veya B'de çift ya da üç römork çeken sürücüler için Çift/Üç Römork (T) onayının gerekli olduğunu belirtir. Kaynak: Montana CDL El Kitabı, Haz. 2026 Rev. (MVD/DOJ)."},"25":{"q":"Montana CDL El Kitabı'na göre, Tanker (N) onayı, derecelendirilmiş kapasitesi en az ne kadar olan bir tankta sıvı veya gaz halindeki maddeler taşınırken gereklidir?","options":["119 galon","500 galon","1,000 galon","3,500 galon"],"explanation":"Montana CDL El Kitabı (MT-3), Tank Aracı (N) onayını, derecelendirilmiş kapasitesi 1,000 galon veya daha fazla olan bir tank ya da toplam derecelendirilmiş kapasitesi 1,000 galon olan birden fazla tank için gerekli olarak tanımlar. Kaynak: Montana CDL El Kitabı, Haz. 2026 Rev. (MVD/DOJ)."},"26":{"q":"EYALET İÇİ (yalnızca Montana) Ticari Sürücü Belgesine başvurmak için asgari yaş nedir?","options":["16 yaş","18 yaş","19 yaş","21 yaş"],"explanation":"Montana CDL El Kitabı (Asgari Sürücü Yaşları, MT-3), eyalet içi (yalnızca Montana) başvuru sahibinin Montana niteliklerini karşılaması ve en az 18 yaşında olması gerektiğini belirtir. Kaynak: Montana CDL El Kitabı, Haz. 2026 Rev. (MVD/DOJ)."},"27":{"q":"Montana'da EYALETLERARASI Ticari Sürücü Belgesine başvurmak için asgari yaş nedir?","options":["18 yaş","19 yaş","21 yaş","25 yaş"],"explanation":"Montana CDL El Kitabı (Asgari Sürücü Yaşları, MT-3), eyaletlerarası bir belgeye başvurmak için en az 21 yaşında olmanız ve bir CDL niteliklerini karşılayabilmeniz gerektiğini belirtir. Kaynak: Montana CDL El Kitabı, Haz. 2026 Rev. (MVD/DOJ)."},"28":{"q":"Montana'da CDL beceri (yol öncesi kontrol, temel kontrol ve yol) testine girmeden önce, bir Ticari Öğrenci İzni asgari ne kadar süre tutulmalıdır?","options":["7 gün","10 gün","14 gün","30 gün"],"explanation":"Montana CDL El Kitabı (CLP tanımı, MT-2), tüm CLP izinlerinin yol öncesi kontrol, temel beceri ve yol testine girmeden önce asgari 14 gün tutulması gerektiğini belirtir (sürücü 15. günde test verebilir). Bu, federal CLP kuralını yansıtır. Kaynak: Montana CDL El Kitabı, Haz. 2026 Rev. (MVD/DOJ); 49 CFR 383.25."},"29":{"q":"Tehlikeli Maddeler (H) onaylı bir Montana CDL'si verilebilmeden, yenilenebilmeden veya devredilebilmeden önce, federal yasa sürücünün hangi taramayı geçmesini gerektirir?","options":["Yalnızca bir DOT ilaç ve alkol testi","Bir TSA Güvenlik Tehdit Değerlendirmesi (parmak izi temelli geçmiş kontrolü)","Bir FBI poligraf incelemesi","Bir eyalet görme ve refleks taraması"],"explanation":"Montana CDL El Kitabı (Tehlikeli Maddeler, MT-2), federal yasaya uygun olarak, bir HazMat onayı almak, devretmek veya yenilemek isteyen sürücülerin önce TSA tarafından parmak izi alımı ve sabıka geçmişi kontrolü dahil bir Güvenlik Tehdit Değerlendirmesi (STA) tamamlatmaları gerektiğini belirtir. Kaynak: Montana CDL El Kitabı, Haz. 2026 Rev. (MVD/DOJ); 49 CFR 1572."},"30":{"q":"Bir HazMat onayı için TSA Güvenlik Tehdit Değerlendirmesini tamamlamış bir Montana sürücüsünden, önceki değerlendirme son kaç yıl içinde yapılmışsa yenileme veya devir sırasında genellikle başka bir STA tamamlaması istenmez?","options":["1 yıl","2 yıl","5 yıl","7 yıl"],"explanation":"Montana CDL El Kitabı (MT-2), CDL'lerini yenilemek veya devretmek için başvurdukları son iki yıl içinde daha önce bir güvenlik tehdit değerlendirmesi yaptırmış olanlardan başka bir STA tamamlamalarının istenmeyebileceğini belirtir. Kaynak: Montana CDL El Kitabı, Haz. 2026 Rev. (MVD/DOJ)."},"31":{"q":"Montana'da benimsenen federal Giriş Seviyesi Sürücü Eğitimi (ELDT) kuralları uyarınca, ilk kez başvuran biri test öncesinde nerede listelenen bir sağlayıcıdan ELDT tamamlamalıdır?","options":["Montana DOT yüklenici listesi","FMCSA Eğitim Sağlayıcı Kaydı (TPR)","AAMVA sürücü okulu dizini","Eyaletin onayladığı herhangi bir meslek okulu"],"explanation":"ELDT, FMCSA Eğitim Sağlayıcı Kaydı'nda (TPR) listelenen bir sağlayıcıdan eğitim alınmasını gerektirir. Montana, CDL El Kitabı'nda (MT-2) bu gerekliliğe atıfta bulunur. Kaynak: FMCSA ELDT kuralı (49 CFR 380, 7 Şubat 2022'de yürürlüğe girdi); Montana CDL El Kitabı, Haz. 2026 Rev. (MVD/DOJ)."},"32":{"q":"Federal ELDT gereklilikleri, Sınıf A veya B CDL'sine ilk kez başvuranlar ile hangi onay grubuna ilk kez başvuranlar için geçerlidir?","options":["N (Tanker) ve T (Çift/Üç)","P (Yolcu), S (Okul Otobüsü) ve H (HazMat)","Yalnızca T (Çift/Üç) ve S (Okul Otobüsü)","Yalnızca H (HazMat)"],"explanation":"FMCSA ELDT kuralı uyarınca (7 Şubat 2022'de yürürlüğe girdi), ilk kez alınan Sınıf A/B CDL'leri ile ilk kez alınan Yolcu (P), Okul Otobüsü (S) ve Tehlikeli Maddeler (H) onayları için eğitim gereklidir. Montana bu gereklilikleri benimsemiştir (CDL El Kitabı, MT-2/MT-3). Kaynak: 49 CFR 380; Montana CDL El Kitabı, Haz. 2026 Rev. (MVD/DOJ)."},"33":{"q":"Aşağıdakilerden hangisi, bir Montana CDL başvuru sahibinin faaliyet gösterdiği ticaret türünü belirtmek için seçmesi gereken dört öz-sertifikasyon kategorisinden biridir?","options":["Eyaletlerarası istisna dışı (non-excepted)","Federal sözleşmeli taşıyıcı","Rekreasyonel eyaletlerarası","Sınırlı ticari muafiyet"],"explanation":"Montana CDL El Kitabı (Öz-Sertifikasyon, MT-3), dört kategoriyi Eyaletlerarası istisna dışı, Eyaletlerarası istisnalı, Eyalet içi istisna dışı ve Eyalet içi istisnalı olarak sıralar. Kaynak: Montana CDL El Kitabı, Haz. 2026 Rev. (MVD/DOJ); 49 CFR 383.71."},"34":{"q":"'Eyaletlerarası istisna dışı' olarak öz-sertifikasyon yapan bir Montana CDL başvuru sahibi, tıbbi gereklilikler hakkında hangi beyanı yapmaktadır?","options":["Bir tıbbi muayene belgesi bulundurmaktan muaf oldukları","Federal tıbbi (MEC) gerekliliklerini karşılamaları gerektiği","Yalnızca bir Montana eyalet içi tıbbi muafiyetine ihtiyaç duydukları","Hiçbir tıbbi sertifikasyona ihtiyaç duymadıkları"],"explanation":"Montana CDL El Kitabı (Öz-Sertifikasyon, MT-3), bir Eyaletlerarası istisna dışı sürücünün federal Tıbbi Muayene Belgesi (MEC) gerekliliklerini karşılaması gerektiğini belirtir. Kaynak: Montana CDL El Kitabı, Haz. 2026 Rev. (MVD/DOJ); 49 CFR 383.71."},"35":{"q":"Bir Montana ticari sürücü belgesi için tüm başvuru sahipleri kaç farklı kanıt kategorisinden belge sunmalıdır?","options":["İki: kimlik ve ikamet","Üç: yetkili bulunuş, kimlik ve Montana ikameti","Dört: kimlik, ikamet, SSN kartı ve vatandaşlık","Bir: tek bir REAL ID uyumlu belge"],"explanation":"Montana CDL El Kitabı (Yetkili Bulunuş, Kimlik ve İkamet Kanıtı, MT-7/MT-8), üç kategoriden belge gerektirir: yetkili bulunuş kanıtı, kimlik kanıtı ve Montana ikamet kanıtı. Kaynak: Montana CDL El Kitabı, Haz. 2026 Rev. (MVD/DOJ)."},"36":{"q":"Bir Montana CDL başvurusundaki Sosyal Güvenlik numarasıyla ilgili olarak eyalet neyi gerektirir?","options":["SSN, Sosyal Güvenlik İdaresi'nde kayıtlı numarayla eşleşmelidir","Bir CDL için hiçbir zaman SSN gerekmez","Yalnızca son dört hane kaydedilir ve asla doğrulanmaz","Noter onaylı bir beyanname SSN'nin yerini alır"],"explanation":"Montana CDL El Kitabı (Sosyal Güvenlik Numarası Kanıtı ve Kimlik Doğrulaması, MT-2), CDL başvurusunda kullanılan ad, doğum tarihi ve SSN'nin Sosyal Güvenlik İdaresi'nde kayıtlı bilgilerle eşleşmesi gerektiğini ve SSN'nin SSA ile kontrol edildiğini belirtir. Kaynak: Montana CDL El Kitabı, Haz. 2026 Rev. (MVD/DOJ); FMCSR 383.153."},"37":{"q":"Bir Montana ticari sürücüsü hizmet dışı (out-of-service) bırakıldıktan sonra araç kullanmaya devam ederse, bu tür ilk suç ne kadar süreli bir CDL askıya alınmasıyla sonuçlanır?","options":["30 gün","90 gün","6 ay","3 yıl"],"explanation":"Montana CDL El Kitabı (Sürücü Diskalifikasyonları, MT-5), hizmet dışı bırakıldıktan sonra araç kullanırsanız, CDL'nizin ilk suç için altı ay süreyle askıya alınacağını (ve sonraki suçlar için daha uzun süre) belirtir. Kaynak: Montana CDL El Kitabı, Haz. 2026 Rev. (MVD/DOJ); 49 CFR 383.51."},"38":{"q":"Montana'nın nitelikli çiftlikle ilgili hizmet çalışanlarına yönelik Kısıtlı Mevsimsel CDL'si her takvim yılında hangi mevsimsel dönemde geçerlidir?","options":["1 Ocak - 30 Haziran","15 Mart - 10 Eylül","1 Nisan - 1 Ekim","1 Mayıs - 30 Kasım"],"explanation":"Montana CDL El Kitabı (Kısıtlı Mevsimsel CDL, MT-5), bir Mevsimsel CDL'nin yalnızca bir takvim yılının 15 Mart - 10 Eylül dönemi için geçerli olduğunu ve iş yeri veya çiftliğin 150 millik yarıçapı içinde çalışmaya izin verdiğini belirtir. Kaynak: Montana CDL El Kitabı, Haz. 2026 Rev. (MVD/DOJ)."},"39":{"q":"Montana'da, bir kişinin ticari motorlu taşıt (CMV) kullanmasının yasa dışı sayıldığı kan alkol konsantrasyonu (BAC) eşiği ve üzeri nedir?","options":["0.08","0.04","0.02","0.10"],"explanation":"Montana, federal CMV standardını izler: bir CMV'yi 0.04 veya daha yüksek alkol konsantrasyonuyla kullanmak büyük bir suçtur. Kaynak: MCA 61-8-802 ve Montana CDL El Kitabı (Bölüm 1, Diskalifikasyonlar); 49 CFR 383.51."},"40":{"q":"Montana'nın zımni rıza yasası uyarınca, eyalette herhangi bir aracı kullanarak bir sürücü aşağıdakilerden hangisine zaten rıza göstermiş sayılır?","options":["Alkol veya uyuşturucu için kan, nefes ya da idrar testi","Mahkeme emri olmadan aracın aranması","Yıllık bir tıbbi muayene","Her trafik kontrolünde görme taraması"],"explanation":"Montana'nın zımni rıza yasası, eyalette bir aracı kullanan herkesin alkol konsantrasyonunu veya uyuşturucu varlığını belirlemek için kan, nefes ya da idrar testine rıza gösterdiğini öngörür. Kaynak: Montana zımni rıza yasası (MCA 61-8-1016, eski adıyla 61-8-402) ve Montana CDL El Kitabı."},"41":{"q":"Bir Montana CDL sahibi, tehlikeli madde TAŞIMAZKEN ilk büyük suçunu (örneğin DUI) işler. CDL ne kadar süreyle diskalifiye edilir?","options":["6 ay","1 yıl","3 yıl","60 gün"],"explanation":"İlk büyük suç, CDL'nin 1 yıllık diskalifikasyonuyla sonuçlanır. Kaynak: MCA 61-8-802(1) ve Montana CDL El Kitabı; 49 CFR 383.51."},"42":{"q":"Bir Montana CDL sahibinin ilk büyük suçu, plakartlanabilir tehlikeli madde taşıyan bir CMV kullanırken işlenirse, diskalifikasyon süresi şuna yükseltilir:","options":["1 yıl","2 yıl","3 yıl","Ömür boyu"],"explanation":"İlk büyük suç, plakartlanabilir tehlikeli madde taşıyan bir CMV kullanılırken işlendiğinde, diskalifikasyon 1 yıl yerine 3 yıldır. Kaynak: MCA 61-8-802(1) ve Montana CDL El Kitabı; 49 CFR 383.51."},"43":{"q":"Yaşamı boyunca (ayrı bir olaydan kaynaklanan) İKİNCİ bir büyük suçtan mahkûm olan bir sürücü için Montana'daki diskalifikasyon süresi nedir?","options":["3 yıl","5 yıl","10 yıl","Ömür boyu"],"explanation":"İkinci bir büyük suç, ömür boyu diskalifikasyonla sonuçlanır; ancak Montana, federal kurallar uyarınca asgari 10 yıllık bir süreden sonra yeniden işe iade etmeye izin verebilir. Kaynak: MCA 61-8-802 ve Montana CDL El Kitabı; 49 CFR 383.51."},"44":{"q":"Bir Montana CMV sürücüsünden yasal olarak alkol için nefes testi vermesi istenir ve reddeder. Bu reddetme CDL açısından nasıl değerlendirilir?","options":["Ciddi bir trafik ihlali olarak (60 günlük ceza)","Başarısız bir testle aynı diskalifikasyonu içeren büyük bir suç olarak","Bildirime tabi olmayan idari bir mesele olarak","Bir hizmet dışı emri ihlali olarak"],"explanation":"Zımni rıza uyarınca gerekli bir alkol/uyuşturucu testini reddetmek büyük bir suçtur ve 0.04 veya üzeri test sonucuyla aynı diskalifikasyonu taşır: ilk reddetme için 1 yıl (hazmat için 3 yıl), ikincisi için ömür boyu. Kaynak: MCA 61-8-802 ve Montana CDL El Kitabı; 49 CFR 383.51."},"45":{"q":"0.04'ün altında saptanabilir herhangi bir miktarda alkolü bulunan bir Montana CMV sürücüsü diskalifiye edilmez, ancak ne kadar süreyle hizmet dışı bırakılmalıdır?","options":["1 saat","8 saat","24 saat","72 saat"],"explanation":"0.04'ün altında saptanabilir alkol konsantrasyonu bulunan bir CMV sürücüsü 24 saat süreyle hizmet dışı bırakılmalıdır. Kaynak: Montana CDL El Kitabı; 49 CFR 392.5 / 383.51."},"46":{"q":"Aşağıdakilerden hangisi bir Montana CDL sahibi için CİDDİ bir trafik ihlali olarak sınıflandırılır?","options":["Belirtilen hız sınırının 15 mph veya daha fazla üzerinde sürmek","Bir CMV'de ilk DUI","Bir alkol testini reddetmek","Bir DUI nedeniyle belge askıdayken araç kullanmak"],"explanation":"Aşırı hız (sınırın 15 mph veya daha fazla üzerinde) ciddi bir trafik ihlalidir. DUI ve test reddi büyük suçlardır, ciddi ihlaller değil. Kaynak: Montana CDL El Kitabı (Diskalifikasyonlar); 49 CFR 383.51."},"47":{"q":"3 yıllık bir süre içinde kaç ciddi trafik ihlali, bir Montana CDL'sinin 60 günlük diskalifikasyonunu tetikler?","options":["Bir","İki","Üç","Dört"],"explanation":"3 yıllık bir süre içinde ikinci bir ciddi trafik ihlali 60 günlük diskalifikasyonla sonuçlanır. Kaynak: Montana CDL El Kitabı; 49 CFR 383.51."},"48":{"q":"Bir Montana CDL sahibi, 3 yıllık bir süre içinde ÜÇ ciddi trafik ihlalinden mahkûm olur. Asgari diskalifikasyon nedir?","options":["60 gün","90 gün","120 gün","180 gün"],"explanation":"3 yıllık bir süre içinde üç ciddi trafik ihlali 120 günlük diskalifikasyonla sonuçlanır. Kaynak: Montana CDL El Kitabı; 49 CFR 383.51."},"49":{"q":"Bunlardan hangisi bir Montana CDL sahibi için ciddi bir trafik ihlali olarak SAYILMAZ?","options":["Çok yakın takip etmek","Uygunsuz veya düzensiz şerit değişiklikleri","Dikkatsiz sürüş","Hız sınırının 5 mph üzerinde sürmek"],"explanation":"Ciddi ihlaller arasında dikkatsiz sürüş, uygunsuz/düzensiz şerit değişiklikleri, çok yakın takip etmek ve sınırın 15+ mph üzerinde hız yapmak bulunur. Hafif hız aşımı (örn. 5 mph üzeri) ciddi bir ihlal değildir. Kaynak: Montana CDL El Kitabı; 49 CFR 383.51."},"50":{"q":"Bir CMV kullanırken elde tutulan bir cep telefonu kullanmak, Montana CDL açısından hangi tür ihlal olarak sınıflandırılır?","options":["Büyük bir suç","Ciddi bir trafik ihlali","Bir hizmet dışı ihlali","Bir demiryolu geçidi ihlali"],"explanation":"Bir CMV kullanırken elde tutulan bir cep telefonu kullanmak, Montana'da uygulanan federal kural uyarınca ciddi bir trafik ihlalidir. Kaynak: Montana CDL El Kitabı; 49 CFR 392.82 ve 383.51."},"51":{"q":"Bir CMV kullanırken mesaj yazmak Montana CDL sürücüleri için yasaktır. 3 yıl içinde mesaj yazma/elde tutulan telefon kullanımından ikinci bir mahkûmiyet ne tür bir diskalifikasyonla sonuçlanır?","options":["Diskalifikasyon yok","60 gün","120 gün","1 yıl"],"explanation":"Mesaj yazma/elde tutulan telefon kullanımı ciddi bir ihlaldir. İlk mahkûmiyet diskalifikasyon getirmez, ancak 3 yıl içindeki ikincisi 60 günlük diskalifikasyonla (üçüncüsü için 120 gün) sonuçlanır. Kaynak: Montana CDL El Kitabı; 49 CFR 392.80/392.82 ve 383.51."},"52":{"q":"Bir CMV kullanırken işlenen bir Montana CDL sahibinin İLK demiryolu-karayolu hemzemin geçit ihlali için asgari diskalifikasyon nedir?","options":["30 gün","60 gün","120 gün","1 yıl"],"explanation":"İlk demiryolu-karayolu hemzemin geçit ihlali asgari 60 günlük diskalifikasyonla sonuçlanır. Kaynak: Montana CDL El Kitabı; 49 CFR 383.51."},"53":{"q":"3 yıllık bir süre içindeki İKİNCİ bir demiryolu hemzemin geçit ihlali için bir Montana CDL'si en az şu kadar diskalifiye edilir:","options":["60 gün","120 gün","180 gün","1 yıl"],"explanation":"3 yıllık bir süre içindeki ikinci bir demiryolu hemzemin geçit ihlali asgari 120 günlük diskalifikasyonla sonuçlanır. Kaynak: Montana CDL El Kitabı; 49 CFR 383.51."},"54":{"q":"3 yıllık bir süre içindeki ÜÇÜNCÜ bir demiryolu hemzemin geçit ihlali bir Montana CDL'sini en az şu kadar diskalifiye eder:","options":["120 gün","180 gün","1 yıl","3 yıl"],"explanation":"3 yıllık bir süre içindeki üçüncü bir demiryolu hemzemin geçit ihlali asgari 1 yıllık diskalifikasyonla sonuçlanır. Kaynak: Montana CDL El Kitabı; 49 CFR 383.51."},"55":{"q":"Bir Montana CMV sürücüsü, İLK kez bir hizmet dışı emrini ihlal eder (hazmat veya yolcu taşımamaktadır). Asgari diskalifikasyon nedir?","options":["30 gün","90 gün","180 gün","1 yıl"],"explanation":"Bir hizmet dışı emrini ihlal etmekten ilk mahkûmiyet en az 180 günlük diskalifikasyonla sonuçlanır. Kaynak: Montana CDL El Kitabı; 49 CFR 383.51."},"56":{"q":"Bir Montana CDL sahibi için 10 yıllık bir süre içinde (ayrı olaylarda) İKİNCİ bir hizmet dışı emri ihlali için asgari diskalifikasyon nedir?","options":["180 gün","1 yıl","2 yıl","3 yıl"],"explanation":"10 yıl içinde ayrı olaylarda ikinci bir hizmet dışı emri ihlali asgari 2 yıllık diskalifikasyonla sonuçlanır (üçüncüsü için 3 yıl). Kaynak: Montana CDL El Kitabı; 49 CFR 383.51."},"57":{"q":"Bir Montana CMV sürücüsü, plakartlanabilir tehlikeli madde taşırken VEYA 16 ya da daha fazla yolcu taşımak için tasarlanmış bir aracı kullanırken ilk kez bir hizmet dışı emrini ihlal ederse, asgari diskalifikasyon şudur:","options":["60 gün","180 gün","1 yıl","2 yıl"],"explanation":"Plakartlanmış hazmat taşırken veya 16+ yolcu (sürücü dahil) taşırken ilk hizmet dışı emri ihlali asgari 180 günlük diskalifikasyonla sonuçlanır; sonraki bir ihlal için en az 3 yıl. Kaynak: Montana CDL El Kitabı; 49 CFR 383.51."},"58":{"q":"Bir Montana CDL sahibi KİŞİSEL (ticari olmayan) aracında bir DUI alır. Bu, CDL'sini nasıl etkiler?","options":["Bir CMV'de olmadığı için hiçbir etkisi yoktur","Büyük bir suç olarak değerlendirilir ve CDL'yi diskalifiye eder","Yalnızca ceza puanı ekler ancak diskalifikasyon getirmez","Yalnızca 24 saatlik bir hizmet dışı emriyle sonuçlanır"],"explanation":"DUI gibi büyük suçlar, kişisel bir araçta işlense bile CDL'yi diskalifiye eder; ilk suç 1 yıllık bir diskalifikasyondur. Kaynak: MCA 61-8-802 ve Montana CDL El Kitabı; 49 CFR 383.51."},"59":{"q":"Bir kentsel alan dışındaki Montana federal destekli eyaletler arası otoyolda, yüklü bir yarı römork (1 tonu aşan derecelendirilmiş kapasiteye sahip kamyon) yasal olarak en fazla hangi hıza kadar seyahat edebilir?","options":["Her zaman 65 mph","80 mph, otomobillerle aynı","Her zaman 70 mph","Gündüz 75 mph, gece 65 mph"],"explanation":"Montana ayrı bir kamyon sınırı belirler: 1 tonu aşan derecelendirilmiş kapasiteye sahip bir kamyon/çekici, eyaletler arası otoyolda 70 mph ile sınırlandırılmıştır; otomobiller kırsal eyaletler arası otoyollarda 80 mph hızla gidebilse de. Kaynak: MCA 61-8-312 (kamyonlara özel hız sınırlamaları) ve 61-8-303; HB393 (2019) ile yükseltildi."},"60":{"q":"Eyaletler arası otoyol OLMAYAN bir Montana iki şeritli kamu otoyolunda, 1 tonu aşan derecelendirilmiş kapasiteye sahip bir kamyon için azami hız:","options":["Gündüz 70 mph, gece 65 mph","Gündüz 60 mph, gece 55 mph","65 mph, gündüz ve gece","Her zaman 55 mph"],"explanation":"Eyaletler arası olmayan otoyollarda kamyon sınırı gündüz ve gece sabit olarak 65 mph'dir. Daha eski olan gündüz 60 / gece 55 ayrımı 2019'da yürürlükten kaldırıldı. Kaynak: MCA 61-8-312; HB393 (2019)."},"61":{"q":"Montana'nın durmak zorunda olan otobüsler ve etiketli tehlikeli madde araçları için demir yolu geçidi kuralı uyarınca, boyalı bir durma çizgisinin bulunmadığı yerlerde, sürücü en yakın raydan hangi mesafe içinde durmalıdır?","options":["15 fitten daha yakın olmamak ve 50 fitten daha uzak olmamak","10 fitten daha yakın olmamak ve 40 fitten daha uzak olmamak","25 fitten daha yakın olmamak ve 75 fitten daha uzak olmamak","5 fitten daha yakın olmamak ve 30 fitten daha uzak olmamak"],"explanation":"Montana 15 ila 50 fit kuralını izler: durmak zorunda olan araçlar, en yakın rayın en yakın raydan 15 fitten daha yakın ve 50 fitten daha uzak olmayacak şekilde durmalıdır. Kaynak: Montana CDL Kılavuzu, Bölüm 2.15 (Demir yolu-karayolu Geçitleri)."},"62":{"q":"Hangi ticari araçlar bir Montana demir yolu-karayolu hemzemin geçidinde HER ZAMAN tam durmak zorundadır (yeşil işaret veya polis yönlendirmesi olmadığı sürece)?","options":["26.001 pound üzerindeki tüm kombine araçlar","Yalnızca üçlü römork kombinasyonları","Eyalet dışında kayıtlı herhangi bir kamyon","Yolcu taşıyan otobüsler ve tehlikeli maddeler için etiketlenmesi zorunlu olan araçlar"],"explanation":"Montana kılavuzu, tüm yolcu taşıyan (otobüs) ve tehlikeli madde etiketli araçların geçitte durmak zorunda olduğunu belirtir; sıradan yüklü kamyonlar, kargo veya yasa gerektirmedikçe durmak zorunda değildir. Kaynak: Montana CDL Kılavuzu, Bölüm 2.15.2 ve 2.15.4."},"63":{"q":"Montana'nın okul otobüsü yasası uyarınca, bir okul otobüsü kırmızı ışıkları yanıp sönerek yol üzerinde durduğunda, yaklaşan bir sürücü otobüsten yaklaşık ne kadar uzakta durmalıdır?","options":["20 fit","50 fit","30 fit","10 fit"],"explanation":"Montana, her iki yönden yaklaşan sürücülerin yanıp sönen kırmızı ışıkları gösteren bir okul otobüsünden yaklaşık 30 fitten daha yakın olmamak üzere durmasını ve kırmızı ışıklar sönene kadar durmuş halde kalmasını gerektirir. Kaynak: MCA 61-8-351 (okul otobüsüyle karşılaşma veya geçme)."},"64":{"q":"Ayrı yollara sahip bir Montana otoyolunda (örneğin karşı yönün fiziksel olarak ayrı bir yolda bulunduğu bölünmüş bir otoyol), DİĞER yolda durmuş bir okul otobüsüyle karşılaşan bir sürücü:","options":["Durmalıdır, çünkü yaklaşan tüm trafik her zaman durmalıdır","Yalnızca orta refüj 30 fitten dar ise durmalıdır","Durmamalıdır — farklı bir yoldaki araçların durması gerekmez","10 mph'ye yavaşlamalı ancak tam durmasına gerek yoktur"],"explanation":"Montana istisnası: ayrı yollara sahip bir otoyoldaki sürücü, farklı bir yolda bulunan bir okul otobüsüyle karşılaştığında veya onu geçtiğinde durmak zorunda değildir. İstisna, sadece boyalı bir orta çizgiye değil, 'ayrı yollara' bağlıdır. Kaynak: MCA 61-8-351."},"65":{"q":"Bir Montana okul otobüsü yalnızca YANIP SÖNEN SARI (amber) ışıklarını çalıştırdığında, yaklaşan bir sürücünün yapması gereken:","options":["Makul bir hıza yavaşlamak ve durmaya hazır olmak","Hemen en az 30 fit uzakta tam durmak","Hızı korumak, çünkü sarı ışıklar herhangi bir yükümlülük taşımaz","Yalnızca yol kenarında çocuklar görünürse durmak"],"explanation":"Yanıp sönen sarı, otobüsün durmaya hazırlandığı anlamına gelir; Montana yasası sürücülerin makul bir hıza yavaşlamasını ve durmaya hazır olmasını gerektirir. Durma yükümlülüğü kırmızı ışıklar etkinleştiğinde ortaya çıkar. Kaynak: MCA 61-8-351."},"66":{"q":"Montana'nın Şerit Değiştir (Move Over) yasası uyarınca, bir EYALETLER ARASI otoyolda durmuş bir acil durum veya karayolu çalışanı aracına yaklaşırken ve şerit değiştirmek MÜMKÜN olduğunda, sürücü hızını belirlenmiş sınırın en az ne kadar altına düşürmelidir?","options":["Belirlenmiş sınırın 10 mph altına","Belirlenmiş sınırın 30 mph altına","Belirlenmiş sınırın 20 mph altına","Belirlenmiş sınırın 5 mph altına"],"explanation":"MCA 61-8-388, şerit değiştirmek mümkün olduğunda (ve bitişik olmayan bir şeride geçerken) bir eyaletler arası otoyolda hızın belirlenmiş sınırın 20 mph altına düşürülmesini gerektirir. Şerit değiştirmek güvenli değilse, sürücü belirlenmiş sınırın yarısına yavaşlamalıdır. Kaynak: MCA 61-8-388."},"67":{"q":"Montana'nın Şerit Değiştir (Move Over) yasası uyarınca, şerit değiştirmenin mümkün olduğu bir EYALET OTOYOLU veya İLÇE YOLUNDA, durmuş bir acil durum aracını geçerken gereken hız düşüşü en az:","options":["Belirlenmiş sınırın 20 mph altı","Belirlenmiş sınırın 15 mph altı","Belirlenmiş sınırın 10 mph altı","Belirlenmiş sınırın 30 mph altı"],"explanation":"Bir eyalet otoyolu veya ilçe yolunda, MCA 61-8-388, şerit değiştirmek mümkün olduğunda belirlenmiş sınırın 30 mph altına yavaşlamayı gerektirir; şerit değiştirmek güvenli değilse, belirlenmiş sınırın yarısına yavaşlayın. Kaynak: MCA 61-8-388."},"68":{"q":"Montana'nın Şerit Değiştir (Move Over) yasası uyarınca, sürücü durmuş bir acil durum aracına yaklaşırken güvenli bir şekilde şerit değiştiremiyorsa, sürücü hangi hıza düşmelidir?","options":["Belirlenmiş hız sınırının yarısına","Belirlenmiş sınır ne olursa olsun 20 mph'ye","Olay yeri temizlenene kadar tam durmaya","Belirlenmiş sınırın 10 mph altına"],"explanation":"Şerit değiştirme güvenli bir şekilde yapılamadığında, MCA 61-8-388 dikkatle ilerlerken belirlenmiş hız sınırının yarısına düşürmeyi gerektirir. Kaynak: MCA 61-8-388."},"69":{"q":"Çok şeritli bir Montana otoyolunda, durmuş bir acil durum aracına yaklaşırken Şerit Değiştir yasasının (belirlenmiş geçici bir sınırın bulunmadığı durumda) temel gerekliliği:","options":["Sağ şeritte tamamen durmak","Güvenli bir şekilde yapılabiliyorsa, durmuş araca bitişik olmayan bir şeride geçmek","Geçerken kornaya sürekli basmak","Maksimum alan bırakmak için banket üzerine sürmek"],"explanation":"MCA 61-8-388, çok şeritli bir otoyoldaki sürücülere, güvenli olduğunda durmuş acil durum veya karayolu çalışanı aracına bitişik şeridi boşaltmalarını yönlendirir; bu mümkün değilse, gerektiği gibi yavaşlayın ve dikkatle geçin. Kaynak: MCA 61-8-388."},"70":{"q":"Bir Montana CDL sürücüsü bir yolun banketinde durmak zorunda kalırsa, uyarı cihazları kaç dakika içinde yerleştirilmelidir?","options":["5 dakika içinde","10 dakika içinde","15 dakika içinde","30 dakika içinde"],"explanation":"Durmuş bir kamyon veya otobüs, bir yolda veya bankette durduktan sonra 10 dakika içinde acil durum uyarı cihazlarını yerleştirmelidir. Kaynak: Montana CDL Kılavuzu, Bölüm 2.5 (İletişim / uyarı cihazları)."},"71":{"q":"Bir Montana CDL sürücüsü TEK YÖNLÜ veya BÖLÜNMÜŞ bir otoyolda durduğunda, üç uyarı cihazı nereye yerleştirilir?","options":["Yaklaşan trafiğe doğru 10 ft, 50 ft ve 150 ft","Yaklaşan trafiğe doğru 10 ft, 100 ft ve 200 ft","Aracın 10 ft önünde ve 100 ft önünde ve 100 ft arkasında","Yaklaşan trafiğe doğru 15 ft, 50 ft ve 100 ft"],"explanation":"Tek yönlü veya bölünmüş bir otoyolda, uyarı cihazlarını yaklaşan trafiğe doğru 10 fit, 100 fit ve 200 fit mesafelere yerleştirin. Kaynak: Montana CDL Kılavuzu, Bölüm 2.5 (uyarı cihazı yerleşimi)."},"72":{"q":"Her iki yönde trafik taşıyan bölünmemiş iki yönlü bir Montana yolunda, durmuş bir CMV için üç yansıtıcı üçgen şu mesafelere yerleştirilir:","options":["Aracın 10 ft içinde ve önde 100 ft ile arkada 100 ft","Hepsi aracın arkasında olmak üzere 10 ft, 100 ft ve 200 ft","Yalnızca karşıdan gelen trafiğe doğru 50 ft, 100 ft ve 200 ft","10 ft içinde ve önde 200 ft ile arkada 200 ft"],"explanation":"İki şeritli iki yönlü veya bölünmemiş bir yolda, durduğunuz şerit/bankette bir cihazı aracın 10 fit içine, birini 100 fit önüne ve birini 100 fit arkasına yerleştirin. Kaynak: Montana CDL Kılavuzu, Bölüm 2.5."},"73":{"q":"Bir Montana CDL aracı, zorunlu acil durum uyarı cihazları olarak kaç adet kırmızı yansıtıcı üçgen taşımalıdır?","options":["İki","Üç","Dört","Altı"],"explanation":"Zorunlu uyarı ekipmanı üç kırmızı yansıtıcı üçgendir (veya 6 fünye ya da 3 sıvı yanan işaret fişeği gibi alternatifler). Kaynak: Montana CDL Kılavuzu, Bölüm 2.1 (araç muayenesi) ve Bölüm 2.5."},"74":{"q":"Bir tepe veya virajın durmuş bir CMV'nin 500 fit içinde görüşünü engellediği bir Montana yolunda, sürücü şunu yapmalıdır:","options":["Üç üçgenin hepsini tamponun 10 fit içine yerleştirmek","En arkadaki üçgeni, trafik uyarı alabilsin diye yol boyunca geriye, engelin ötesine taşımak","Üçgenleri standart konumlarda bırakmak ve dörtlü flaşörlere güvenmek","Engelin tam 500 fit önüne bir üçgen yerleştirmek"],"explanation":"Bir tepe, viraj veya engel, sürücülerin aracı 500 fit içinde görmesini engelliyorsa, en arkadaki uyarı cihazını engelin ötesine geriye taşıyın ki yaklaşan trafik zamanında uyarılsın. Kaynak: Montana CDL Kılavuzu, Bölüm 2.5."},"75":{"q":"Bir demir yolu geçidine yaklaşan bir Montana okul otobüsü sürücüsü, otobüsün dörtlü flaşörlerini geçitten yaklaşık ne kadar önce çalıştırmalıdır?","options":["Geçitten yaklaşık 50 fit önce","Geçitten yaklaşık 500 fit önce","Yalnızca geçitte durduktan sonra","Geçitten yaklaşık 200 fit önce"],"explanation":"Montana'nın okul otobüsü prosedürleri, dörtlü flaşörlerin geçitten yaklaşık 200 fit önce çalıştırılmasını, ardından en yakın raydan 15 ila 50 fit mesafede durulmasını gerektirir. Kaynak: Montana CDL Kılavuzu, Bölüm 10 (Okul Otobüsleri), geçit prosedürleri."},"76":{"q":"50.000 veya daha fazla nüfuslu bir kentsel alan içindeki bir Montana eyaletler arası otoyolunda, binek araçlar için hız sınırı:","options":["Her zaman 80 mph","Gündüz 75 mph, gece 65 mph","Her zaman 55 mph","Her zaman 65 mph"],"explanation":"Kırsal eyaletler arası otoyollar otomobillere 80 mph izin verirken, sınır 50.000+ nüfuslu bir kentsel alan içindeki eyaletler arası otoyol kesimlerinde 65 mph'ye düşer. Kaynak: MCA 61-8-303 (hız kısıtlamaları)."},"77":{"q":"Şerit Değiştir yasasının geçerli olduğu yerlerde, Montana ayrıca sürücülerin olay yerinde mevcutsa aşağıdakilerden hangisine uymasını gerektirir?","options":["Bir işaretçinin yönlendirmeleri veya belirlenmiş geçici bir hız sınırı tabelası","Yalnızca operatörün telsiz talimatları","Bir şerit değiştirildikten sonra başka hiçbir şey","Her acil durum yerinde zorunlu tam durma"],"explanation":"MCA 61-8-388, sürücülerin herhangi bir işaretçinin yönlendirmelerine veya belirlenmiş geçici bir hız sınırı tabelasına uymasını gerektirir; yasal mph düşüşleri yalnızca geçici bir sınır belirtilmediğinde geçerlidir. Kaynak: MCA 61-8-388."},"78":{"q":"Bir mafsal kancası (beşinci teker değil) ile bağlanmış bir kombinasyonda beceri testinden sonra verilen bir Montana A Sınıfı CDL hangi kısıtlamayı taşır?","options":["Sürücüyü yalnızca eyalet içiyle sınırlandıran bir 'K' kısıtlaması","Hava frensi olmayan araçlar için bir 'L' kısıtlaması","Kısmi hava frenli sistemler için bir 'Z' kısıtlaması","Bir beşinci teker çekici/yarı römork kombinasyonu kullanımını yasaklayan bir 'O' kısıtlaması"],"explanation":"Montana, beceri testi bir mafsal kancası veya başka bir beşinci teker olmayan bağlantı ile bağlanmış bir kombinasyonda yapıldığında A Sınıfı bir lisansa 'O' kısıtlaması koyar ve bir beşinci teker çekici/yarı römork kullanımını yasaklar. Kaynak: Montana CDL Kılavuzu (lisans kısıtlamaları/onay bölümü)."},"79":{"q":"Hangi Montana kurumu gerçekte ticari sürücü belgesini (CDL) verir ve başvuruyu bir ilçe ofisinde işleme alır?","options":["Federal Motorlu Taşıyıcı Güvenlik İdaresi (FMCSA)","Montana Motorlu Araçlar Bölümü (MVD)","Montana Ulaştırma Departmanı (MDT)","Montana Karayolu Devriyesi"],"explanation":"Montana'da CDL, Motorlu Araçlar Bölümü (MVD) tarafından verilir ve başvuru sahipleri işlemi bir ilçe Sürücü Belgesi ofisinde tamamlar. MDT (Ulaştırma) beceri sınavı programını ve ELDT'yi yürütür, ancak belgenin kendisi MVD tarafından verilir. Kaynak: Montana MVD CDL sayfaları ve MDT 'CDL'ye Giden On Kolay Adım'."},"80":{"q":"Montana'da CDL beceri testini geçtikten sonra, ticari belgenin gerçekten verilmesi için nereye gitmelisiniz?","options":["Belgeyi anında basan MDT beceri sınavı görevlisine","FMCSA Eğitim Sağlayıcı Kayıt web sitesine","Belgenin verilmesi için tekrar ilçe MVD ofisine","Başka bir ziyaret gerekmeden otomatik olarak posta ile gönderilir"],"explanation":"Montana'nın MDT 'CDL'ye Giden On Kolay Adım' belgesi, sınav görevlisinin beceri testi sonuçlarını MVD'ye ilettiğini, ancak başvuru sahibinin yeni ticari belgenin verilmesi için ilçe MVD'ye GERİ DÖNMESİ GEREKTİĞİNİ belirtir. Kaynak: MDT 'CDL'ye Giden On Kolay Adım', Adım 10."},"81":{"q":"Montana'da uygulanan federal kurallar uyarınca, CDL beceri (yol) testini alabilmeniz için bir Ticari Öğrenici İzni (CLP) ne kadar süre elinizde tutmanız gerekir?","options":["En az 14 gün","En az 7 gün","En az 30 gün","En az 60 gün"],"explanation":"Montana tarafından uygulanan FMCSA kuralları, mevcut bir CDL sahibi yalnızca yükseltme yaparken bile, beceri testini almadan önce CLP'nin en az 14 gün tutulmasını gerektirir. Kaynak: MDT 'CDL'ye Giden On Kolay Adım', Adım 4F ve 9."},"82":{"q":"Bir Montana Ticari Öğrenici İzni (CLP) ne kadar süre geçerlidir?","options":["90 gün","60 gün","1 yıl","180 gün"],"explanation":"Bir Montana CLP'si 180 gün geçerlidir ve süresi dolmadan önce bir kez yenilenebilir. Kaynak: Montana MVD 'Montana'da Yeni Bir CDL Almak'."},"83":{"q":"Bir Montana CLP'si süresi dolmadan önce kaç kez yenilenebilir?","options":["Bir kez","Yenilenemez","İki kez","Üç kez"],"explanation":"Montana, 180 günlük CLP'nin süresi dolmadan önce bir kez yenilenmesine izin verir. Kaynak: Montana MVD 'Montana'da Yeni Bir CDL Almak'."},"84":{"q":"İlk kez A veya B Sınıfı başvuru sahibi Montana beceri testini alabilmeden önce, hangi eğitim tamamlanmalı ve FMCSA Eğitim Sağlayıcı Kayıt sistemine kaydedilmelidir?","options":["İlçe tarafından onaylanmış bir savunmacı sürüş kursu","Giriş Düzeyi Sürücü Eğitimi (ELDT)","Bir Montana Karayolu Devriyesi yanında sürüş programı","Bir hava frensi onay dersi"],"explanation":"7 Şubat 2022'den bu yana, uygun bir başvuru sahibinin CDL beceri testini alabilmesinden önce FMCSA'nın Eğitim Sağlayıcı Kayıt sisteminde listelenen bir sağlayıcıdan ELDT alınması zorunludur. MDT'nin kendisi kayıtlı bir eğitim sağlayıcısıdır. Kaynak: MDT 'CDL'ye Giden On Kolay Adım', Adım 5; MDT ELDT sayfası."},"85":{"q":"Montana'nın CDL beceri testi üç bölümde uygulanır. Hangi set bu üç bölümü doğru şekilde adlandırır?","options":["Yazılı sınav, görme taraması ve yolda sürüş","Sefer öncesi muayene, hava frensi testi ve gece sürüşü","Sefer öncesi muayene, temel araç kontrolü ve yolda sürüş","Geri manevra, kuplaj ve yazılı bir onay testi"],"explanation":"Tüm eyaletler gibi, Montana'nın üç bölümlü beceri testi sefer öncesi araç muayenesi, temel araç kontrolü (geri manevra) hareketleri ve yolda sürüş testinden oluşur. Kaynak: Montana CDL Kılavuzu; MDT 'CDL'ye Giden On Kolay Adım', Adım 6-9."},"86":{"q":"Standart bir Montana CDL'si yenilenmesi gerekmeden önce ne kadar süre geçerlidir (21 ila 70 yaş arası tipik bir sürücü için)?","options":["8 yıl","5 yıl","2 yıl","4 yıl"],"explanation":"Bir Montana ticari sürücü belgesi 4 yıl için verilir; bu, standart 8 yıllık ticari olmayan Montana belgesinden daha kısa bir döngüdür. Kaynak: MDT 'CDL'ye Giden On Kolay Adım', Adım 10; Montana MVD CDL yenileme sayfası."},"87":{"q":"Bir Montana CDL başvuru sahibi sürüş türünü beyan ederken kaç adet öz beyan işletme kategorisi arasından seçim yapmalıdır?","options":["İki","Dört","Üç","Altı"],"explanation":"Montana dört federal öz beyan kategorisini kullanır: istisna olmayan eyaletler arası, istisna olan eyaletler arası, istisna olmayan eyalet içi (yalnızca Montana) ve istisna olan eyalet içi. Kaynak: Montana MVD CDL Öz Beyan Sınıflandırması ve Tıbbi Belgelendirme formu; MCA 61-5-141."},"88":{"q":"Eyalet sınırlarını geçen ve tüm federal fiziksel uygunluk standartlarını karşılamak zorunda olan bir Montana sürücüsü hangi kategori altında öz beyanda bulunur?","options":["İstisna olmayan eyaletler arası","İstisna olan eyaletler arası","İstisna olmayan eyalet içi","İstisna olan eyalet içi"],"explanation":"Eyaletler arası ticarette faaliyet gösteren ve 49 CFR Bölüm 391 fiziksel uygunluk standartlarına tabi olan bir sürücü, istisna olmayan eyaletler arası olarak öz beyanda bulunur ve dosyasında güncel bir tıbbi muayene görevlisi sertifikası bulundurmalıdır. Kaynak: Montana MVD öz beyan formu; MCA 61-5-141."},"89":{"q":"Hangi öz beyan kategorisi, sürücünün Montana Eyaleti'ne geçerli bir DOT tıbbi muayene görevlisi sertifikası sunmasını ve bunu sürdürmesini gerektirir?","options":["İstisna olan eyaletler arası","İstisna olan eyalet içi","İstisna olmayan eyaletler arası","Devlet filosu istisnası"],"explanation":"İstisna olmayan eyaletler arası sürücüler 49 CFR Bölüm 391'i karşılamalı ve güncel bir Tıbbi Muayene Görevlisi Sertifikası sunmalıdır; 'istisna olan' kategoriler dosyada tıbbi kart bulundurulmasını gerektirmez. (İstisna olmayan eyalet içi de bir kart veya bir Montana tıbbi beyanı gerektirir.) Kaynak: Montana MVD öz beyan formu; MCA 61-5-141."},"90":{"q":"İstisna olmayan bir Montana CDL sahibi yeni bir DOT tıbbi muayene görevlisi sertifikası aldığında, bu eyalete nasıl sunulur?","options":["Yalnızca sürücünün işvereniyle dosyalanır","Sürücü siciline tarayarak ekleyen ilçe MVD'ye verilir","Washington'daki FMCSA ulusal ofisine doğrudan posta ile gönderilir","Sunulması gerekmez; doktorun imzası yeterlidir"],"explanation":"İstisna olmayan Montana sürücüleri, tıbbi sertifikayı aldıklarında ve her yenilemede ilçe MVD'lerine sunmalıdır; MVD bir kopyasını sürücü siciline tarar. Kaynak: MDT 'CDL'ye Giden On Kolay Adım', Adım 4B; MCA 61-5-141."},"91":{"q":"Bir Montana CDL'sini geçerli tutmak için kullanılan standart bir DOT tıbbi muayene görevlisi sertifikası en fazla ne kadar süre için verilebilir?","options":["12 aya kadar","36 aya kadar","24 aya kadar","6 aya kadar"],"explanation":"Bir DOT fiziksel muayenesi 24 aya kadar geçerlidir; bir muayene görevlisi tıbbi bir durumu izlemek için daha kısa süreli bir sertifika verebilir. Kaynak: MDT 'CDL'ye Giden On Kolay Adım', Adım 2; Montana CDL tıbbi rehberliği."},"92":{"q":"MCA 61-5-141 uyarınca, sahibi güncel bir tıbbi sertifikayı son geçerlilik tarihine kadar sunmazsa bir Montana CDL'sine ne olur?","options":["Tam sürücü belgesi derhal iptal edilir","Bir sonraki 4 yıllık yenilemeye kadar hiçbir şey değişmez","Sürücü para cezası alır ancak tam CDL ayrıcalıklarını korur","MVD ticari belgeyi temel (CDL olmayan) bir belgeye düşürür"],"explanation":"MCA 61-5-141, güncel bir sertifika dosyada yoksa departmanın CDLIS kaydını 'sertifikalı değil' olarak işaretlemesini ve ticari belgeyi temel bir belgeye düşürmesini yönlendirir. Kaynak: MCA 61-5-141, İşletme durumunun öz beyanı."},"93":{"q":"Montana'nın öz beyan yasası uyarınca, bir tıbbi sertifikanın süresi dolduktan sonra MVD bir CDL'yi düşürmek için kaç gün içinde harekete geçmelidir?","options":["10 gün","30 gün","60 gün","90 gün"],"explanation":"MCA 61-5-141, departmanın sertifika geçersiz hale geldikten sonra 10 gün içinde kaydı sertifikalı değil olarak işaretlemek, belgeyi düşürmek ve sürücüyü bilgilendirmek için harekete geçmesini gerektirir. Kaynak: MCA 61-5-141."},"94":{"q":"Başvuru sahibi henüz CDL'yi almamışsa, geçilmiş Montana CDL yazılı bilgi testi sonuçları ne kadar süre geçerli kalır?","options":["Geçildiği tarihten itibaren altı ay","Geçildiği tarihten itibaren bir yıl","Geçildiği tarihten itibaren iki yıl","Geçildiği tarihten itibaren 180 gün"],"explanation":"Montana bilgi testi sonuçları geçildiği tarihten itibaren bir yıl geçerli kalır; CDL o yıl içinde alınmazsa, tüm yazılı testlerin yeniden alınması gerekir. Kaynak: MDT 'CDL'ye Giden On Kolay Adım', Adım 4D."},"95":{"q":"Montana'da, bir CDL yazılı bilgi testinde başarısız olan bir başvuru sahibi o testi ne zaman yeniden deneyebilir?","options":["Yalnızca 7 günlük bir bekleme süresinden sonra","Yalnızca 14 günden sonra","Ertesi gün","Yalnızca 30 günden sonra"],"explanation":"Montana, başarısız olunan bir yazılı bilgi testinin ertesi gün yeniden alınmasına izin verir. Kaynak: MDT 'CDL'ye Giden On Kolay Adım', Adım 4D."},"96":{"q":"Test günü, bir Montana başvuru sahibinin beceri testinin sefer öncesi araç muayenesi bölümünü tamamlamak için ne kadar zamanı vardır?","options":["30 dakika","60 dakika","20 dakika","45 dakika"],"explanation":"Montana, test günü sefer öncesi muayenenin tamamlanması için 45 dakika ayırır; fren kontrolünün düzgün yapılmaması başarısızlıkla sonuçlanır. Kaynak: MDT 'CDL'ye Giden On Kolay Adım', Adım 6A."},"97":{"q":"Halihazırda standart bir Montana (CDL olmayan) sürücü belgesine sahip olan bir Montana CDL başvuru sahibi, randevuda yine de aşağıdakilerden hangisini sunmalıdır?","options":["Her seferinde yeni bir doğum belgesi","Tekrar Montana'da ikamet kanıtı","Geçerli bir DOT fiziksel (tıbbi muayene görevlisi) sertifikası","Bir Montana Karayolu Devriyesi izin formu"],"explanation":"Halihazırda standart bir Montana belgesine sahip başvuru sahipleri, Sosyal Güvenlik numarası kanıtı, yetkili bulunma kanıtı ve geçerli bir DOT fiziksel (tıbbi muayene görevlisi) sertifikası sunmalıdır; kimlik/ikamet kanıtı zaten dosyadaydı. Kaynak: MDT 'CDL'ye Giden On Kolay Adım', Gerekli Belgeler."},"98":{"q":"Eyalet içi (yalnızca Montana) ticari sürüş için bir Montana CDL'si almak için minimum yaş, eyaletler arası sürüşe kıyasla nedir?","options":["Eyalet içi için 21 ve eyaletler arası için 25","Hem eyalet içi hem eyaletler arası için 18","Eyalet içi için 16 ve eyaletler arası için 18","Eyalet içi için 18 ve eyaletler arası için 21"],"explanation":"Montana, bir başvuru sahibinin eyalet içinde (Montana içinde) ticari araç kullanmak için en az 18 ve eyaletler arası araç kullanmak için en az 21 yaşında olmasını gerektirir. Kaynak: Montana CDL Kılavuzu; Montana MVD CDL gereksinimleri."}},"es":{"0":{"q":"En las carreteras de Montana, ¿cuál es el ancho máximo legal de un vehículo comercial y su carga sin un permiso de sobredimensión?","options":["8 pies 0 pulgadas (96 pulgadas)","9 pies 0 pulgadas (108 pulgadas)","10 pies 0 pulgadas (120 pulgadas)","8 pies 6 pulgadas (102 pulgadas)"],"explanation":"Montana limita el ancho exterior total del vehículo a 102 pulgadas (8 pies 6 pulgadas), según MCA 61-10-102 y el Montana Commercial Vehicle Size and Weight and Safety Trucker's Handbook ('Legal Dimensions'). Las cargas más anchas que esto requieren un permiso."},"1":{"q":"¿Cuál es la altura máxima legal de un vehículo, vacío o con carga, en las carreteras de Montana?","options":["13 pies 6 pulgadas","14 pies","15 pies","15 pies 6 pulgadas"],"explanation":"Según MCA 61-10-103 y el Montana Trucker's Handbook, un vehículo (vacío o cargado) no puede exceder los 14 pies de altura. Alturas mayores requieren un permiso de sobredimensión."},"2":{"q":"Sin un permiso, ¿cuál es la longitud máxima de un semirremolque en una combinación de tractocamión-semirremolque en Montana?","options":["48 pies","57 pies","53 pies","60 pies"],"explanation":"MCA 61-10-104 y el Montana Trucker's Handbook establecen la longitud máxima del semirremolque en 53 pies (excluyendo las partes no diseñadas para transportar carga). Un permiso por plazo (term permit) puede extender esto a 57 pies según MCA 61-10-124."},"3":{"q":"En Montana, ¿cuál es el peso bruto máximo permitido en un eje simple sin un permiso de sobrepeso?","options":["20,000 libras","18,000 libras","22,400 libras","34,000 libras"],"explanation":"Según MCA 61-10-107 y el Montana Trucker's Handbook, el peso total sobre uno o más ejes cuyos centros no estén separados más de 40 pulgadas no puede exceder las 20,000 libras. Esto coincide con el límite federal de eje simple para autopistas interestatales."},"4":{"q":"¿Cuál es el peso bruto máximo permitido en un grupo de ejes en tándem en Montana sin un permiso de sobrepeso?","options":["32,000 libras","34,000 libras","36,000 libras","40,000 libras"],"explanation":"MCA 61-10-107 y el Montana Trucker's Handbook establecen que dos ejes consecutivos separados más de 40 pulgadas pero menos de 96 pulgadas no pueden cargar más de 34,000 libras."},"5":{"q":"¿Cómo define Montana un 'eje en tándem' a efectos de los límites de peso?","options":["Dos ejes separados exactamente 40 pulgadas","Dos ejes consecutivos separados más de 40 pulgadas y menos de 96 pulgadas","Cualquier par de ejes que estén a menos de 120 pulgadas entre sí","Dos ejes separados más de 96 pulgadas"],"explanation":"MCA 61-10-107 (citado en el Montana Trucker's Handbook) define un eje en tándem como dos ejes consecutivos separados más de 40 pulgadas pero menos de 96 pulgadas; dicho grupo está limitado a 34,000 libras."},"6":{"q":"¿Cuál es la fórmula de puente de Montana usada para calcular el peso bruto máximo permitido sobre un grupo de ejes?","options":["W = 1000((LN/(N+1)) + 10N + 20)","W = 250((LN/(N-1)) + 6N + 18)","W = 500((LN/(N+1)) + 12N + 12)","W = 500((LN/(N-1)) + 12N + 36)"],"explanation":"La fórmula de puente de Montana (que coincide con la Bridge Formula B federal) es W = 500((LN/(N-1)) + 12N + 36), donde L es la distancia en pies entre los ejes exteriores de un grupo y N es el número de ejes, según MCA 61-10-107 y el Montana Trucker's Handbook."},"7":{"q":"En Montana, ¿cuándo los límites de peso de eje simple y en tándem prevalecen (reemplazan) sobre el resultado de la fórmula de puente?","options":["Para todos los ejes separados más de 120 pulgadas","Solo en el Sistema Interestatal","Para todos los ejes separados no más de 96 pulgadas","Nunca; la fórmula de puente siempre rige"],"explanation":"El Montana Trucker's Handbook explica que los límites de peso de eje simple o en tándem reemplazan los límites de la fórmula de puente para todos los ejes separados no más de 96 pulgadas (MCA 61-10-107)."},"8":{"q":"¿Cuál es el peso bruto máximo que Montana permite para una combinación de vehículos que transporta cargas reducibles (divisibles)?","options":["80,000 libras","105,500 libras","131,060 libras","129,000 libras"],"explanation":"Según MCA 61-10-107 y la Montana Gross Vehicle Weight Chart del Trucker's Handbook, el peso bruto máximo para cargas reducibles es de 131,060 libras."},"9":{"q":"¿Cómo se limita el peso del eje direccional (delantero) según las reglas de Montana?","options":["A la capacidad nominal del fabricante del neumático, sin exceder las 20,000 libras","A exactamente 12,000 libras en todos los casos","A 34,000 libras como un tándem","No hay límite para el eje direccional"],"explanation":"El Montana Trucker's Handbook señala que los ejes direccionales están limitados a la capacidad nominal del fabricante estampada en el costado del neumático, sin exceder las 20,000 libras (MCA 61-10-107)."},"10":{"q":"Sin un permiso, ¿cuál es la longitud total máxima de las combinaciones de vehículos no especificadas de otra manera en las carreteras de Montana?","options":["65 pies","75 pies","80 pies","70 pies"],"explanation":"MCA 61-10-104 y el Montana Trucker's Handbook limitan dichas combinaciones a 75 pies en total (excepto las combinaciones a las que se permite mayor longitud, como los tractores que arrastran un remolque de 53 pies, que no tienen límite de longitud total)."},"11":{"q":"Un tractor que arrastra un solo remolque de 53 pies (o más corto) en Montana está sujeto a ¿qué regla de longitud?","options":["Aún debe mantenerse dentro de 65 pies en total","Siempre requiere un permiso de viaje único","No se requiere permiso de longitud total sin importar la longitud total","Está limitado a 70 pies en total"],"explanation":"El Montana Trucker's Handbook establece que no se requiere permiso de sobrelongitud para un tractor que arrastra un remolque de 53 pies (o más corto), sin importar la longitud total de la combinación (MCA 61-10-104)."},"12":{"q":"¿Qué sección de la agencia de Montana emite los permisos de sobredimensión y sobrepeso y las tarifas de peso bruto vehicular para los vehículos comerciales?","options":["La mesa de licencias de la Montana Highway Patrol","La Sección de Permisos de la División de Servicios de Transportistas Motorizados (Motor Carrier Services, MCS) del MDT","La oficina del sheriff del condado","La Administración Federal de Seguridad de Autotransportes (Federal Motor Carrier Safety Administration)"],"explanation":"Según el Montana Trucker's Handbook, la Sección de Permisos de la División de Servicios de Transportistas Motorizados (Motor Carrier Services, MCS) del Departamento de Transporte de Montana emite los permisos de tamaño/peso; los transportistas también pueden autoemitirlos en línea (ePART / eTRIPS)."},"13":{"q":"Una carga de sobredimensión que es solo de un viaje único y no está matriculada en Montana, ¿qué tipo de permiso requiere?","options":["Únicamente un permiso permanente por plazo (term permit)","Un permiso de cosechadora personalizada (custom combine)","Ningún permiso, ya que es un traslado por única vez","Un permiso de sobredimensión de viaje único, que queda nulo al salir del estado"],"explanation":"El Montana Trucker's Handbook dispone que los operadores que circulen de forma temporal por viaje deben obtener un permiso de sobredimensión de viaje único (para cargas de más de 8'6\" de ancho, 14' de alto, 75' de largo, o una unidad simple de más de 55'); el permiso queda nulo al salir del estado."},"14":{"q":"¿Qué seguro de responsabilidad civil mínimo requiere Montana para la emisión de un permiso (especial) de sobredimensión/sobrepeso?","options":["$300,000 de límite único combinado","$500,000 de límite único combinado","$1,000,000 de límite único combinado por suceso","$750,000 de límite único combinado"],"explanation":"Los Requisitos Generales del Permiso de Sobredimensión del Montana Trucker's Handbook especifican un mínimo de $1,000,000 de límite único combinado de responsabilidad por lesiones corporales y daños a la propiedad por suceso."},"15":{"q":"El Permiso por Plazo de Peso de Invierno (Winter Weight Term Permit) de Montana permite ¿cuánto exceso de peso, y en cuáles carreteras?","options":["10% de exceso en carreteras no interestatales, del 1 de diciembre al 7 de marzo","20% de exceso en todas las carreteras, todo el año","10% de exceso únicamente en carreteras interestatales","15% de exceso en carreteras no interestatales, del 1 de noviembre al 1 de abril"],"explanation":"El Montana Trucker's Handbook establece que el Permiso por Plazo de Peso de Invierno permite un 10% de exceso de peso en carreteras no interestatales del 1 de diciembre al 7 de marzo, y puede suspenderse durante los deshielos tempranos."},"16":{"q":"Una operación de cosechadora personalizada (custom combine) no residente en Montana puede pagar una tarifa de permiso especial en lugar de las tarifas de GVW y los permisos de sobredimensión de ¿cuánto por unidad?","options":["$20 por unidad","$35 por unidad","$105 por unidad","$40 por unidad"],"explanation":"Según MCA 15-24-301 y 61-10-130 (y ARM 18.8.426), el Montana Trucker's Handbook dispone que una operación de cosechadora personalizada no residente puede pagar una tarifa de permiso especial de $40 por unidad (los residentes pagan el 35% de las tarifas de GVW más $20 por unidad)."},"17":{"q":"En el Sistema Interestatal de Montana, ¿cuál es el límite federal de peso de eje simple que también se aplica en Montana?","options":["20,000 libras","18,000 libras","21,000 libras","24,000 libras"],"explanation":"El Montana Trucker's Handbook señala expresamente que el límite federal de peso de eje simple en el Sistema Interestatal es de 20,000 libras, consistente con el límite general de eje simple de Montana según MCA 61-10-107."},"18":{"q":"Para el transporte de heno o paja incidental a la actividad agrícola, Montana permite una altura del vehículo de hasta ¿qué máximo, y dentro de qué distancia?","options":["15 pies 6 pulgadas, por no más de 25 millas","16 pies, por no más de 50 millas","14 pies 6 pulgadas, por no más de 10 millas","15 pies, por no más de 100 millas"],"explanation":"MCA 61-10-103 establece una excepción agrícola: un implemento agrícola o un vehículo que transporta heno o paja puede alcanzar 15 pies 6 pulgadas si viaja no más de 25 millas de forma incidental a la actividad agrícola y no pasa por debajo de obstáculos de 17 pies o menos."},"19":{"q":"A una carga no divisible que excede el límite de la fórmula de puente pero NO excede los pesos legales por eje, se le cobra una tarifa de permiso de Montana con base en ¿qué?","options":["Una tarifa anual fija de $200 sin importar la distancia","Únicamente el peso bruto registrado del vehículo","El 10% del valor de la carga","El kilometraje del viaje (p. ej., $10 hasta 100 millas, $30 para 101-199, $50 para 200+ millas)"],"explanation":"El Montana Trucker's Handbook ('Overweight On Bridge - Legal Axle Weights - Non-Divisible Loads,' MCA 61-10-107) cobra $10 hasta 100 millas, $30 para 101-199 millas, y $50 para 200 millas y más."},"20":{"q":"En Montana, ¿qué clase de CDL se requiere para operar una combinación de vehículos con una calificación de peso bruto combinado (GCWR) de 26,001 libras o más, cuando la(s) unidad(es) remolcada(s) exceden las 10,000 libras?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"Según el Montana CDL Manual (Classifications, MT-2), un vehículo de combinación de Clase A tiene un GCWR de 11,794 kg (26,001 lbs) o más siempre que la(s) unidad(es) remolcada(s) excedan los 4,536 kg (10,000 lbs). Fuente: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"21":{"q":"Un solo 'vehículo recto muy pesado' (heavy heavy straight vehicle) en Montana con un GVWR de 26,001 libras o más que no remolca nada de más de 10,000 libras, ¿qué clase de CDL requiere?","options":["Clase A","Clase B","Clase C","Clase M"],"explanation":"El Montana CDL Manual (Classifications, MT-2) define la Clase B como cualquier vehículo simple con un GVWR de 26,001 lbs o más, o dicho vehículo remolcando una unidad de no más de 10,000 lbs. Fuente: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"22":{"q":"En Montana, un vehículo que no cumple las definiciones de peso de Clase A o B pero está diseñado para transportar 16 o más pasajeros (incluido el conductor) o se usa para transportar materiales peligrosos con cartel (placarded), ¿qué clase de CDL requiere?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"El Montana CDL Manual (Classifications, MT-2) define la Clase C como un vehículo simple o combinación que no cumple ni la Clase A ni la B pero está diseñado para transportar 16+ pasajeros incluido el conductor, o se usa para transportar materiales peligrosos que requieren cartel (placardable). Fuente: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"23":{"q":"Según las reglas de CDL de Montana, ¿cuál es el número mínimo de pasajeros (incluido el conductor) que un vehículo debe estar diseñado para transportar antes de que se requiera un endoso de Pasajeros (P)?","options":["8 pasajeros","10 pasajeros","15 pasajeros","16 pasajeros"],"explanation":"El Montana CDL Manual (MT-3) establece que se requiere un endoso de Vehículo de Pasajeros (P) para vehículos de Clase A, B o C diseñados para transportar 16 o más pasajeros incluido el conductor. Fuente: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"24":{"q":"¿Qué endoso de CDL de Montana se requiere para operar un vehículo comercial que arrastra remolques dobles o triples?","options":["Endoso N","Endoso T","Endoso X","Endoso H"],"explanation":"El Montana CDL Manual (MT-2/MT-3) establece que se requiere el endoso de Remolques Dobles/Triples (T) para los conductores que arrastran remolques dobles o triples en Clase A o B. Fuente: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"25":{"q":"Según el Montana CDL Manual, el endoso de Cisterna (N) se requiere al transportar materiales líquidos o gaseosos en un tanque que tenga una capacidad nominal de al menos ¿cuánto?","options":["119 galones","500 galones","1,000 galones","3,500 galones"],"explanation":"El Montana CDL Manual (MT-3) define el endoso de Vehículo Cisterna (N) como requerido para un tanque con una capacidad nominal de 1,000 galones o más, o varios tanques con una capacidad nominal conjunta de 1,000 galones. Fuente: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"26":{"q":"¿Cuál es la edad mínima para solicitar una Licencia de Conducir Comercial INTRAESTATAL (solo dentro de Montana)?","options":["16 años","18 años","19 años","21 años"],"explanation":"El Montana CDL Manual (Minimum Driver Ages, MT-3) establece que un solicitante intraestatal (solo Montana) debe cumplir los requisitos de Montana y tener al menos 18 años. Fuente: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"27":{"q":"¿Cuál es la edad mínima para solicitar una Licencia de Conducir Comercial INTERESTATAL en Montana?","options":["18 años","19 años","21 años","25 años"],"explanation":"El Montana CDL Manual (Minimum Driver Ages, MT-3) establece que para solicitar una licencia interestatal debes tener al menos 21 años y ser capaz de cumplir los requisitos para una CDL. Fuente: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"28":{"q":"Antes de presentar el examen de habilidades de la CDL (inspección previa al viaje, control básico y manejo en carretera) en Montana, se debe tener un Permiso de Aprendiz Comercial (CLP) durante un mínimo de ¿cuánto tiempo?","options":["7 días","10 días","14 días","30 días"],"explanation":"El Montana CDL Manual (CLP definition, MT-2) establece que todos los permisos CLP deben tenerse durante un mínimo de 14 días antes de presentar el examen de inspección previa al viaje, habilidades básicas y manejo en carretera (el conductor puede examinarse el día 15). Esto refleja la regla federal del CLP. Fuente: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); 49 CFR 383.25."},"29":{"q":"Antes de que pueda emitirse, renovarse o transferirse una CDL de Montana con un endoso de Materiales Peligrosos (H), la ley federal exige que el conductor apruebe ¿cuál evaluación?","options":["Únicamente una prueba de drogas y alcohol del DOT","Una Evaluación de Amenazas a la Seguridad de la TSA (verificación de antecedentes basada en huellas dactilares)","Un examen de polígrafo del FBI","Una evaluación estatal de visión y reflejos"],"explanation":"El Montana CDL Manual (Hazardous Materials, MT-2) establece que, en cumplimiento de la ley federal, los conductores que deseen obtener, transferir o renovar un endoso de HazMat deben primero completar una Evaluación de Amenazas a la Seguridad (STA) realizada por la TSA, que incluye la toma de huellas dactilares y una verificación de antecedentes penales. Fuente: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); 49 CFR 1572."},"30":{"q":"Un conductor de Montana que completó una Evaluación de Amenazas a la Seguridad de la TSA para un endoso de HazMat generalmente NO está obligado a completar otra STA al renovar o transferir si la evaluación previa ocurrió dentro de los últimos ¿cuántos años?","options":["1 año","2 años","5 años","7 años"],"explanation":"El Montana CDL Manual (MT-2) establece que quienes hayan tenido previamente una evaluación de amenazas a la seguridad dentro de los dos años previos a solicitar la renovación o transferencia de su CDL pueden no estar obligados a completar otra STA. Fuente: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"31":{"q":"Según las reglas federales de Capacitación para Conductores de Nivel Inicial (ELDT) adoptadas en Montana, un solicitante por primera vez debe completar la ELDT con un proveedor inscrito ¿dónde antes de examinarse?","options":["La lista de contratistas del Montana DOT","El Registro de Proveedores de Capacitación de la FMCSA (Training Provider Registry, TPR)","El directorio de escuelas de manejo de la AAMVA","Cualquier escuela vocacional aprobada por el estado"],"explanation":"La ELDT requiere capacitación de un proveedor inscrito en el Registro de Proveedores de Capacitación de la FMCSA (Training Provider Registry, TPR). Montana hace referencia a este requisito en su CDL Manual (MT-2). Fuente: regla ELDT de la FMCSA (49 CFR 380, vigente desde Feb 7, 2022); Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"32":{"q":"Los requisitos federales de ELDT se aplican a los solicitantes por primera vez de una CDL de Clase A o B y a los solicitantes por primera vez de ¿cuál conjunto de endosos?","options":["N (Cisterna) y T (Dobles/Triples)","P (Pasajeros), S (Autobús Escolar) y H (HazMat)","Solo T (Dobles/Triples) y S (Autobús Escolar)","Únicamente H (HazMat)"],"explanation":"Según la regla ELDT de la FMCSA (vigente desde Feb 7, 2022), se requiere capacitación para las CDL de Clase A/B por primera vez y para los endosos de Pasajeros (P), Autobús Escolar (S) y Materiales Peligrosos (H) por primera vez. Montana adoptó estos requisitos (CDL Manual, MT-2/MT-3). Fuente: 49 CFR 380; Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"33":{"q":"¿Cuál de las siguientes es una de las cuatro categorías de autocertificación que un solicitante de CDL de Montana debe elegir para indicar el tipo de comercio en el que opera?","options":["Interestatal no exceptuado (Interstate non-excepted)","Transportista por contrato federal","Interestatal recreativo","Exención comercial limitada"],"explanation":"El Montana CDL Manual (Self-Certification, MT-3) enumera las cuatro categorías como Interestatal no exceptuado, Interestatal exceptuado, Intraestatal no exceptuado e Intraestatal exceptuado. Fuente: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); 49 CFR 383.71."},"34":{"q":"Un solicitante de CDL de Montana que se autocertifica como 'Interestatal no exceptuado' está haciendo ¿cuál declaración sobre los requisitos médicos?","options":["Está exento de tener un certificado de examinador médico","Debe cumplir los requisitos médicos federales (MEC)","Solo necesita una exención médica intraestatal de Montana","No necesita ninguna certificación médica en absoluto"],"explanation":"El Montana CDL Manual (Self-Certification, MT-3) establece que un conductor Interestatal no exceptuado debe cumplir los requisitos del Certificado de Examinador Médico (MEC) federal. Fuente: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); 49 CFR 383.71."},"35":{"q":"Todos los solicitantes de una licencia de conducir comercial de Montana deben presentar documentos de ¿cuántas categorías distintas de comprobación?","options":["Dos: identidad y residencia","Tres: presencia autorizada, identidad y residencia en Montana","Cuatro: identidad, residencia, tarjeta del SSN y ciudadanía","Una: un solo documento que cumpla con REAL ID"],"explanation":"El Montana CDL Manual (Proof of Authorized Presence, Identity, and Residence, MT-7/MT-8) exige documentos de tres categorías: comprobante de presencia autorizada, comprobante de identidad y comprobante de residencia en Montana. Fuente: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"36":{"q":"Con respecto al número de Seguro Social en una solicitud de CDL de Montana, ¿qué exige el estado?","options":["El SSN debe coincidir con el número registrado en la Administración del Seguro Social","Nunca se necesita un SSN para una CDL","Solo se registran los últimos cuatro dígitos y nunca se verifican","Una declaración jurada notariada reemplaza al SSN"],"explanation":"El Montana CDL Manual (Proof of Social Security Number and Identity Confirmation, MT-2) establece que el nombre, la fecha de nacimiento y el SSN usados en la solicitud de CDL deben coincidir con lo registrado en la Administración del Seguro Social, y el SSN se verifica con la SSA. Fuente: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); FMCSR 383.153."},"37":{"q":"Si un conductor comercial de Montana sigue conduciendo después de ser puesto fuera de servicio (out-of-service), la primera infracción de este tipo resulta en una suspensión de la CDL de ¿cuánto tiempo?","options":["30 días","90 días","6 meses","3 años"],"explanation":"El Montana CDL Manual (Driver Disqualifications, MT-5) establece que si conduces después de ser puesto fuera de servicio, tu CDL será suspendida por seis meses para una primera infracción (y por más tiempo en infracciones posteriores). Fuente: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); 49 CFR 383.51."},"38":{"q":"La CDL Estacional Restringida de Montana para empleados calificados de servicios relacionados con la agricultura es válida durante ¿qué ventana estacional de cada año calendario?","options":["Del 1 de enero al 30 de junio","Del 15 de marzo al 10 de septiembre","Del 1 de abril al 1 de octubre","Del 1 de mayo al 30 de noviembre"],"explanation":"El Montana CDL Manual (Restricted Seasonal CDL, MT-5) establece que una CDL Estacional es válida únicamente para el periodo del 15 de marzo al 10 de septiembre de un año calendario y permite operar dentro de un radio de 150 millas del lugar de trabajo o de la granja. Fuente: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)."},"39":{"q":"En Montana, ¿cuál es la concentración de alcohol en la sangre (BAC) en o por encima de la cual se considera que una persona opera ilegalmente un vehículo motorizado comercial (CMV)?","options":["0.08","0.04","0.02","0.10"],"explanation":"Montana sigue el estándar federal para CMV: operar un CMV con una concentración de alcohol de 0.04 o más es una infracción grave (major offense). Fuente: MCA 61-8-802 y el Montana CDL Manual (Section 1, Disqualifications); 49 CFR 383.51."},"40":{"q":"Según la ley de consentimiento implícito de Montana, al operar cualquier vehículo en el estado se considera que un conductor ya ha consentido a ¿cuál de las siguientes opciones?","options":["Una prueba de sangre, aliento u orina para detectar alcohol o drogas","Un registro del vehículo sin una orden judicial","Un examen médico anual","Una evaluación de la vista en cada parada de tránsito"],"explanation":"La ley de consentimiento implícito de Montana dispone que cualquier persona que opere un vehículo en el estado ha dado su consentimiento a una prueba de sangre, aliento u orina para determinar la concentración de alcohol o la presencia de drogas. Fuente: estatuto de consentimiento implícito de Montana (MCA 61-8-1016, anteriormente 61-8-402) y el Montana CDL Manual."},"41":{"q":"Un titular de CDL de Montana comete una primera infracción grave (como un DUI) mientras NO transporta materiales peligrosos. ¿Por cuánto tiempo queda descalificada la CDL?","options":["6 meses","1 año","3 años","60 días"],"explanation":"Una primera infracción grave resulta en una descalificación de la CDL de 1 año. Fuente: MCA 61-8-802(1) y el Montana CDL Manual; 49 CFR 383.51."},"42":{"q":"Si la primera infracción grave de un titular de CDL de Montana ocurre mientras opera un CMV que transporta materiales peligrosos con cartel (placardable), el periodo de descalificación se incrementa a:","options":["1 año","2 años","3 años","De por vida"],"explanation":"Cuando una primera infracción grave ocurre mientras se opera un CMV que transporta materiales peligrosos con cartel (placardable), la descalificación es de 3 años en lugar de 1 año. Fuente: MCA 61-8-802(1) y el Montana CDL Manual; 49 CFR 383.51."},"43":{"q":"¿Cuál es el periodo de descalificación en Montana para un conductor condenado por una SEGUNDA infracción grave (de un incidente separado) durante su vida?","options":["3 años","5 años","10 años","De por vida"],"explanation":"Una segunda infracción grave resulta en una descalificación de por vida, aunque Montana puede permitir la rehabilitación según las reglas federales después de un periodo mínimo de 10 años. Fuente: MCA 61-8-802 y el Montana CDL Manual; 49 CFR 383.51."},"44":{"q":"A un conductor de CMV de Montana se le solicita legalmente que se someta a una prueba de aliento para detectar alcohol y se niega. ¿Cómo se trata esta negativa a efectos de la CDL?","options":["Como una infracción de tránsito grave (serious) con sanción de 60 días","Como una infracción grave (major offense), con la misma descalificación que una prueba reprobada","Como un asunto administrativo no reportable","Como una violación de una orden de fuera de servicio (out-of-service)"],"explanation":"Negarse a una prueba obligatoria de alcohol/drogas bajo consentimiento implícito es una infracción grave (major offense) y conlleva la misma descalificación que dar positivo en 0.04 o más: 1 año (3 años para hazmat) para una primera negativa, de por vida para una segunda. Fuente: MCA 61-8-802 y el Montana CDL Manual; 49 CFR 383.51."},"45":{"q":"Un conductor de CMV de Montana que tiene cualquier cantidad detectable de alcohol por debajo de 0.04 no queda descalificado, pero debe ser puesto fuera de servicio (out of service) durante ¿cuánto tiempo?","options":["1 hora","8 horas","24 horas","72 horas"],"explanation":"Un conductor de CMV con una concentración de alcohol detectable inferior a 0.04 debe ser puesto fuera de servicio durante 24 horas. Fuente: Montana CDL Manual; 49 CFR 392.5 / 383.51."},"46":{"q":"¿Cuál de las siguientes se clasifica como una infracción de tránsito GRAVE (serious) para un titular de CDL de Montana?","options":["Conducir 15 mph o más por encima del límite de velocidad señalizado","Un primer DUI en un CMV","Negarse a una prueba de alcohol","Conducir mientras la licencia está suspendida por un DUI"],"explanation":"El exceso de velocidad (15 mph o más por encima del límite) es una infracción de tránsito grave (serious). El DUI y la negativa a la prueba son infracciones graves (major offenses), no infracciones serious. Fuente: Montana CDL Manual (Disqualifications); 49 CFR 383.51."},"47":{"q":"¿Cuántas infracciones de tránsito graves (serious) dentro de un periodo de 3 años activan una descalificación de 60 días de una CDL de Montana?","options":["Una","Dos","Tres","Cuatro"],"explanation":"Una segunda infracción de tránsito grave (serious) dentro de un periodo de 3 años resulta en una descalificación de 60 días. Fuente: Montana CDL Manual; 49 CFR 383.51."},"48":{"q":"Un titular de CDL de Montana es condenado por TRES infracciones de tránsito graves (serious) dentro de un periodo de 3 años. ¿Cuál es la descalificación mínima?","options":["60 días","90 días","120 días","180 días"],"explanation":"Tres infracciones de tránsito graves (serious) en un periodo de 3 años resultan en una descalificación de 120 días. Fuente: Montana CDL Manual; 49 CFR 383.51."},"49":{"q":"¿Cuál de estas NO se cuenta como una infracción de tránsito grave (serious) para un titular de CDL de Montana?","options":["Seguir demasiado de cerca","Cambios de carril indebidos o erráticos","Conducción imprudente","Conducir 5 mph por encima del límite de velocidad"],"explanation":"Las infracciones graves (serious) incluyen la conducción imprudente, los cambios de carril indebidos/erráticos, seguir demasiado de cerca y exceder la velocidad en 15+ mph por encima del límite. El exceso de velocidad menor (p. ej., 5 mph por encima) no es una infracción grave. Fuente: Montana CDL Manual; 49 CFR 383.51."},"50":{"q":"Usar un teléfono móvil de mano mientras se conduce un CMV se clasifica, a efectos de la CDL de Montana, como ¿qué tipo de infracción?","options":["Una infracción grave (major offense)","Una infracción de tránsito grave (serious)","Una violación de fuera de servicio (out-of-service)","Una violación de cruce ferroviario"],"explanation":"Usar un teléfono móvil de mano mientras se conduce un CMV es una infracción de tránsito grave (serious) según la regla federal aplicada en Montana. Fuente: Montana CDL Manual; 49 CFR 392.82 y 383.51."},"51":{"q":"Enviar mensajes de texto mientras se conduce un CMV está prohibido para los conductores con CDL de Montana. Una segunda condena por enviar mensajes de texto/usar el teléfono de mano dentro de 3 años resulta en ¿qué descalificación?","options":["Ninguna descalificación","60 días","120 días","1 año"],"explanation":"Enviar mensajes de texto/usar el teléfono de mano es una infracción grave (serious). Una primera condena no conlleva descalificación, pero una segunda dentro de 3 años resulta en una descalificación de 60 días (120 días para una tercera). Fuente: Montana CDL Manual; 49 CFR 392.80/392.82 y 383.51."},"52":{"q":"¿Cuál es la descalificación mínima para la PRIMERA violación de cruce a nivel entre ferrocarril y carretera de un titular de CDL de Montana cometida mientras conducía un CMV?","options":["30 días","60 días","120 días","1 año"],"explanation":"Una primera violación de cruce a nivel entre ferrocarril y carretera resulta en una descalificación mínima de 60 días. Fuente: Montana CDL Manual; 49 CFR 383.51."},"53":{"q":"Para una SEGUNDA violación de cruce ferroviario a nivel dentro de un periodo de 3 años, una CDL de Montana queda descalificada por al menos:","options":["60 días","120 días","180 días","1 año"],"explanation":"Una segunda violación de cruce ferroviario a nivel en un periodo de 3 años resulta en una descalificación mínima de 120 días. Fuente: Montana CDL Manual; 49 CFR 383.51."},"54":{"q":"Una TERCERA violación de cruce ferroviario a nivel dentro de un periodo de 3 años descalifica una CDL de Montana por al menos:","options":["120 días","180 días","1 año","3 años"],"explanation":"Una tercera violación de cruce ferroviario a nivel en un periodo de 3 años resulta en una descalificación mínima de 1 año. Fuente: Montana CDL Manual; 49 CFR 383.51."},"55":{"q":"Un conductor de CMV de Montana viola una orden de fuera de servicio (out-of-service) por PRIMERA vez (sin transportar hazmat ni pasajeros). ¿Cuál es la descalificación mínima?","options":["30 días","90 días","180 días","1 año"],"explanation":"Una primera condena por violar una orden de fuera de servicio resulta en una descalificación de al menos 180 días. Fuente: Montana CDL Manual; 49 CFR 383.51."},"56":{"q":"¿Cuál es la descalificación mínima para una SEGUNDA violación de una orden de fuera de servicio (incidentes separados) dentro de un periodo de 10 años para un titular de CDL de Montana?","options":["180 días","1 año","2 años","3 años"],"explanation":"Una segunda violación de una orden de fuera de servicio en incidentes separados dentro de 10 años resulta en una descalificación mínima de 2 años (3 años para una tercera). Fuente: Montana CDL Manual; 49 CFR 383.51."},"57":{"q":"Si un conductor de CMV de Montana viola una orden de fuera de servicio por primera vez mientras transporta materiales peligrosos con cartel (placardable) O mientras opera un vehículo diseñado para transportar 16 o más pasajeros, la descalificación mínima es:","options":["60 días","180 días","1 año","2 años"],"explanation":"Una primera violación de una orden de fuera de servicio mientras se transporta hazmat con cartel o se llevan 16+ pasajeros (incluido el conductor) resulta en una descalificación mínima de 180 días, con al menos 3 años para una violación posterior. Fuente: Montana CDL Manual; 49 CFR 383.51."},"58":{"q":"Un titular de CDL de Montana recibe un DUI en su vehículo PERSONAL (no comercial). ¿Cómo afecta esto a su CDL?","options":["No tiene ningún efecto porque no fue en un CMV","Se trata como una infracción grave (major offense) y descalifica la CDL","Solo agrega puntos pero sin descalificación","Resulta únicamente en una orden de fuera de servicio de 24 horas"],"explanation":"Las infracciones graves (major offenses) como el DUI descalifican la CDL incluso cuando se cometen en un vehículo personal; una primera infracción es una descalificación de 1 año. Fuente: MCA 61-8-802 y el Montana CDL Manual; 49 CFR 383.51."},"59":{"q":"En una autopista interestatal de Montana con ayuda federal, fuera de un área urbanizada, un camión semirremolque cargado (camión de más de 1 tonelada de capacidad nominal) puede circular legalmente hasta qué velocidad máxima?","options":["65 mph en todo momento","80 mph, igual que los autos","70 mph en todo momento","75 mph de día, 65 mph de noche"],"explanation":"Montana establece un límite de velocidad aparte para los camiones: un camión o camión tractor de más de 1 tonelada de capacidad nominal tiene un tope de 70 mph en la interestatal, aunque los autos puedan circular a 80 mph en las interestatales rurales. Fuente: MCA 61-8-312 (limitaciones especiales de velocidad para camiones) y 61-8-303; elevado por la HB393 (2019)."},"60":{"q":"En una carretera pública de dos carriles de Montana que NO es interestatal, la velocidad máxima para un camión de más de 1 tonelada de capacidad nominal es:","options":["70 mph de día, 65 mph de noche","60 mph de día, 55 mph de noche","65 mph, de día y de noche","55 mph en todo momento"],"explanation":"En las carreteras que no son interestatales, el límite para camiones es de 65 mph fijos, tanto de día como de noche. Las cifras anteriores divididas de 60 de día y 55 de noche fueron derogadas en 2019. Fuente: MCA 61-8-312; HB393 (2019)."},"61":{"q":"Según la norma de Montana sobre cruces ferroviarios para autobuses y vehículos con materiales peligrosos que llevan rótulos y deben detenerse, cuando no hay una línea de alto pintada, el conductor debe detenerse dentro de qué distancia del riel más cercano?","options":["No más cerca de 15 feet ni más lejos de 50 feet","No más cerca de 10 feet ni más lejos de 40 feet","No más cerca de 25 feet ni más lejos de 75 feet","No más cerca de 5 feet ni más lejos de 30 feet"],"explanation":"Montana sigue la regla de 15 a 50 feet: los vehículos que deben detenerse tienen que parar no más cerca de 15 feet ni a más de 50 feet del riel más cercano de la vía más próxima. Fuente: Manual CDL de Montana, Sección 2.15 (Cruces ferroviarios)."},"62":{"q":"Cuáles vehículos comerciales SIEMPRE deben hacer una parada completa en un cruce a nivel de ferrocarril y carretera de Montana (en ausencia de una señal verde o de la indicación de un policía)?","options":["Todos los vehículos combinados de más de 26,001 pounds","Solo las combinaciones de triple remolque","Cualquier camión registrado fuera del estado","Autobuses que transportan pasajeros y vehículos que deben llevar rótulos por materiales peligrosos"],"explanation":"El manual de Montana indica que todos los vehículos que transportan pasajeros (autobuses) y los vehículos con rótulos de materiales peligrosos deben detenerse en el cruce; los camiones cargados comunes no están obligados a hacerlo, a menos que la carga o la ley lo exijan. Fuente: Manual CDL de Montana, Secciones 2.15.2 y 2.15.4."},"63":{"q":"Según la ley de autobuses escolares de Montana, cuando un autobús escolar está detenido en la calzada con sus luces rojas intermitentes encendidas, un conductor que se aproxima debe detenerse a no menos de aproximadamente qué distancia del autobús?","options":["20 feet","50 feet","30 feet","10 feet"],"explanation":"Montana exige que los conductores que se aproximan desde cualquier dirección se detengan a no menos de aproximadamente 30 feet de un autobús escolar que muestra luces rojas intermitentes, y que permanezcan detenidos hasta que las luces rojas se apaguen. Fuente: MCA 61-8-351 (encuentro o adelantamiento de un autobús escolar)."},"64":{"q":"En una carretera de Montana con calzadas separadas (por ejemplo, una autopista dividida con la dirección opuesta en una calzada físicamente separada), un conductor que se encuentra con un autobús escolar detenido en la OTRA calzada debe:","options":["Detenerse, porque todo el tránsito que se aproxima siempre debe detenerse","Detenerse solo si la mediana es más angosta que 30 feet","No detenerse: los vehículos en una calzada distinta no necesitan detenerse","Reducir a 10 mph pero no necesita hacer una parada completa"],"explanation":"Excepción de Montana: un conductor en una carretera con calzadas separadas no necesita detenerse al encontrarse con un autobús escolar o adelantarlo cuando este se encuentra en una calzada distinta. La excepción depende de que existan 'calzadas separadas', no simplemente de una línea central pintada. Fuente: MCA 61-8-351."},"65":{"q":"Cuando un autobús escolar de Montana ha activado únicamente sus luces AMARILLAS (ámbar) INTERMITENTES, un conductor que se aproxima debe:","options":["Reducir a una velocidad razonable y estar preparado para detenerse","Hacer una parada completa de inmediato a por lo menos 30 feet de distancia","Mantener la velocidad porque las luces ámbar no implican ninguna obligación","Detenerse solo si hay niños visibles al borde de la carretera"],"explanation":"El ámbar intermitente significa que el autobús se está preparando para detenerse; la ley de Montana exige que los conductores reduzcan a una velocidad razonable y estén preparados para detenerse. La obligación de detenerse surge cuando se activan las luces rojas. Fuente: MCA 61-8-351."},"66":{"q":"Según la ley 'Move Over' de Montana, al aproximarse a un vehículo de emergencia o de trabajadores de carretera detenido en una INTERESTATAL y cuando SÍ es posible cambiar de carril, el conductor debe reducir la velocidad a por lo menos cuánto por debajo del límite señalizado?","options":["10 mph por debajo del límite señalizado","30 mph por debajo del límite señalizado","20 mph por debajo del límite señalizado","5 mph por debajo del límite señalizado"],"explanation":"La MCA 61-8-388 exige reducir la velocidad a 20 mph por debajo del límite señalizado en una interestatal cuando es posible cambiar de carril (y moverse a un carril no adyacente). Si el cambio de carril es inseguro, el conductor debe reducir a la mitad del límite señalizado. Fuente: MCA 61-8-388."},"67":{"q":"Según la ley 'Move Over' de Montana, en una CARRETERA ESTATAL o CAMINO DE CONDADO donde es posible cambiar de carril, la reducción de velocidad requerida al pasar junto a un vehículo de emergencia detenido es de por lo menos:","options":["20 mph por debajo del límite señalizado","15 mph por debajo del límite señalizado","10 mph por debajo del límite señalizado","30 mph por debajo del límite señalizado"],"explanation":"En una carretera estatal o camino de condado, la MCA 61-8-388 exige reducir a 30 mph por debajo del límite señalizado cuando es posible cambiar de carril; si el cambio de carril es inseguro, reducir a la mitad del límite señalizado. Fuente: MCA 61-8-388."},"68":{"q":"Según la ley 'Move Over' de Montana, si el conductor NO PUEDE cambiar de carril de forma segura al aproximarse a un vehículo de emergencia detenido, a qué velocidad debe reducir?","options":["A la mitad del límite de velocidad señalizado","A 20 mph sin importar el límite señalizado","A una parada completa hasta que se despeje el lugar","A 10 mph por debajo del límite señalizado"],"explanation":"Cuando no se puede cambiar de carril de forma segura, la MCA 61-8-388 exige reducir a la mitad del límite de velocidad señalizado mientras se avanza con precaución. Fuente: MCA 61-8-388."},"69":{"q":"En una carretera de Montana con varios carriles, el requisito principal de la ley 'Move Over' al aproximarse a un vehículo de emergencia detenido (cuando no hay un límite temporal señalizado) es:","options":["Detenerse por completo en el carril derecho","Cambiarse a un carril que no sea adyacente al vehículo detenido, si se puede hacer de forma segura","Tocar la bocina continuamente al pasar","Conducir sobre el acotamiento para dar el máximo espacio"],"explanation":"La MCA 61-8-388 indica a los conductores en una carretera de varios carriles que desocupen el carril adyacente al vehículo de emergencia o de trabajadores de carretera detenido cuando sea seguro; si eso no es posible, reducir la velocidad según lo requerido y pasar con precaución. Fuente: MCA 61-8-388."},"70":{"q":"Si un conductor con CDL de Montana debe detenerse en el acotamiento de una carretera, dentro de cuántos minutos debe colocar los dispositivos de advertencia?","options":["Dentro de 5 minutos","Dentro de 10 minutos","Dentro de 15 minutos","Dentro de 30 minutos"],"explanation":"Un camión o autobús detenido debe colocar los dispositivos de advertencia de emergencia dentro de los 10 minutos de haberse detenido en una carretera o acotamiento. Fuente: Manual CDL de Montana, Sección 2.5 (Comunicación / dispositivos de advertencia)."},"71":{"q":"Cuando un conductor con CDL de Montana se detiene en una carretera de UN SOLO SENTIDO o DIVIDIDA, dónde se colocan los tres dispositivos de advertencia?","options":["A 10 ft, 50 ft y 150 ft en dirección al tránsito que se aproxima","A 10 ft, 100 ft y 200 ft en dirección al tránsito que se aproxima","A 10 ft, 100 ft adelante y 100 ft detrás del vehículo","A 15 ft, 50 ft y 100 ft en dirección al tránsito que se aproxima"],"explanation":"En una carretera de un solo sentido o dividida, coloque los dispositivos de advertencia a 10 feet, 100 feet y 200 feet en dirección al tránsito que se aproxima. Fuente: Manual CDL de Montana, Sección 2.5 (colocación de dispositivos de advertencia)."},"72":{"q":"En una carretera de Montana de doble sentido sin dividir que lleva tránsito en ambas direcciones, los tres triángulos reflectantes para un CMV detenido se colocan en:","options":["Dentro de 10 ft del vehículo, y a 100 ft adelante y 100 ft atrás","A 10 ft, 100 ft y 200 ft, todos detrás del vehículo","A 50 ft, 100 ft y 200 ft únicamente en dirección al tránsito que viene de frente","Dentro de 10 ft, y a 200 ft adelante y 200 ft atrás"],"explanation":"En una carretera de dos carriles de doble sentido o sin dividir, coloque un dispositivo dentro de 10 feet del vehículo, uno a 100 feet adelante y uno a 100 feet atrás, en el carril o acotamiento donde se detuvo. Fuente: Manual CDL de Montana, Sección 2.5."},"73":{"q":"Cuántos triángulos reflectantes rojos debe llevar un vehículo con CDL de Montana como dispositivos de advertencia de emergencia obligatorios?","options":["Dos","Tres","Cuatro","Seis"],"explanation":"El equipo de advertencia obligatorio son tres triángulos reflectantes rojos (o alternativas como 6 bengalas tipo fusee o 3 bengalas de combustible líquido). Fuente: Manual CDL de Montana, Sección 2.1 (inspección del vehículo) y Sección 2.5."},"74":{"q":"En una carretera de Montana donde una colina o curva bloquea la visibilidad de un CMV detenido dentro de 500 feet, el conductor debe:","options":["Colocar los tres triángulos dentro de 10 feet del parachoques","Mover el triángulo más alejado hacia atrás por la carretera, más allá del obstáculo, para que el tránsito reciba advertencia","Dejar los triángulos en sus posiciones estándar y confiar en las luces intermitentes","Colocar un triángulo exactamente a 500 feet por delante del obstáculo"],"explanation":"Si una colina, curva u obstáculo impide que los conductores vean el vehículo dentro de 500 feet, mueva el dispositivo de advertencia más alejado hacia atrás, más allá del obstáculo, para que el tránsito que se aproxima sea advertido a tiempo. Fuente: Manual CDL de Montana, Sección 2.5."},"75":{"q":"Un conductor de autobús escolar de Montana que se aproxima a un cruce ferroviario debe activar las luces de emergencia del autobús aproximadamente a qué distancia antes del cruce?","options":["Unos 50 feet antes del cruce","Unos 500 feet antes del cruce","Solo después de detenerse en el cruce","Unos 200 feet antes del cruce"],"explanation":"Los procedimientos para autobuses escolares de Montana exigen activar las luces de emergencia unos 200 feet antes del cruce y luego detenerse a entre 15 y 50 feet del riel más cercano. Fuente: Manual CDL de Montana, Sección 10 (Autobuses escolares), procedimientos de cruce."},"76":{"q":"En una interestatal de Montana dentro de un área urbanizada de 50,000 personas o más, el límite de velocidad para vehículos de pasajeros es:","options":["80 mph en todo momento","75 mph de día, 65 mph de noche","55 mph en todo momento","65 mph en todo momento"],"explanation":"Si bien las interestatales rurales permiten a los autos circular a 80 mph, el límite baja a 65 mph en los tramos de la interestatal dentro de un área urbanizada de 50,000 habitantes o más. Fuente: MCA 61-8-303 (restricciones de velocidad)."},"77":{"q":"Donde aplica la ley 'Move Over', Montana también exige que los conductores obedezcan cuál de los siguientes si está presente en el lugar?","options":["Las indicaciones de un señalero o un tablero señalizado con un límite de velocidad temporal","Solo las instrucciones por radio del despachador","Nada más una vez que se ha cambiado de un carril","Una parada completa obligatoria en cada lugar de emergencia"],"explanation":"La MCA 61-8-388 exige que los conductores sigan las indicaciones de cualquier señalero o de un tablero señalizado con un límite de velocidad temporal; las reducciones de mph establecidas por ley aplican únicamente cuando no hay un límite temporal señalizado. Fuente: MCA 61-8-388."},"78":{"q":"Una CDL Clase A de Montana emitida tras un examen de habilidades en una combinación conectada con un gancho de remolque (pintle hook, no una quinta rueda) lleva cuál restricción?","options":["Una restricción 'K' que limita al conductor únicamente al servicio intraestatal","Una restricción 'L' para vehículos sin frenos de aire","Una restricción 'Z' para sistemas de frenos de aire parciales","Una restricción 'O' que prohíbe operar una combinación de tractor y semirremolque de quinta rueda"],"explanation":"Montana coloca una restricción 'O' en una licencia Clase A cuando el examen de habilidades se realiza en una combinación conectada por un gancho de remolque (pintle hook) u otro acople que no sea de quinta rueda, lo que impide operar un tractor con semirremolque de quinta rueda. Fuente: Manual CDL de Montana (sección de restricciones/endosos de la licencia)."},"79":{"q":"Cuál agencia de Montana realmente emite la licencia de conducir comercial (CDL) y procesa la solicitud en una oficina del condado?","options":["La Administración Federal de Seguridad de Autotransportes (FMCSA)","La División de Vehículos Motorizados de Montana (Montana MVD)","El Departamento de Transporte de Montana (MDT)","La Patrulla de Caminos de Montana"],"explanation":"En Montana, la CDL es emitida por la División de Vehículos Motorizados (MVD), y los solicitantes finalizan el proceso en una oficina de Licencias de Conducir del condado. El MDT (Transporte) administra el programa del examen de habilidades y el ELDT, pero la licencia en sí es emitida por la MVD. Fuente: páginas de CDL de Montana MVD y 'Ten Easy Steps to a CDL' del MDT."},"80":{"q":"Después de aprobar el examen de habilidades de la CDL en Montana, a dónde debe ir para que la licencia comercial sea efectivamente emitida?","options":["Al examinador de habilidades del MDT, quien la imprime en el momento","Al sitio web del Registro de Proveedores de Capacitación de la FMCSA","De regreso a la oficina de la MVD del condado para que se emita la licencia","Se envía automáticamente por correo sin necesidad de otra visita"],"explanation":"El documento 'Ten Easy Steps to a CDL' del MDT de Montana indica que el examinador transmite los resultados del examen de habilidades a la MVD, pero el solicitante DEBE regresar a la MVD del condado para que se emita la nueva licencia comercial. Fuente: 'Ten Easy Steps to a CDL' del MDT, Paso 10."},"81":{"q":"Según las normas federales adoptadas en Montana, cuánto tiempo debe tener el Permiso de Aprendiz Comercial (CLP) antes de poder presentar el examen de habilidades (de manejo) de la CDL?","options":["Al menos 14 days","Al menos 7 days","Al menos 30 days","Al menos 60 days"],"explanation":"Las normas de la FMCSA aplicadas por Montana exigen tener el CLP por un mínimo de 14 days antes de presentar el examen de habilidades, incluso cuando un titular de CDL existente solo está haciendo una mejora de categoría. Fuente: 'Ten Easy Steps to a CDL' del MDT, Pasos 4F y 9."},"82":{"q":"Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Montana?","options":["90 days","60 days","1 año","180 days"],"explanation":"Un CLP de Montana es válido por 180 days y puede renovarse una sola vez antes de que venza. Fuente: 'Getting a New CDL in Montana' de Montana MVD."},"83":{"q":"Cuántas veces puede renovarse un CLP de Montana antes de que venza?","options":["Una vez","No puede renovarse","Dos veces","Tres veces"],"explanation":"Montana permite que el CLP de 180 days se renueve una sola vez antes de su vencimiento. Fuente: 'Getting a New CDL in Montana' de Montana MVD."},"84":{"q":"Antes de que un solicitante primerizo de Clase A o Clase B pueda presentar el examen de habilidades de Montana, qué capacitación debe completarse y registrarse en el Registro de Proveedores de Capacitación de la FMCSA?","options":["Un curso de manejo defensivo aprobado por el condado","Capacitación de Conductor de Nivel Inicial (ELDT)","Un programa de acompañamiento de la Patrulla de Caminos de Montana","Una clase de endoso de frenos de aire"],"explanation":"Desde el 7 de febrero de 2022, se requiere la ELDT de un proveedor listado en el Registro de Proveedores de Capacitación de la FMCSA antes de que un solicitante elegible pueda presentar el examen de habilidades de la CDL. El propio MDT es un proveedor de capacitación registrado. Fuente: 'Ten Easy Steps to a CDL' del MDT, Paso 5; página de ELDT del MDT."},"85":{"q":"El examen de habilidades de la CDL de Montana se administra en tres partes. Cuál conjunto nombra correctamente esas tres partes?","options":["Examen escrito, evaluación de la vista y manejo en carretera","Inspección previaje, examen de frenos de aire y manejo nocturno","Inspección previaje, control básico del vehículo y manejo en carretera","Maniobras de retroceso, acople y un examen escrito de endoso"],"explanation":"Al igual que en todos los estados, el examen de habilidades de tres partes de Montana consiste en la inspección previaje del vehículo, las maniobras de control básico del vehículo (retroceso) y el examen de manejo en carretera. Fuente: Manual CDL de Montana; 'Ten Easy Steps to a CDL' del MDT, Pasos 6-9."},"86":{"q":"Por cuánto tiempo es válida una CDL estándar de Montana antes de que deba renovarse (para un conductor típico de entre 21 y 70 años)?","options":["8 años","5 años","2 años","4 años"],"explanation":"Una licencia de conducir comercial de Montana se emite por 4 años, un ciclo más corto que la licencia no comercial estándar de Montana de 8 años. Fuente: 'Ten Easy Steps to a CDL' del MDT, Paso 10; página de renovación de CDL de Montana MVD."},"87":{"q":"Entre cuántas categorías de autocertificación de operación debe elegir un solicitante de CDL de Montana al declarar su tipo de manejo?","options":["Dos","Cuatro","Tres","Seis"],"explanation":"Montana utiliza las cuatro categorías federales de autocertificación: interestatal no exenta, interestatal exenta, intraestatal no exenta (solo Montana) e intraestatal exenta. Fuente: formulario de Clasificación de Autocertificación de CDL y Documentación Médica de Montana MVD; MCA 61-5-141."},"88":{"q":"Un conductor de Montana que cruza líneas estatales y debe cumplir con todas las normas federales de calificación física se autocertifica bajo cuál categoría?","options":["Interestatal no exenta","Interestatal exenta","Intraestatal no exenta","Intraestatal exenta"],"explanation":"Un conductor que opera en comercio interestatal y que está sujeto a las normas de calificación física del 49 CFR Part 391 se autocertifica como interestatal no exenta y debe mantener archivado un certificado vigente del examinador médico. Fuente: formulario de autocertificación de Montana MVD; MCA 61-5-141."},"89":{"q":"Cuál categoría de autocertificación exige que el conductor presente y mantenga un certificado válido del examinador médico del DOT ante el Estado de Montana?","options":["Interestatal exenta","Intraestatal exenta","Interestatal no exenta","Exenta de flota gubernamental"],"explanation":"Los conductores interestatales no exentos deben cumplir con el 49 CFR Part 391 y presentar un Certificado del Examinador Médico vigente; las categorías 'exentas' no requieren tener una tarjeta médica archivada. (La intraestatal no exenta también requiere una tarjeta o una declaración médica de Montana.) Fuente: formulario de autocertificación de Montana MVD; MCA 61-5-141."},"90":{"q":"Cuando un titular de CDL no exento de Montana obtiene un nuevo certificado del examinador médico del DOT, cómo se presenta ante el estado?","options":["Se archiva únicamente con el empleador del conductor","Se entrega a la MVD del condado, que lo escanea en el historial de manejo","Se envía por correo directamente a la oficina nacional de la FMCSA en Washington","No se necesita presentarlo; la firma del médico es suficiente"],"explanation":"Los conductores no exentos de Montana deben presentar el certificado médico ante la MVD de su condado al obtenerlo y en cada renovación; la MVD escanea una copia en el historial de manejo. Fuente: 'Ten Easy Steps to a CDL' del MDT, Paso 4B; MCA 61-5-141."},"91":{"q":"Un certificado estándar del examinador médico del DOT que se usa para mantener válida una CDL de Montana puede emitirse por un máximo de cuánto tiempo?","options":["Hasta 12 months","Hasta 36 months","Hasta 24 months","Hasta 6 months"],"explanation":"Un examen físico del DOT es válido hasta por 24 months; un examinador puede emitir un certificado más corto para monitorear una condición médica. Fuente: 'Ten Easy Steps to a CDL' del MDT, Paso 2; guía médica de la CDL de Montana."},"92":{"q":"Según la MCA 61-5-141, qué le sucede a una CDL de Montana si el titular no presenta un certificado médico vigente antes de su fecha de vencimiento?","options":["La licencia de conducir completa se revoca de inmediato","Nada cambia hasta la siguiente renovación de los 4 años","El conductor recibe una multa pero conserva todos los privilegios de la CDL","La MVD degrada la licencia comercial a una licencia base (sin CDL)"],"explanation":"La MCA 61-5-141 ordena al departamento marcar el registro del CDLIS como 'no certificado' y degradar la licencia comercial a una licencia base si no hay un certificado vigente archivado. Fuente: MCA 61-5-141, Autocertificación del estatus de operación."},"93":{"q":"Según el estatuto de autocertificación de Montana, dentro de cuántos días debe actuar la MVD para degradar una CDL después de que vence un certificado médico?","options":["10 days","30 days","60 days","90 days"],"explanation":"La MCA 61-5-141 exige que el departamento actúe dentro de los 10 days posteriores a que el certificado pierda validez para marcar el registro como no certificado, degradar la licencia y notificar al conductor. Fuente: MCA 61-5-141."},"94":{"q":"Por cuánto tiempo siguen siendo válidos los resultados aprobados del examen escrito de conocimientos de la CDL de Montana si el solicitante aún no ha obtenido la CDL?","options":["Seis meses desde la fecha en que se aprobó","Un año desde la fecha en que se aprobó","Dos años desde la fecha en que se aprobó","180 days desde la fecha en que se aprobó"],"explanation":"Los resultados del examen de conocimientos de Montana siguen siendo válidos por un año desde la fecha en que se aprobó; si la CDL no se obtiene dentro de ese año, deben volver a presentarse todos los exámenes escritos. Fuente: 'Ten Easy Steps to a CDL' del MDT, Paso 4D."},"95":{"q":"En Montana, cuándo puede un solicitante que reprueba un examen escrito de conocimientos de la CDL volver a presentar ese examen?","options":["Solo después de un período de espera de 7 days","Solo después de 14 days","Al día siguiente","Solo después de 30 days"],"explanation":"Montana permite que un examen escrito de conocimientos reprobado se vuelva a presentar al día siguiente. Fuente: 'Ten Easy Steps to a CDL' del MDT, Paso 4D."},"96":{"q":"El día del examen, cuánto tiempo tiene un solicitante de Montana para completar la parte de inspección previaje del vehículo del examen de habilidades?","options":["30 minutos","60 minutos","20 minutos","45 minutos"],"explanation":"Montana asigna 45 minutos para completar la inspección previaje el día del examen; realizar incorrectamente la verificación de frenos resulta en una reprobación. Fuente: 'Ten Easy Steps to a CDL' del MDT, Paso 6A."},"97":{"q":"Un solicitante de CDL en Montana que ya tiene una licencia de conducir estándar de Montana (sin CDL) aún debe presentar cuál de los siguientes en la cita?","options":["Un acta de nacimiento nueva cada vez","Comprobante de residencia en Montana nuevamente","Un certificado físico válido del DOT (del examinador médico)","Un formulario de autorización de la Patrulla de Caminos de Montana"],"explanation":"Los solicitantes que ya tienen una licencia estándar de Montana deben presentar comprobante del número de Seguro Social, comprobante de presencia autorizada y un certificado físico válido del DOT (del examinador médico); el comprobante de identidad/residencia ya estaba archivado. Fuente: 'Ten Easy Steps to a CDL' del MDT, Documentos Requeridos."},"98":{"q":"Cuál es la edad mínima para obtener una CDL de Montana para manejo comercial intraestatal (solo Montana) frente al manejo interestatal?","options":["21 para intraestatal y 25 para interestatal","18 tanto para intraestatal como para interestatal","16 para intraestatal y 18 para interestatal","18 para intraestatal y 21 para interestatal"],"explanation":"Montana exige que el solicitante tenga al menos 18 años para manejar un vehículo comercial dentro del estado (intraestatal) y al menos 21 años para manejar interestatal. Fuente: Manual CDL de Montana; requisitos de CDL de Montana MVD."}},"hi":{"0":{"q":"मोंटाना के राजमार्गों पर, ओवरसाइज़ परमिट के बिना किसी वाणिज्यिक वाहन और उसके लदान की अधिकतम कानूनी चौड़ाई कितनी है?","options":["8 फीट 0 इंच (96 इंच)","9 फीट 0 इंच (108 इंच)","10 फीट 0 इंच (120 इंच)","8 फीट 6 इंच (102 इंच)"],"explanation":"मोंटाना MCA 61-10-102 तथा Montana Commercial Vehicle Size and Weight and Safety Trucker's Handbook ('Legal Dimensions') के अनुसार वाहन की कुल बाहरी चौड़ाई को 102 इंच (8 फीट 6 इंच) तक सीमित करता है। इससे चौड़े लदान के लिए परमिट आवश्यक है।"},"1":{"q":"मोंटाना के राजमार्गों पर किसी वाहन की, बिना लदान या लदान सहित, अधिकतम कानूनी ऊँचाई कितनी है?","options":["13 फीट 6 इंच","14 फीट","15 फीट","15 फीट 6 इंच"],"explanation":"MCA 61-10-103 तथा Montana Trucker's Handbook के अनुसार, कोई वाहन (बिना लदान या लदान सहित) ऊँचाई में 14 फीट से अधिक नहीं हो सकता। इससे अधिक ऊँचाई के लिए ओवर-डाइमेंशनल परमिट आवश्यक है।"},"2":{"q":"मोंटाना में बिना परमिट के, ट्रक ट्रैक्टर-सेमीट्रेलर संयोजन में सेमीट्रेलर की अधिकतम लंबाई कितनी है?","options":["48 फीट","57 फीट","53 फीट","60 फीट"],"explanation":"MCA 61-10-104 तथा Montana Trucker's Handbook सेमीट्रेलर की अधिकतम लंबाई 53 फीट निर्धारित करते हैं (लदान वहन करने हेतु अभिकल्पित न किए गए भागों को छोड़कर)। MCA 61-10-124 के अंतर्गत एक टर्म परमिट इसे 57 फीट तक बढ़ा सकता है।"},"3":{"q":"मोंटाना में, ओवरवेट परमिट के बिना एकल एक्सल पर अनुमत अधिकतम सकल भार कितना है?","options":["20,000 pounds","18,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"MCA 61-10-107 तथा Montana Trucker's Handbook के अनुसार, ऐसे एक या अधिक एक्सलों पर कुल भार जिनके केंद्र 40 इंच से अधिक दूर न हों, 20,000 pounds से अधिक नहीं हो सकता। यह संघीय अंतरराज्यीय एकल-एक्सल सीमा से मेल खाता है।"},"4":{"q":"मोंटाना में ओवरवेट परमिट के बिना टैंडम एक्सल समूह पर अनुमत अधिकतम सकल भार कितना है?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"MCA 61-10-107 तथा Montana Trucker's Handbook बताते हैं कि 40 इंच से अधिक परंतु 96 इंच से कम दूरी पर स्थित कोई भी दो लगातार एक्सल 34,000 pounds से अधिक का भार वहन नहीं कर सकते।"},"5":{"q":"भार-सीमा के प्रयोजनों के लिए मोंटाना 'टैंडम एक्सल' को कैसे परिभाषित करता है?","options":["ठीक 40 इंच की दूरी पर दो एक्सल","40 इंच से अधिक और 96 इंच से कम दूरी पर दो लगातार एक्सल","एक-दूसरे से 120 इंच के भीतर कोई भी दो एक्सल","96 इंच से अधिक दूरी पर दो एक्सल"],"explanation":"MCA 61-10-107 (Montana Trucker's Handbook में उद्धृत) टैंडम एक्सल को 40 इंच से अधिक परंतु 96 इंच से कम दूरी पर स्थित दो लगातार एक्सल के रूप में परिभाषित करता है; ऐसा समूह 34,000 pounds तक सीमित है।"},"6":{"q":"एक्सलों के समूह पर अधिकतम अनुमेय सकल भार की गणना के लिए मोंटाना ब्रिज फॉर्मूला क्या है?","options":["W = 1000((LN/(N+1)) + 10N + 20)","W = 250((LN/(N-1)) + 6N + 18)","W = 500((LN/(N+1)) + 12N + 12)","W = 500((LN/(N-1)) + 12N + 36)"],"explanation":"मोंटाना ब्रिज फॉर्मूला (संघीय Bridge Formula B से मेल खाता हुआ) W = 500((LN/(N-1)) + 12N + 36) है, जहाँ L किसी समूह के बाहरी एक्सलों के बीच फीट में दूरी है और N एक्सलों की संख्या है, MCA 61-10-107 तथा Montana Trucker's Handbook के अनुसार।"},"7":{"q":"मोंटाना में, एकल- और टैंडम-एक्सल भार सीमाएँ ब्रिज फॉर्मूला परिणाम को कब निरस्त (अतिक्रमण) करती हैं?","options":["120 इंच से अधिक दूरी पर स्थित सभी एक्सलों के लिए","केवल अंतरराज्यीय प्रणाली (Interstate System) पर","96 इंच से अधिक दूरी पर स्थित न होने वाले सभी एक्सलों के लिए","कभी नहीं; ब्रिज फॉर्मूला हमेशा नियंत्रक होता है"],"explanation":"Montana Trucker's Handbook बताता है कि 96 इंच से अधिक दूरी पर स्थित न होने वाले सभी एक्सलों के लिए एकल- या टैंडम-एक्सल भार सीमाएँ ब्रिज फॉर्मूला सीमाओं को निरस्त कर देती हैं (MCA 61-10-107)।"},"8":{"q":"घटाने योग्य (विभाज्य) लदान ढोने वाले वाहन संयोजन के लिए मोंटाना अधिकतम कितना सकल भार अनुमत करता है?","options":["80,000 pounds","105,500 pounds","131,060 pounds","129,000 pounds"],"explanation":"MCA 61-10-107 तथा Trucker's Handbook में दिए गए Montana Gross Vehicle Weight Chart के अनुसार, घटाने योग्य लदान के लिए अधिकतम सकल भार 131,060 pounds है।"},"9":{"q":"मोंटाना नियमों के अंतर्गत स्टीयरिंग (अगले) एक्सल के भार कैसे सीमित किए जाते हैं?","options":["टायर निर्माता की निर्धारित क्षमता तक, 20,000 pounds से अधिक नहीं","सभी मामलों में ठीक 12,000 pounds तक","टैंडम की तरह 34,000 pounds तक","स्टीयरिंग एक्सल पर कोई सीमा नहीं है"],"explanation":"Montana Trucker's Handbook बताता है कि स्टीयरिंग एक्सल टायर के साइडवॉल पर अंकित निर्माता की निर्धारित क्षमता तक सीमित हैं, जो 20,000 pounds से अधिक नहीं होनी चाहिए (MCA 61-10-107)।"},"10":{"q":"बिना परमिट के, मोंटाना के राजमार्गों पर अन्यथा निर्दिष्ट न किए गए वाहन संयोजनों के लिए अधिकतम कुल संयोजन लंबाई कितनी है?","options":["65 फीट","75 फीट","80 फीट","70 फीट"],"explanation":"MCA 61-10-104 तथा Montana Trucker's Handbook ऐसे संयोजनों को कुल 75 फीट तक सीमित करते हैं (उन संयोजनों को छोड़कर जिन्हें अधिक लंबाई की अनुमति है, जैसे 53-फीट ट्रेलर खींचने वाले ट्रैक्टर, जिनकी कोई कुल-लंबाई सीमा नहीं है)।"},"11":{"q":"मोंटाना में एकल 53-फीट (या उससे छोटे) ट्रेलर को खींचने वाला ट्रैक्टर किस लंबाई नियम के अधीन है?","options":["उसे फिर भी कुल 65 फीट के भीतर रहना चाहिए","उसे हमेशा एक सिंगल-ट्रिप परमिट की आवश्यकता होती है","कुल लंबाई कुछ भी हो, किसी ओवरऑल लंबाई परमिट की आवश्यकता नहीं है","वह कुल 70 फीट तक सीमित है"],"explanation":"Montana Trucker's Handbook बताता है कि 53-फीट (या उससे छोटे) ट्रेलर को खींचने वाले ट्रैक्टर के लिए, कुल संयोजन लंबाई कुछ भी हो, किसी ओवर-लेंथ परमिट की आवश्यकता नहीं है (MCA 61-10-104)।"},"12":{"q":"वाणिज्यिक वाहनों के लिए ओवरसाइज़ और ओवरवेट परमिट तथा सकल-वाहन-भार शुल्क मोंटाना की कौन-सी एजेंसी शाखा जारी करती है?","options":["Montana Highway Patrol की लाइसेंसिंग डेस्क","MDT का Motor Carrier Services (MCS) Division Permitting Section","काउंटी शेरिफ़ का कार्यालय","Federal Motor Carrier Safety Administration"],"explanation":"Montana Trucker's Handbook के अनुसार, Montana Department of Transportation का Motor Carrier Services (MCS) Division Permitting Section साइज़/वेट परमिट जारी करता है; वाहक ऑनलाइन (ePART / eTRIPS) के माध्यम से स्वयं भी परमिट जारी कर सकते हैं।"},"13":{"q":"एक ऐसे ओवर-डाइमेंशनल लदान के लिए जो केवल एकल यात्रा का है और मोंटाना के लिए लाइसेंसीकृत नहीं है, किस प्रकार के परमिट की आवश्यकता होती है?","options":["केवल एक स्थायी टर्म परमिट","एक कस्टम कम्बाइन परमिट","कोई परमिट नहीं, क्योंकि यह एक बार की आवाजाही है","एक सिंगल-ट्रिप ओवर-डाइमेंशनल परमिट, जो राज्य छोड़ते ही निरस्त हो जाता है"],"explanation":"Montana Trucker's Handbook प्रावधान करता है कि अस्थायी यात्रा आधार पर संचालकों को एक सिंगल-ट्रिप ओवर-डाइमेंशनल परमिट प्राप्त करना होगा (8'6\" चौड़े, 14' ऊँचे, 75' लंबे, या 55' से बड़े एकल यूनिट से अधिक के लदान के लिए); राज्य छोड़ते ही यह परमिट निरस्त हो जाता है।"},"14":{"q":"ओवरसाइज़/ओवरवेट (विशेष) परमिट जारी करने के लिए मोंटाना न्यूनतम कितना देयता बीमा अनिवार्य करता है?","options":["$300,000 combined single limit","$500,000 combined single limit","$1,000,000 combined single limit प्रति घटना","$750,000 combined single limit"],"explanation":"Montana Trucker's Handbook की General Oversize Permit Requirements प्रति घटना न्यूनतम $1,000,000 combined single limit शारीरिक चोट और संपत्ति क्षति देयता निर्दिष्ट करती हैं।"},"15":{"q":"मोंटाना का Winter Weight Term Permit कितना अतिरिक्त भार और किन सड़कों पर अनुमत करता है?","options":["गैर-अंतरराज्यीय राजमार्गों पर 10% अतिरिक्त, 1 दिसंबर से 7 मार्च तक","सभी राजमार्गों पर 20% अतिरिक्त, साल भर","केवल अंतरराज्यीय राजमार्गों पर 10% अतिरिक्त","गैर-अंतरराज्यीय राजमार्गों पर 15% अतिरिक्त, 1 नवंबर से 1 अप्रैल तक"],"explanation":"Montana Trucker's Handbook बताता है कि Winter Weight Term Permit गैर-अंतरराज्यीय राजमार्गों पर 1 दिसंबर से 7 मार्च तक 10% अतिरिक्त भार की अनुमति देता है, और इसे जल्दी बर्फ पिघलने के दौरान निलंबित किया जा सकता है।"},"16":{"q":"मोंटाना में एक गैर-निवासी कस्टम कम्बाइन संचालन GVW शुल्क और ओवरसाइज़ परमिटों के बदले प्रति यूनिट कितना विशेष परमिट शुल्क दे सकता है?","options":["$20 प्रति यूनिट","$35 प्रति यूनिट","$105 प्रति यूनिट","$40 प्रति यूनिट"],"explanation":"MCA 15-24-301 और 61-10-130 (तथा ARM 18.8.426) के अंतर्गत, Montana Trucker's Handbook प्रावधान करता है कि एक गैर-निवासी कस्टम कम्बाइन संचालन प्रति यूनिट $40 विशेष परमिट शुल्क दे सकता है (निवासी 35% GVW शुल्क के साथ प्रति यूनिट $20 देते हैं)।"},"17":{"q":"मोंटाना अंतरराज्यीय प्रणाली (Interstate System) पर, संघीय एकल-एक्सल भार सीमा क्या है जो मोंटाना में भी लागू होती है?","options":["20,000 pounds","18,000 pounds","21,000 pounds","24,000 pounds"],"explanation":"Montana Trucker's Handbook स्पष्ट रूप से बताता है कि Interstate System पर संघीय एकल-एक्सल भार सीमा 20,000 pounds है, जो MCA 61-10-107 के अंतर्गत मोंटाना की सामान्य एकल-एक्सल सीमा के अनुरूप है।"},"18":{"q":"खेती से संबंधित घास या पुआल के परिवहन के लिए, मोंटाना अधिकतम कितनी वाहन ऊँचाई और कितनी दूरी के भीतर अनुमत करता है?","options":["15 फीट 6 इंच, 25 मील से अधिक नहीं","16 फीट, 50 मील से अधिक नहीं","14 फीट 6 इंच, 10 मील से अधिक नहीं","15 फीट, 100 मील से अधिक नहीं"],"explanation":"MCA 61-10-103 एक खेती अपवाद प्रदान करता है: कोई कृषि उपकरण या घास या पुआल ढोने वाला वाहन 15 फीट 6 इंच तक पहुँच सकता है यदि वह खेती से संबंधित 25 मील से अधिक यात्रा न करे और 17 फीट या उससे नीची बाधाओं के नीचे से न गुजरे।"},"19":{"q":"एक गैर-विभाज्य लदान जो ब्रिज फॉर्मूला सीमा से अधिक है परंतु कानूनी एक्सल भार से अधिक नहीं है, उस पर मोंटाना परमिट शुल्क किस आधार पर लगाया जाता है?","options":["दूरी कुछ भी हो, एक निश्चित $200 वार्षिक शुल्क","केवल वाहन का पंजीकृत सकल भार","लदान के मूल्य का 10%","यात्रा माइलेज (जैसे, 100 मील तक $10, 101-199 के लिए $30, 200+ मील के लिए $50)"],"explanation":"Montana Trucker's Handbook ('Overweight On Bridge - Legal Axle Weights - Non-Divisible Loads,' MCA 61-10-107) 100 मील तक $10, 101-199 मील के लिए $30, और 200 मील व उससे अधिक के लिए $50 शुल्क लगाता है।"},"20":{"q":"मोंटाना में, 26,001 pounds या उससे अधिक के सकल संयोजन भार रेटिंग (GCWR) वाले वाहनों के संयोजन को संचालित करने के लिए कौन-सी CDL श्रेणी आवश्यक है, जब खींची जा रही यूनिट(यूनिटों) का भार 10,000 pounds से अधिक हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"Montana CDL Manual (Classifications, MT-2) के अनुसार, एक Class A संयोजन वाहन का GCWR 11,794 kg (26,001 lbs) या उससे अधिक होता है, बशर्ते खींची जा रही यूनिट(यूनिटों) का भार 4,536 kg (10,000 lbs) से अधिक हो। स्रोत: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)।"},"21":{"q":"मोंटाना में 26,001 pounds या उससे अधिक GVWR वाला एकल 'भारी भारी सीधा वाहन' जो 10,000 pounds से अधिक की किसी वस्तु को नहीं खींच रहा, उसके लिए कौन-सी CDL श्रेणी आवश्यक है?","options":["Class A","Class B","Class C","Class M"],"explanation":"Montana CDL Manual (Classifications, MT-2) Class B को 26,001 lbs या उससे अधिक GVWR वाले किसी भी एकल वाहन, या ऐसे वाहन के रूप में परिभाषित करता है जो 10,000 lbs से अधिक न होने वाली किसी यूनिट को खींच रहा हो। स्रोत: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)।"},"22":{"q":"मोंटाना में, एक ऐसा वाहन जो Class A या B भार परिभाषाओं को पूरा नहीं करता परंतु 16 या अधिक यात्रियों (चालक सहित) को परिवहन करने हेतु अभिकल्पित है या प्लेकार्डयुक्त खतरनाक सामग्री ढोने के लिए उपयोग होता है, उसके लिए कौन-सी CDL श्रेणी आवश्यक है?","options":["Class A","Class B","Class C","Class D"],"explanation":"Montana CDL Manual (Classifications, MT-2) Class C को ऐसे एकल वाहन या संयोजन के रूप में परिभाषित करता है जो न तो Class A और न ही B को पूरा करता है परंतु चालक सहित 16+ यात्रियों को ढोने हेतु अभिकल्पित है, या प्लेकार्डयोग्य खतरनाक सामग्री के परिवहन के लिए उपयोग होता है। स्रोत: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)।"},"23":{"q":"मोंटाना CDL नियमों के अंतर्गत, Passenger (P) एंडोर्समेंट आवश्यक होने से पहले किसी वाहन को न्यूनतम कितने यात्रियों (चालक सहित) को ढोने हेतु अभिकल्पित होना चाहिए?","options":["8 यात्री","10 यात्री","15 यात्री","16 यात्री"],"explanation":"Montana CDL Manual (MT-3) बताता है कि चालक सहित 16 या अधिक यात्रियों को परिवहन करने हेतु अभिकल्पित Class A, B, या C वाहनों के लिए Passenger Vehicle (P) एंडोर्समेंट आवश्यक है। स्रोत: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)।"},"24":{"q":"डबल या ट्रिपल ट्रेलर खींचने वाले वाणिज्यिक वाहन को संचालित करने के लिए कौन-सा मोंटाना CDL एंडोर्समेंट आवश्यक है?","options":["N एंडोर्समेंट","T एंडोर्समेंट","X एंडोर्समेंट","H एंडोर्समेंट"],"explanation":"Montana CDL Manual (MT-2/MT-3) बताता है कि Class A या B में डबल या ट्रिपल ट्रेलर खींचने वाले चालकों के लिए Double/Triple Trailers (T) एंडोर्समेंट आवश्यक है। स्रोत: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)।"},"25":{"q":"Montana CDL Manual के अनुसार, Tanker (N) एंडोर्समेंट तब आवश्यक होता है जब किसी ऐसे टैंक में तरल या गैसीय सामग्री का परिवहन किया जाए जिसकी निर्धारित क्षमता कम से कम कितनी हो?","options":["119 गैलन","500 गैलन","1,000 गैलन","3,500 गैलन"],"explanation":"Montana CDL Manual (MT-3) Tank Vehicle (N) एंडोर्समेंट को ऐसे टैंक के लिए आवश्यक के रूप में परिभाषित करता है जिसकी निर्धारित क्षमता 1,000 गैलन या उससे अधिक हो, या कई टैंक जिनकी कुल निर्धारित क्षमता 1,000 गैलन हो। स्रोत: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)।"},"26":{"q":"एक INTRASTATE (केवल मोंटाना) वाणिज्यिक चालक लाइसेंस के लिए आवेदन करने की न्यूनतम आयु क्या है?","options":["16 वर्ष","18 वर्ष","19 वर्ष","21 वर्ष"],"explanation":"Montana CDL Manual (Minimum Driver Ages, MT-3) बताता है कि एक इंट्रास्टेट (केवल मोंटाना) आवेदक को मोंटाना की योग्यताएँ पूरी करनी चाहिए और कम से कम 18 वर्ष का होना चाहिए। स्रोत: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)।"},"27":{"q":"मोंटाना में एक INTERSTATE वाणिज्यिक चालक लाइसेंस के लिए आवेदन करने की न्यूनतम आयु क्या है?","options":["18 वर्ष","19 वर्ष","21 वर्ष","25 वर्ष"],"explanation":"Montana CDL Manual (Minimum Driver Ages, MT-3) बताता है कि एक इंटरस्टेट लाइसेंस के लिए आवेदन करने हेतु आपको कम से कम 21 वर्ष का होना चाहिए और CDL की योग्यताएँ पूरी करने में सक्षम होना चाहिए। स्रोत: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)।"},"28":{"q":"मोंटाना में CDL स्किल्स (प्री-ट्रिप, बेसिक कंट्रोल, और रोड) टेस्ट देने से पहले, एक Commercial Learner Permit को न्यूनतम कितने समय तक धारण करना आवश्यक है?","options":["7 दिन","10 दिन","14 दिन","30 दिन"],"explanation":"Montana CDL Manual (CLP definition, MT-2) बताता है कि सभी CLP परमिटों को प्री-ट्रिप, बेसिक स्किल्स, और रोड टेस्ट देने से पहले न्यूनतम 14 दिन तक धारण किया जाना चाहिए (चालक 15वें दिन टेस्ट दे सकता है)। यह संघीय CLP नियम को दर्शाता है। स्रोत: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); 49 CFR 383.25।"},"29":{"q":"Hazardous Materials (H) एंडोर्समेंट के साथ एक मोंटाना CDL जारी, नवीनीकृत, या स्थानांतरित किए जाने से पहले, संघीय कानून चालक को कौन-सी स्क्रीनिंग पास करना अनिवार्य करता है?","options":["केवल एक DOT ड्रग और अल्कोहल टेस्ट","एक TSA Security Threat Assessment (फिंगरप्रिंट-आधारित पृष्ठभूमि जाँच)","एक FBI पॉलीग्राफ परीक्षा","एक राज्य दृष्टि और रिफ्लेक्स स्क्रीनिंग"],"explanation":"Montana CDL Manual (Hazardous Materials, MT-2) बताता है कि संघीय कानून के अनुपालन में, HazMat एंडोर्समेंट प्राप्त, स्थानांतरित, या नवीनीकृत करने के इच्छुक चालकों को पहले TSA द्वारा पूर्ण किया गया एक Security Threat Assessment (STA) करवाना होगा, जिसमें फिंगरप्रिंटिंग और आपराधिक पृष्ठभूमि जाँच शामिल है। स्रोत: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); 49 CFR 1572।"},"30":{"q":"एक मोंटाना चालक जिसने HazMat एंडोर्समेंट के लिए TSA Security Threat Assessment पूरा कर लिया है, उसे नवीनीकरण या स्थानांतरण के समय आम तौर पर एक और STA पूरा करने की आवश्यकता नहीं होती यदि पूर्व मूल्यांकन पिछले कितने वर्षों के भीतर हुआ हो?","options":["1 वर्ष","2 वर्ष","5 वर्ष","7 वर्ष"],"explanation":"Montana CDL Manual (MT-2) बताता है कि जिन लोगों का अपने CDL को नवीनीकृत या स्थानांतरित करने के आवेदन के पिछले दो वर्षों के भीतर एक सुरक्षा खतरा मूल्यांकन हो चुका है, उन्हें एक और STA पूरा करने की आवश्यकता नहीं हो सकती। स्रोत: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)।"},"31":{"q":"मोंटाना में अपनाए गए संघीय Entry-Level Driver Training (ELDT) नियमों के अंतर्गत, एक पहली बार के आवेदक को टेस्ट देने से पहले कहाँ सूचीबद्ध प्रदाता से ELDT पूरा करना चाहिए?","options":["Montana DOT कॉन्ट्रैक्टर सूची","FMCSA Training Provider Registry (TPR)","AAMVA ड्राइवर स्कूल निर्देशिका","कोई भी राज्य-अनुमोदित ट्रेड स्कूल"],"explanation":"ELDT के लिए FMCSA Training Provider Registry (TPR) पर सूचीबद्ध प्रदाता से प्रशिक्षण आवश्यक है। मोंटाना अपने CDL Manual (MT-2) में इस आवश्यकता का संदर्भ देता है। स्रोत: FMCSA ELDT rule (49 CFR 380, effective Feb 7, 2022); Montana CDL Manual, Rev. June 2026 (MVD/DOJ)।"},"32":{"q":"संघीय ELDT आवश्यकताएँ Class A या B CDL के पहली बार के आवेदकों पर और किस एंडोर्समेंट समूह के पहली बार के आवेदकों पर लागू होती हैं?","options":["N (Tanker) और T (Doubles/Triples)","P (Passenger), S (School Bus), और H (HazMat)","केवल T (Doubles/Triples) और S (School Bus)","केवल H (HazMat)"],"explanation":"FMCSA ELDT rule (effective Feb 7, 2022) के अंतर्गत, पहली बार के Class A/B CDL के लिए और पहली बार के Passenger (P), School Bus (S), तथा Hazardous Materials (H) एंडोर्समेंट के लिए प्रशिक्षण आवश्यक है। मोंटाना ने इन आवश्यकताओं को अपनाया (CDL Manual, MT-2/MT-3)। स्रोत: 49 CFR 380; Montana CDL Manual, Rev. June 2026 (MVD/DOJ)।"},"33":{"q":"निम्नलिखित में से कौन-सी उन चार स्व-प्रमाणन श्रेणियों में से एक है जिसे एक मोंटाना CDL आवेदक को यह दर्शाने के लिए चुनना चाहिए कि वे किस प्रकार के वाणिज्य में संचालन करते हैं?","options":["Interstate non-excepted","Federal contract carrier","Recreational interstate","Limited commercial waiver"],"explanation":"Montana CDL Manual (Self-Certification, MT-3) चार श्रेणियों को इस प्रकार सूचीबद्ध करता है: Interstate non-excepted, Interstate excepted, Intrastate non-excepted, और Intrastate excepted। स्रोत: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); 49 CFR 383.71।"},"34":{"q":"एक मोंटाना CDL आवेदक जो 'Interstate non-excepted' के रूप में स्व-प्रमाणित करता है, वह चिकित्सा आवश्यकताओं के बारे में कौन-सा कथन दे रहा है?","options":["वे एक चिकित्सा परीक्षक का प्रमाणपत्र रखने से छूट प्राप्त हैं","उन्हें संघीय चिकित्सा (MEC) आवश्यकताओं को पूरा करना होगा","उन्हें केवल एक मोंटाना इंट्रास्टेट चिकित्सा छूट की आवश्यकता है","उन्हें कोई भी चिकित्सा प्रमाणन की आवश्यकता नहीं है"],"explanation":"Montana CDL Manual (Self-Certification, MT-3) बताता है कि एक Interstate non-excepted चालक को संघीय Medical Examiner's Certificate (MEC) आवश्यकताओं को पूरा करना चाहिए। स्रोत: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); 49 CFR 383.71।"},"35":{"q":"एक मोंटाना वाणिज्यिक चालक लाइसेंस के सभी आवेदकों को कितनी अलग-अलग प्रमाण श्रेणियों से दस्तावेज़ प्रदान करने होते हैं?","options":["दो: पहचान और निवास","तीन: अधिकृत उपस्थिति, पहचान, और मोंटाना निवास","चार: पहचान, निवास, SSN कार्ड, और नागरिकता","एक: एक एकल REAL ID-अनुपालक दस्तावेज़"],"explanation":"Montana CDL Manual (Proof of Authorized Presence, Identity, and Residence, MT-7/MT-8) तीन श्रेणियों से दस्तावेज़ अनिवार्य करता है: अधिकृत उपस्थिति का प्रमाण, पहचान का प्रमाण, और मोंटाना निवास का प्रमाण। स्रोत: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)।"},"36":{"q":"एक मोंटाना CDL आवेदन पर सामाजिक सुरक्षा नंबर के संबंध में, राज्य क्या अनिवार्य करता है?","options":["SSN को Social Security Administration के पास दर्ज नंबर से मेल खाना चाहिए","CDL के लिए कभी भी किसी SSN की आवश्यकता नहीं होती","केवल अंतिम चार अंक दर्ज किए जाते हैं और कभी सत्यापित नहीं होते","एक नोटरीकृत शपथपत्र SSN की जगह ले लेता है"],"explanation":"Montana CDL Manual (Proof of Social Security Number and Identity Confirmation, MT-2) बताता है कि CDL आवेदन पर प्रयुक्त नाम, जन्म तिथि, और SSN को Social Security Administration के पास दर्ज जानकारी से मेल खाना चाहिए, और SSN की जाँच SSA के साथ की जाती है। स्रोत: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); FMCSR 383.153।"},"37":{"q":"यदि एक मोंटाना वाणिज्यिक चालक आउट-ऑफ-सर्विस घोषित किए जाने के बाद भी गाड़ी चलाना जारी रखता है, तो ऐसे पहले अपराध पर CDL कितने समय के लिए निलंबित होता है?","options":["30 दिन","90 दिन","6 महीने","3 वर्ष"],"explanation":"Montana CDL Manual (Driver Disqualifications, MT-5) बताता है कि यदि आप आउट-ऑफ-सर्विस घोषित किए जाने के बाद गाड़ी चलाते हैं, तो पहले अपराध पर आपका CDL छह महीने के लिए निलंबित होगा (और बाद के अपराधों पर अधिक समय के लिए)। स्रोत: Montana CDL Manual, Rev. June 2026 (MVD/DOJ); 49 CFR 383.51।"},"38":{"q":"योग्य कृषि-संबंधी सेवा कर्मचारियों के लिए मोंटाना का Restricted Seasonal CDL प्रत्येक कैलेंडर वर्ष में किस मौसमी अवधि के दौरान वैध रहता है?","options":["1 जनवरी से 30 जून तक","15 मार्च से 10 सितंबर तक","1 अप्रैल से 1 अक्टूबर तक","1 मई से 30 नवंबर तक"],"explanation":"Montana CDL Manual (Restricted Seasonal CDL, MT-5) बताता है कि एक Seasonal CDL केवल किसी कैलेंडर वर्ष की 15 मार्च से 10 सितंबर की अवधि के लिए वैध होता है और व्यवसाय स्थल या फार्म की 150-मील त्रिज्या के भीतर संचालन की अनुमति देता है। स्रोत: Montana CDL Manual, Rev. June 2026 (MVD/DOJ)।"},"39":{"q":"मोंटाना में, वह रक्त अल्कोहल सांद्रता (BAC) क्या है जिस पर या उससे ऊपर किसी व्यक्ति को एक वाणिज्यिक मोटर वाहन (CMV) का अवैध रूप से संचालन करते हुए माना जाता है?","options":["0.08","0.04","0.02","0.10"],"explanation":"मोंटाना संघीय CMV मानक का पालन करता है: 0.04 या उससे अधिक अल्कोहल सांद्रता के साथ CMV संचालित करना एक प्रमुख अपराध है। स्रोत: MCA 61-8-802 और Montana CDL Manual (Section 1, Disqualifications); 49 CFR 383.51।"},"40":{"q":"मोंटाना के अंतर्निहित-सहमति (implied-consent) कानून के अंतर्गत, राज्य में कोई भी वाहन संचालित करने से एक चालक को निम्नलिखित में से किसके लिए पहले ही सहमति दिए हुए माना जाता है?","options":["अल्कोहल या नशीली दवाओं के लिए रक्त, श्वास, या मूत्र की जाँच","बिना वारंट के वाहन की तलाशी","एक वार्षिक चिकित्सा परीक्षा","हर ट्रैफ़िक रुकाव पर एक दृष्टि स्क्रीनिंग"],"explanation":"मोंटाना का अंतर्निहित-सहमति कानून प्रावधान करता है कि राज्य में वाहन संचालित करने वाले किसी भी व्यक्ति ने अल्कोहल सांद्रता या नशीली दवाओं की उपस्थिति निर्धारित करने हेतु रक्त, श्वास, या मूत्र की जाँच के लिए सहमति दी है। स्रोत: Montana implied-consent statute (MCA 61-8-1016, पूर्व में 61-8-402) और Montana CDL Manual।"},"41":{"q":"एक मोंटाना CDL धारक खतरनाक सामग्री का परिवहन न करते हुए पहला प्रमुख अपराध (जैसे DUI) करता है। CDL कितने समय के लिए अयोग्य घोषित होता है?","options":["6 महीने","1 वर्ष","3 वर्ष","60 दिन"],"explanation":"एक पहला प्रमुख अपराध CDL की 1-वर्ष की अयोग्यता का परिणाम देता है। स्रोत: MCA 61-8-802(1) और Montana CDL Manual; 49 CFR 383.51।"},"42":{"q":"यदि एक मोंटाना CDL धारक का पहला प्रमुख अपराध प्लेकार्डयोग्य खतरनाक सामग्री का परिवहन करने वाले CMV को संचालित करते समय होता है, तो अयोग्यता अवधि बढ़ाकर कर दी जाती है:","options":["1 वर्ष","2 वर्ष","3 वर्ष","आजीवन"],"explanation":"जब प्लेकार्डयोग्य खतरनाक सामग्री का परिवहन करने वाले CMV को संचालित करते समय पहला प्रमुख अपराध होता है, तो अयोग्यता 1 वर्ष के बजाय 3 वर्ष होती है। स्रोत: MCA 61-8-802(1) और Montana CDL Manual; 49 CFR 383.51।"},"43":{"q":"अपने जीवनकाल में एक अलग घटना से दूसरे प्रमुख अपराध के लिए दोषी ठहराए गए चालक के लिए मोंटाना में अयोग्यता अवधि क्या है?","options":["3 वर्ष","5 वर्ष","10 वर्ष","आजीवन"],"explanation":"एक दूसरा प्रमुख अपराध आजीवन अयोग्यता का परिणाम देता है, हालाँकि मोंटाना संघीय नियमों के अंतर्गत न्यूनतम 10-वर्ष की अवधि के बाद पुनर्बहाली की अनुमति दे सकता है। स्रोत: MCA 61-8-802 और Montana CDL Manual; 49 CFR 383.51।"},"44":{"q":"एक मोंटाना CMV चालक से अल्कोहल के लिए श्वास परीक्षण देने को विधिपूर्वक कहा जाता है और वह इनकार कर देता है। CDL प्रयोजनों के लिए इस इनकार को कैसे माना जाता है?","options":["एक गंभीर ट्रैफ़िक उल्लंघन (60-दिन का दंड) के रूप में","एक प्रमुख अपराध के रूप में, असफल परीक्षण के समान ही अयोग्यता के साथ","एक गैर-रिपोर्ट योग्य प्रशासनिक मामले के रूप में","एक आउट-ऑफ-सर्विस आदेश उल्लंघन के रूप में"],"explanation":"अंतर्निहित सहमति के अंतर्गत एक आवश्यक अल्कोहल/नशीली दवा परीक्षण से इनकार करना एक प्रमुख अपराध है और 0.04 या उससे अधिक पर परीक्षण किए जाने के समान ही अयोग्यता वहन करता है: पहली बार इनकार के लिए 1 वर्ष (HazMat के लिए 3 वर्ष), दूसरी बार के लिए आजीवन। स्रोत: MCA 61-8-802 और Montana CDL Manual; 49 CFR 383.51।"},"45":{"q":"एक मोंटाना CMV चालक जिसमें 0.04 से कम कोई भी पहचानने योग्य मात्रा में अल्कोहल पाया जाता है, वह अयोग्य नहीं होता, परंतु उसे कितने समय के लिए आउट ऑफ सर्विस रखा जाना चाहिए?","options":["1 घंटा","8 घंटे","24 घंटे","72 घंटे"],"explanation":"0.04 से कम पहचानने योग्य अल्कोहल सांद्रता वाले CMV चालक को 24 घंटे के लिए आउट ऑफ सर्विस रखा जाना चाहिए। स्रोत: Montana CDL Manual; 49 CFR 392.5 / 383.51।"},"46":{"q":"निम्नलिखित में से किसे एक मोंटाना CDL धारक के लिए एक गंभीर (SERIOUS) ट्रैफ़िक उल्लंघन के रूप में वर्गीकृत किया गया है?","options":["निर्धारित गति सीमा से 15 mph या अधिक तेज़ गाड़ी चलाना","एक CMV में पहला DUI","एक अल्कोहल परीक्षण से इनकार करना","DUI के लिए लाइसेंस निलंबित रहते हुए गाड़ी चलाना"],"explanation":"अत्यधिक तेज़ गति (सीमा से 15 mph या अधिक) एक गंभीर ट्रैफ़िक उल्लंघन है। DUI और परीक्षण से इनकार प्रमुख अपराध हैं, गंभीर उल्लंघन नहीं। स्रोत: Montana CDL Manual (Disqualifications); 49 CFR 383.51।"},"47":{"q":"एक 3-वर्ष की अवधि के भीतर कितने गंभीर ट्रैफ़िक उल्लंघन एक मोंटाना CDL की 60-दिन की अयोग्यता को सक्रिय करते हैं?","options":["एक","दो","तीन","चार"],"explanation":"एक 3-वर्ष की अवधि के भीतर दूसरा गंभीर ट्रैफ़िक उल्लंघन 60-दिन की अयोग्यता का परिणाम देता है। स्रोत: Montana CDL Manual; 49 CFR 383.51।"},"48":{"q":"एक मोंटाना CDL धारक एक 3-वर्ष की अवधि के भीतर तीन गंभीर ट्रैफ़िक उल्लंघनों के लिए दोषी ठहराया जाता है। न्यूनतम अयोग्यता क्या है?","options":["60 दिन","90 दिन","120 दिन","180 दिन"],"explanation":"एक 3-वर्ष की अवधि में तीन गंभीर ट्रैफ़िक उल्लंघन 120-दिन की अयोग्यता का परिणाम देते हैं। स्रोत: Montana CDL Manual; 49 CFR 383.51।"},"49":{"q":"इनमें से किसे एक मोंटाना CDL धारक के लिए एक गंभीर ट्रैफ़िक उल्लंघन के रूप में नहीं गिना जाता?","options":["बहुत पास-पास चलना (following too closely)","अनुचित या अनियमित लेन परिवर्तन","लापरवाह गाड़ी चलाना","गति सीमा से 5 mph तेज़ गाड़ी चलाना"],"explanation":"गंभीर उल्लंघनों में लापरवाह गाड़ी चलाना, अनुचित/अनियमित लेन परिवर्तन, बहुत पास-पास चलना, और सीमा से 15+ mph तेज़ गति शामिल हैं। मामूली तेज़ गति (जैसे, 5 mph अधिक) एक गंभीर उल्लंघन नहीं है। स्रोत: Montana CDL Manual; 49 CFR 383.51।"},"50":{"q":"CMV चलाते समय एक हैंड-हेल्ड मोबाइल फ़ोन का उपयोग करना, मोंटाना CDL प्रयोजनों के लिए, किस प्रकार के उल्लंघन के रूप में वर्गीकृत किया गया है?","options":["एक प्रमुख अपराध","एक गंभीर ट्रैफ़िक उल्लंघन","एक आउट-ऑफ-सर्विस उल्लंघन","एक रेलमार्ग-क्रॉसिंग उल्लंघन"],"explanation":"CMV चलाते समय एक हैंड-हेल्ड मोबाइल फ़ोन का उपयोग करना मोंटाना में लागू संघीय नियम के अंतर्गत एक गंभीर ट्रैफ़िक उल्लंघन है। स्रोत: Montana CDL Manual; 49 CFR 392.82 और 383.51।"},"51":{"q":"मोंटाना CDL चालकों के लिए CMV चलाते समय टेक्स्टिंग करना प्रतिबंधित है। 3 वर्ष के भीतर टेक्स्टिंग/हैंड-हेल्ड फ़ोन उपयोग के लिए दूसरी दोषसिद्धि किस अयोग्यता का परिणाम देती है?","options":["कोई अयोग्यता नहीं","60 दिन","120 दिन","1 वर्ष"],"explanation":"टेक्स्टिंग/हैंड-हेल्ड फ़ोन उपयोग एक गंभीर उल्लंघन है। एक पहली दोषसिद्धि कोई अयोग्यता नहीं वहन करती, परंतु 3 वर्ष के भीतर दूसरी 60-दिन की अयोग्यता का परिणाम देती है (तीसरी के लिए 120 दिन)। स्रोत: Montana CDL Manual; 49 CFR 392.80/392.82 और 383.51।"},"52":{"q":"CMV चलाते समय किए गए एक मोंटाना CDL धारक के पहले रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए न्यूनतम अयोग्यता क्या है?","options":["30 दिन","60 दिन","120 दिन","1 वर्ष"],"explanation":"एक पहला रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन न्यूनतम 60-दिन की अयोग्यता का परिणाम देता है। स्रोत: Montana CDL Manual; 49 CFR 383.51।"},"53":{"q":"एक 3-वर्ष की अवधि के भीतर दूसरे रेलमार्ग-ग्रेड क्रॉसिंग उल्लंघन के लिए, एक मोंटाना CDL कम से कम कितने समय के लिए अयोग्य घोषित होता है:","options":["60 दिन","120 दिन","180 दिन","1 वर्ष"],"explanation":"एक 3-वर्ष की अवधि में दूसरा रेलमार्ग-ग्रेड क्रॉसिंग उल्लंघन न्यूनतम 120-दिन की अयोग्यता का परिणाम देता है। स्रोत: Montana CDL Manual; 49 CFR 383.51।"},"54":{"q":"एक 3-वर्ष की अवधि के भीतर एक तीसरा रेलमार्ग-ग्रेड क्रॉसिंग उल्लंघन एक मोंटाना CDL को कम से कम कितने समय के लिए अयोग्य घोषित करता है:","options":["120 दिन","180 दिन","1 वर्ष","3 वर्ष"],"explanation":"एक 3-वर्ष की अवधि में तीसरा रेलमार्ग-ग्रेड क्रॉसिंग उल्लंघन न्यूनतम 1-वर्ष की अयोग्यता का परिणाम देता है। स्रोत: Montana CDL Manual; 49 CFR 383.51।"},"55":{"q":"एक मोंटाना CMV चालक पहली बार (HazMat या यात्रियों को न ढोते हुए) एक आउट-ऑफ-सर्विस आदेश का उल्लंघन करता है। न्यूनतम अयोग्यता क्या है?","options":["30 दिन","90 दिन","180 दिन","1 वर्ष"],"explanation":"एक आउट-ऑफ-सर्विस आदेश का उल्लंघन करने के लिए एक पहली दोषसिद्धि कम से कम 180 दिन की अयोग्यता का परिणाम देती है। स्रोत: Montana CDL Manual; 49 CFR 383.51।"},"56":{"q":"एक मोंटाना CDL धारक के लिए 10-वर्ष की अवधि के भीतर (अलग घटनाओं में) दूसरे आउट-ऑफ-सर्विस आदेश उल्लंघन के लिए न्यूनतम अयोग्यता क्या है?","options":["180 दिन","1 वर्ष","2 वर्ष","3 वर्ष"],"explanation":"10 वर्ष के भीतर अलग घटनाओं में दूसरा आउट-ऑफ-सर्विस आदेश उल्लंघन न्यूनतम 2-वर्ष की अयोग्यता का परिणाम देता है (तीसरे के लिए 3 वर्ष)। स्रोत: Montana CDL Manual; 49 CFR 383.51।"},"57":{"q":"यदि एक मोंटाना CMV चालक पहली बार प्लेकार्डयोग्य खतरनाक सामग्री का परिवहन करते समय अथवा 16 या अधिक यात्रियों को ढोने हेतु अभिकल्पित वाहन को संचालित करते समय एक आउट-ऑफ-सर्विस आदेश का उल्लंघन करता है, तो न्यूनतम अयोग्यता है:","options":["60 दिन","180 दिन","1 वर्ष","2 वर्ष"],"explanation":"प्लेकार्डयुक्त HazMat ढोते समय या 16+ यात्रियों (चालक सहित) को ढोते समय एक पहला आउट-ऑफ-सर्विस आदेश उल्लंघन न्यूनतम 180-दिन की अयोग्यता का परिणाम देता है, जिसमें बाद के उल्लंघन के लिए कम से कम 3 वर्ष होता है। स्रोत: Montana CDL Manual; 49 CFR 383.51।"},"58":{"q":"एक मोंटाना CDL धारक को अपने निजी (गैर-वाणिज्यिक) वाहन में एक DUI मिलता है। यह उनके CDL को कैसे प्रभावित करता है?","options":["इसका कोई प्रभाव नहीं होता क्योंकि यह एक CMV में नहीं था","इसे एक प्रमुख अपराध के रूप में माना जाता है और CDL को अयोग्य घोषित कर देता है","यह केवल अंक जोड़ता है परंतु कोई अयोग्यता नहीं","इसका परिणाम केवल एक 24-घंटे का आउट-ऑफ-सर्विस आदेश होता है"],"explanation":"DUI जैसे प्रमुख अपराध CDL को अयोग्य घोषित कर देते हैं, भले ही वे एक निजी वाहन में किए गए हों; एक पहला अपराध 1-वर्ष की अयोग्यता है। स्रोत: MCA 61-8-802 और Montana CDL Manual; 49 CFR 383.51।"},"59":{"q":"मोंटाना की किसी संघीय-सहायता प्राप्त अंतरराज्यीय राजमार्ग (interstate highway) पर, शहरी क्षेत्र के बाहर, एक लदी हुई सेमी (1 टन से अधिक रेटेड क्षमता वाला ट्रक) कानूनी रूप से अधिकतम कितनी गति तक चल सकती है?","options":["हर समय 65 mph","80 mph, कारों के समान","हर समय 70 mph","दिन में 75 mph, रात में 65 mph"],"explanation":"मोंटाना ट्रकों के लिए एक अलग सीमा निर्धारित करता है: 1 टन से अधिक रेटेड क्षमता वाले ट्रक/ट्रक ट्रैक्टर की सीमा अंतरराज्यीय राजमार्ग पर 70 mph है, भले ही ग्रामीण अंतरराज्यीय राजमार्गों पर कारें 80 mph चल सकती हैं। स्रोत: MCA 61-8-312 (ट्रकों पर विशेष गति सीमाएं) और 61-8-303; HB393 (2019) द्वारा बढ़ाई गई।"},"60":{"q":"मोंटाना के किसी दो-लेन सार्वजनिक राजमार्ग पर, जो अंतरराज्यीय (interstate) नहीं है, 1 टन से अधिक रेटेड क्षमता वाले ट्रक के लिए अधिकतम गति है:","options":["दिन में 70 mph, रात में 65 mph","दिन में 60 mph, रात में 55 mph","65 mph, दिन और रात","हर समय 55 mph"],"explanation":"गैर-अंतरराज्यीय राजमार्गों पर ट्रक की सीमा दिन और रात दोनों समय एक समान 65 mph है। पुराने अलग-अलग आंकड़े दिन में 60/रात में 55 को 2019 में निरस्त कर दिया गया था। स्रोत: MCA 61-8-312; HB393 (2019)।"},"61":{"q":"मोंटाना के रेलरोड-क्रॉसिंग नियम के अंतर्गत, उन बसों और प्लैकार्ड लगे हजमत (hazmat) वाहनों के लिए जिन्हें रुकना अनिवार्य है, जहां कोई पेंट की हुई स्टॉप लाइन नहीं है, चालक को निकटतम रेल से कितनी दूरी के भीतर रुकना चाहिए?","options":["15 फीट से अधिक निकट नहीं और 50 फीट से अधिक दूर नहीं","10 फीट से अधिक निकट नहीं और 40 फीट से अधिक दूर नहीं","25 फीट से अधिक निकट नहीं और 75 फीट से अधिक दूर नहीं","5 फीट से अधिक निकट नहीं और 30 फीट से अधिक दूर नहीं"],"explanation":"मोंटाना 15-से-50-फीट नियम का पालन करता है: जिन वाहनों को रुकना अनिवार्य है, उन्हें निकटतम ट्रैक की निकटतम रेल से 15 फीट से अधिक निकट नहीं और 50 फीट से अधिक दूर नहीं रुकना चाहिए। स्रोत: मोंटाना CDL मैनुअल, सेक्शन 2.15 (रेलरोड-राजमार्ग क्रॉसिंग)।"},"62":{"q":"मोंटाना के किसी रेलरोड-राजमार्ग ग्रेड क्रॉसिंग पर कौन से वाणिज्यिक वाहनों को हमेशा पूरी तरह रुकना चाहिए (हरे सिग्नल या पुलिस के निर्देश के अभाव में)?","options":["26,001 पाउंड से अधिक के सभी संयोजन वाहन","केवल ट्रिपल-ट्रेलर संयोजन","राज्य के बाहर पंजीकृत कोई भी ट्रक","यात्री ले जाने वाली बसें और खतरनाक सामग्री के लिए प्लैकार्ड लगाना अनिवार्य वाहन"],"explanation":"मोंटाना का मैनुअल बताता है कि सभी यात्री ले जाने वाले (बस) और हजमत-प्लैकार्ड वाले वाहनों को क्रॉसिंग पर रुकना अनिवार्य है; सामान्य लदे हुए ट्रकों को तब तक रुकना अनिवार्य नहीं जब तक कार्गो या कानून ऐसा अपेक्षित न करे। स्रोत: मोंटाना CDL मैनुअल, सेक्शन 2.15.2 और 2.15.4।"},"63":{"q":"मोंटाना के स्कूल-बस कानून के अंतर्गत, जब एक स्कूल बस अपनी लाल बत्तियां चमकाते हुए सड़क पर रुकी हो, तो पास आ रहे चालक को बस से लगभग कितनी दूरी से कम पर नहीं रुकना चाहिए?","options":["20 फीट","50 फीट","30 फीट","10 फीट"],"explanation":"मोंटाना के अनुसार किसी भी दिशा से आ रहे चालकों को चमकती लाल बत्तियां प्रदर्शित करने वाली स्कूल बस से लगभग 30 फीट से कम पर नहीं रुकना चाहिए, और लाल बत्तियां बंद होने तक रुके रहना चाहिए। स्रोत: MCA 61-8-351 (स्कूल बस से मिलना या उसे पार करना)।"},"64":{"q":"मोंटाना के किसी अलग-अलग सड़क मार्गों वाले राजमार्ग पर (उदाहरण के लिए, एक विभाजित राजमार्ग जिसमें विपरीत दिशा एक भौतिक रूप से अलग सड़क मार्ग पर हो), दूसरे सड़क मार्ग पर रुकी हुई स्कूल बस से मिलने वाले चालक को:","options":["रुकना चाहिए, क्योंकि सभी पास आ रहे यातायात को हमेशा रुकना ही चाहिए","रुकना चाहिए केवल तभी जब मध्य-विभाजक (median) 30 फीट से संकरा हो","नहीं रुकना चाहिए — किसी भिन्न सड़क मार्ग पर मौजूद वाहनों को रुकने की आवश्यकता नहीं","10 mph तक धीमा करना चाहिए लेकिन पूरी तरह रुकने की आवश्यकता नहीं"],"explanation":"मोंटाना का अपवाद: अलग-अलग सड़क मार्गों वाले राजमार्ग पर चलने वाले चालक को किसी भिन्न सड़क मार्ग पर मौजूद स्कूल बस से मिलने या उसे पार करने पर रुकने की आवश्यकता नहीं। यह अपवाद 'अलग सड़क मार्गों' पर आधारित है, न कि केवल पेंट की हुई केंद्र रेखा पर। स्रोत: MCA 61-8-351।"},"65":{"q":"जब किसी मोंटाना स्कूल बस ने केवल अपनी चमकती एम्बर (पीली) बत्तियां ही चालू की हों, तो पास आ रहे चालक को आवश्यकता होती है:","options":["उचित गति तक धीमा करने और रुकने के लिए तैयार रहने की","तुरंत कम से कम 30 फीट की दूरी पर पूरी तरह रुक जाने की","गति बनाए रखने की क्योंकि एम्बर बत्तियों से कोई दायित्व नहीं बनता","रुकने की केवल तभी जब बच्चे सड़क किनारे दिखाई दें"],"explanation":"चमकती एम्बर का अर्थ है कि बस रुकने की तैयारी कर रही है; मोंटाना कानून के अनुसार चालकों को उचित गति तक धीमा करना और रुकने के लिए तैयार रहना आवश्यक है। रुकने का दायित्व तब उत्पन्न होता है जब लाल बत्तियां सक्रिय होती हैं। स्रोत: MCA 61-8-351।"},"66":{"q":"मोंटाना के मूव ओवर (Move Over) कानून के अंतर्गत, किसी अंतरराज्यीय राजमार्ग (interstate) पर एक स्थिर आपातकालीन या राजमार्ग-कर्मी वाहन के पास आते समय जब लेन बदलना संभव हो, तो चालक को पोस्ट की गई सीमा से कम से कम कितना नीचे गति घटानी चाहिए?","options":["पोस्ट की गई सीमा से 10 mph नीचे","पोस्ट की गई सीमा से 30 mph नीचे","पोस्ट की गई सीमा से 20 mph नीचे","पोस्ट की गई सीमा से 5 mph नीचे"],"explanation":"MCA 61-8-388 के अनुसार अंतरराज्यीय राजमार्ग पर जब लेन बदलना संभव हो (और किसी गैर-निकटवर्ती लेन में जाना हो) तो गति को पोस्ट की गई सीमा से 20 mph नीचे घटाना आवश्यक है। यदि लेन बदलना असुरक्षित हो, तो चालक को पोस्ट की गई सीमा के आधे तक धीमा करना चाहिए। स्रोत: MCA 61-8-388।"},"67":{"q":"मोंटाना के मूव ओवर (Move Over) कानून के अंतर्गत, किसी राज्य राजमार्ग या काउंटी सड़क पर जहां लेन बदलना संभव हो, किसी स्थिर आपातकालीन वाहन को पार करते समय आवश्यक गति-कटौती कम से कम है:","options":["पोस्ट की गई सीमा से 20 mph नीचे","पोस्ट की गई सीमा से 15 mph नीचे","पोस्ट की गई सीमा से 10 mph नीचे","पोस्ट की गई सीमा से 30 mph नीचे"],"explanation":"किसी राज्य राजमार्ग या काउंटी सड़क पर, MCA 61-8-388 के अनुसार जब लेन बदलना संभव हो तो पोस्ट की गई सीमा से 30 mph नीचे धीमा करना आवश्यक है; यदि लेन बदलना असुरक्षित हो, तो पोस्ट की गई सीमा के आधे तक धीमा करें। स्रोत: MCA 61-8-388।"},"68":{"q":"मोंटाना के मूव ओवर (Move Over) कानून के अंतर्गत, यदि चालक किसी स्थिर आपातकालीन वाहन के पास आते समय सुरक्षित रूप से लेन बदलने में असमर्थ है, तो चालक को किस गति तक घटाना चाहिए?","options":["पोस्ट की गई गति सीमा की आधी","पोस्ट की गई सीमा की परवाह किए बिना 20 mph","जब तक दृश्य साफ न हो जाए तब तक पूरी तरह रुकना","पोस्ट की गई सीमा से 10 mph नीचे"],"explanation":"जब लेन बदलना सुरक्षित रूप से संभव न हो, तो MCA 61-8-388 के अनुसार पोस्ट की गई गति सीमा के आधे तक घटाते हुए सावधानी से आगे बढ़ना आवश्यक है। स्रोत: MCA 61-8-388।"},"69":{"q":"मोंटाना के किसी बहु-लेन राजमार्ग पर, किसी स्थिर आपातकालीन वाहन के पास आते समय मूव ओवर (Move Over) कानून की प्राथमिक आवश्यकता (जहां कोई पोस्ट की गई अस्थायी सीमा मौजूद नहीं) है:","options":["दाईं लेन में पूरी तरह रुक जाना","रुके हुए वाहन से सटी हुई लेन से हटकर किसी गैर-निकटवर्ती लेन में जाना, यदि यह सुरक्षित रूप से किया जा सके","पार करते समय लगातार हॉर्न बजाना","अधिकतम जगह देने के लिए कंधे (shoulder) पर गाड़ी चलाना"],"explanation":"MCA 61-8-388 बहु-लेन राजमार्ग पर चालकों को निर्देश देता है कि वे स्थिर आपातकालीन या राजमार्ग-कर्मी वाहन से सटी हुई लेन को सुरक्षित होने पर खाली कर दें; यदि यह संभव न हो, तो आवश्यकतानुसार धीमा करें और सावधानी से पार करें। स्रोत: MCA 61-8-388।"},"70":{"q":"यदि किसी मोंटाना CDL चालक को सड़क के कंधे (shoulder) पर रुकना पड़े, तो चेतावनी उपकरण कितने मिनट के भीतर रखे जाने चाहिए?","options":["5 मिनट के भीतर","10 मिनट के भीतर","15 मिनट के भीतर","30 मिनट के भीतर"],"explanation":"किसी रुके हुए ट्रक या बस को सड़क या कंधे पर रुकने के 10 मिनट के भीतर आपातकालीन चेतावनी उपकरण लगाने चाहिए। स्रोत: मोंटाना CDL मैनुअल, सेक्शन 2.5 (संचार / चेतावनी उपकरण)।"},"71":{"q":"जब कोई मोंटाना CDL चालक किसी एक-तरफ़ा (one-way) या विभाजित राजमार्ग पर रुका हो, तो तीन चेतावनी उपकरण कहां रखे जाते हैं?","options":["पास आ रहे यातायात की ओर 10 फीट, 50 फीट, और 150 फीट पर","पास आ रहे यातायात की ओर 10 फीट, 100 फीट, और 200 फीट पर","वाहन से 10 फीट, 100 फीट आगे और 100 फीट पीछे","पास आ रहे यातायात की ओर 15 फीट, 50 फीट, और 100 फीट पर"],"explanation":"किसी एक-तरफ़ा या विभाजित राजमार्ग पर, चेतावनी उपकरणों को पास आ रहे यातायात की ओर 10 फीट, 100 फीट, और 200 फीट पर रखें। स्रोत: मोंटाना CDL मैनुअल, सेक्शन 2.5 (चेतावनी उपकरण स्थापन)।"},"72":{"q":"दोनों दिशाओं में यातायात ले जाने वाली किसी अविभाजित दो-तरफ़ा मोंटाना सड़क पर, किसी रुके हुए CMV के लिए तीन परावर्तक त्रिकोण कहां रखे जाते हैं:","options":["वाहन के 10 फीट के भीतर, और 100 फीट आगे और 100 फीट पीछे","10 फीट, 100 फीट, और 200 फीट, सभी वाहन के पीछे","केवल आते हुए यातायात की ओर 50 फीट, 100 फीट, और 200 फीट पर","10 फीट के भीतर, और 200 फीट आगे और 200 फीट पीछे"],"explanation":"किसी दो-लेन दो-तरफ़ा या अविभाजित सड़क पर, एक उपकरण वाहन के 10 फीट के भीतर और एक 100 फीट आगे तथा एक 100 फीट पीछे, उसी लेन/कंधे पर रखें जहां आप रुके थे। स्रोत: मोंटाना CDL मैनुअल, सेक्शन 2.5।"},"73":{"q":"किसी मोंटाना CDL वाहन को आवश्यक आपातकालीन चेतावनी उपकरण के रूप में कितने लाल परावर्तक त्रिकोण साथ रखने चाहिए?","options":["दो","तीन","चार","छह"],"explanation":"आवश्यक चेतावनी उपकरण तीन लाल परावर्तक त्रिकोण हैं (या विकल्प जैसे 6 फ्यूज़ या 3 तरल-दहन फ्लेयर)। स्रोत: मोंटाना CDL मैनुअल, सेक्शन 2.1 (वाहन निरीक्षण) और सेक्शन 2.5।"},"74":{"q":"किसी मोंटाना सड़क पर जहां कोई पहाड़ी या मोड़ 500 फीट के भीतर रुके हुए CMV के दृश्य को रोकता हो, चालक को चाहिए:","options":["तीनों त्रिकोण बंपर के 10 फीट के भीतर रखे","सबसे पिछले त्रिकोण को सड़क पर पीछे की ओर रुकावट से परे ले जाए ताकि यातायात को चेतावनी मिले","त्रिकोणों को मानक स्थितियों में छोड़ दे और फ्लैशर पर निर्भर रहे","रुकावट से ठीक 500 फीट आगे एक त्रिकोण रखे"],"explanation":"यदि कोई पहाड़ी, मोड़, या रुकावट चालकों को 500 फीट के भीतर वाहन देखने से रोकती है, तो सबसे पिछले चेतावनी उपकरण को रुकावट से परे पीछे ले जाएं ताकि पास आ रहे यातायात को समय रहते चेतावनी मिल सके। स्रोत: मोंटाना CDL मैनुअल, सेक्शन 2.5।"},"75":{"q":"किसी रेलरोड क्रॉसिंग के पास आ रहे मोंटाना स्कूल-बस चालक को क्रॉसिंग से लगभग कितनी दूरी पहले बस की हजार्ड बत्तियां चालू करनी चाहिए?","options":["क्रॉसिंग से लगभग 50 फीट पहले","क्रॉसिंग से लगभग 500 फीट पहले","केवल क्रॉसिंग पर रुकने के बाद","क्रॉसिंग से लगभग 200 फीट पहले"],"explanation":"मोंटाना की स्कूल-बस प्रक्रियाएं क्रॉसिंग से लगभग 200 फीट पहले हजार्ड बत्तियां चालू करने का निर्देश देती हैं, फिर निकटतम रेल से 15 से 50 फीट पर रुकने का। स्रोत: मोंटाना CDL मैनुअल, सेक्शन 10 (स्कूल बसें), क्रॉसिंग प्रक्रियाएं।"},"76":{"q":"मोंटाना के किसी अंतरराज्यीय राजमार्ग (interstate) पर, 50,000 या अधिक लोगों के शहरी क्षेत्र के भीतर, यात्री वाहनों के लिए गति सीमा है:","options":["हर समय 80 mph","दिन में 75 mph, रात में 65 mph","हर समय 55 mph","हर समय 65 mph"],"explanation":"जबकि ग्रामीण अंतरराज्यीय राजमार्ग कारों को 80 mph की अनुमति देते हैं, 50,000+ जनसंख्या वाले शहरी क्षेत्र के भीतर अंतरराज्यीय खंडों पर सीमा घटकर 65 mph हो जाती है। स्रोत: MCA 61-8-303 (गति प्रतिबंध)।"},"77":{"q":"जहां मूव ओवर (Move Over) कानून लागू होता है, वहां मोंटाना चालकों से निम्नलिखित में से किसका पालन करने की भी अपेक्षा करता है यदि वह दृश्य स्थल पर मौजूद हो?","options":["किसी फ्लैगर के निर्देश या पोस्ट किया गया अस्थायी गति-सीमा साइनबोर्ड","केवल डिस्पैचर के रेडियो निर्देश","एक बार लेन बदल लेने के बाद कुछ और नहीं","हर आपातकालीन दृश्य स्थल पर अनिवार्य पूर्ण विराम"],"explanation":"MCA 61-8-388 के अनुसार चालकों को किसी भी फ्लैगर के निर्देशों या पोस्ट किए गए अस्थायी गति-सीमा साइनबोर्ड का पालन करना आवश्यक है; वैधानिक mph कटौतियां केवल तभी लागू होती हैं जब कोई अस्थायी सीमा पोस्ट न की गई हो। स्रोत: MCA 61-8-388।"},"78":{"q":"पिंटल हुक (pintle hook) से जुड़े संयोजन (न कि फिफ्थ व्हील) में स्किल्स टेस्ट के बाद जारी किया गया कोई मोंटाना Class A CDL कौन सा प्रतिबंध रखता है?","options":["एक 'K' प्रतिबंध जो चालक को केवल राज्य-आंतरिक (intrastate) तक सीमित करता है","एयर ब्रेक रहित वाहनों के लिए एक 'L' प्रतिबंध","आंशिक एयर-ब्रेक प्रणालियों के लिए एक 'Z' प्रतिबंध","एक 'O' प्रतिबंध जो फिफ्थ-व्हील ट्रैक्टर/सेमीट्रेलर संयोजन के संचालन पर रोक लगाता है"],"explanation":"मोंटाना किसी Class A लाइसेंस पर एक 'O' प्रतिबंध लगाता है जब स्किल्स टेस्ट पिंटल हुक या किसी अन्य गैर-फिफ्थ-व्हील कपलिंग से जुड़े संयोजन में लिया जाता है, जो फिफ्थ-व्हील ट्रैक्टर/सेमीट्रेलर के संचालन पर रोक लगाता है। स्रोत: मोंटाना CDL मैनुअल (लाइसेंस प्रतिबंध/एंडोर्समेंट सेक्शन)।"},"79":{"q":"मोंटाना की कौन सी एजेंसी वास्तव में वाणिज्यिक चालक लाइसेंस (CDL) जारी करती है और किसी काउंटी कार्यालय में आवेदन को संसाधित करती है?","options":["फेडरल मोटर कैरियर सेफ्टी एडमिनिस्ट्रेशन (FMCSA)","मोंटाना मोटर व्हीकल डिवीजन (MVD)","मोंटाना डिपार्टमेंट ऑफ ट्रांसपोर्टेशन (MDT)","मोंटाना हाईवे पेट्रोल"],"explanation":"मोंटाना में CDL मोटर व्हीकल डिवीजन (MVD) द्वारा जारी किया जाता है, और आवेदक किसी काउंटी ड्राइवर लाइसेंस कार्यालय में प्रक्रिया पूरी करते हैं। MDT (ट्रांसपोर्टेशन) स्किल्स परीक्षा कार्यक्रम और ELDT चलाता है, लेकिन लाइसेंस स्वयं MVD द्वारा जारी किया जाता है। स्रोत: मोंटाना MVD CDL पेज और MDT 'Ten Easy Steps to a CDL'।"},"80":{"q":"मोंटाना में CDL स्किल्स टेस्ट पास करने के बाद, वाणिज्यिक लाइसेंस वास्तव में जारी करवाने के लिए आपको कहां जाना चाहिए?","options":["MDT स्किल्स परीक्षक के पास, जो इसे मौके पर ही प्रिंट कर देता है","FMCSA ट्रेनिंग प्रोवाइडर रजिस्ट्री वेबसाइट पर","लाइसेंस जारी करवाने के लिए वापस काउंटी MVD कार्यालय में","यह स्वतः डाक से भेज दिया जाता है, किसी और मुलाकात की आवश्यकता नहीं"],"explanation":"मोंटाना के MDT 'Ten Easy Steps to a CDL' के अनुसार परीक्षक स्किल्स-टेस्ट के परिणाम MVD को भेजता है, लेकिन आवेदक को नया वाणिज्यिक लाइसेंस जारी करवाने के लिए काउंटी MVD में अवश्य लौटना चाहिए। स्रोत: MDT 'Ten Easy Steps to a CDL,' Step 10।"},"81":{"q":"मोंटाना में अपनाए गए संघीय नियमों के अंतर्गत, CDL स्किल्स (रोड) टेस्ट देने से पहले आपको कमर्शियल लर्नर्स परमिट (CLP) कितने समय तक रखना चाहिए?","options":["कम से कम 14 दिन","कम से कम 7 दिन","कम से कम 30 दिन","कम से कम 60 दिन"],"explanation":"मोंटाना द्वारा लागू FMCSA नियमों के अनुसार स्किल्स टेस्ट देने से पहले CLP को कम से कम 14 दिनों तक रखना आवश्यक है, भले ही कोई मौजूदा CDL धारक केवल अपग्रेड कर रहा हो। स्रोत: MDT 'Ten Easy Steps to a CDL,' Steps 4F और 9।"},"82":{"q":"मोंटाना कमर्शियल लर्नर्स परमिट (CLP) कितने समय के लिए वैध होता है?","options":["90 दिन","60 दिन","1 वर्ष","180 दिन"],"explanation":"मोंटाना CLP 180 दिनों के लिए वैध होता है और इसकी समाप्ति से पहले एक बार नवीनीकृत किया जा सकता है। स्रोत: मोंटाना MVD 'Getting a New CDL in Montana'।"},"83":{"q":"किसी मोंटाना CLP को इसकी समाप्ति से पहले कितनी बार नवीनीकृत किया जा सकता है?","options":["एक बार","इसे नवीनीकृत नहीं किया जा सकता","दो बार","तीन बार"],"explanation":"मोंटाना 180-दिन के CLP को समाप्ति से पहले एक बार नवीनीकृत करने की अनुमति देता है। स्रोत: मोंटाना MVD 'Getting a New CDL in Montana'।"},"84":{"q":"किसी पहली बार के Class A या Class B आवेदक के मोंटाना स्किल्स टेस्ट देने से पहले, कौन सा प्रशिक्षण पूरा किया जाना चाहिए और FMCSA ट्रेनिंग प्रोवाइडर रजिस्ट्री पर दर्ज किया जाना चाहिए?","options":["काउंटी द्वारा अनुमोदित एक डिफेंसिव ड्राइविंग कोर्स","एंट्री-लेवल ड्राइवर ट्रेनिंग (ELDT)","एक मोंटाना हाईवे पेट्रोल राइड-अलॉन्ग कार्यक्रम","एक एयर-ब्रेक एंडोर्समेंट कक्षा"],"explanation":"7 फरवरी 2022 से, किसी पात्र आवेदक के CDL स्किल्स टेस्ट देने से पहले FMCSA की ट्रेनिंग प्रोवाइडर रजिस्ट्री में सूचीबद्ध किसी प्रोवाइडर से ELDT आवश्यक है। MDT स्वयं एक पंजीकृत प्रशिक्षण प्रदाता है। स्रोत: MDT 'Ten Easy Steps to a CDL,' Step 5; MDT ELDT पेज।"},"85":{"q":"मोंटाना का CDL स्किल्स टेस्ट तीन भागों में आयोजित किया जाता है। कौन सा सेट उन तीन भागों को सही नाम देता है?","options":["लिखित परीक्षा, दृष्टि जांच, और ऑन-रोड ड्राइविंग","प्री-ट्रिप निरीक्षण, एयर-ब्रेक टेस्ट, और रात्रि ड्राइविंग","प्री-ट्रिप निरीक्षण, बेसिक वाहन नियंत्रण, और ऑन-रोड ड्राइविंग","बैकिंग, कपलिंग, और एक लिखित एंडोर्समेंट टेस्ट"],"explanation":"सभी राज्यों की तरह, मोंटाना का तीन-भाग वाला स्किल्स टेस्ट प्री-ट्रिप वाहन निरीक्षण, बेसिक वाहन नियंत्रण (बैकिंग) युक्तियों, और ऑन-रोड ड्राइविंग टेस्ट से मिलकर बनता है। स्रोत: मोंटाना CDL मैनुअल; MDT 'Ten Easy Steps to a CDL,' Steps 6-9।"},"86":{"q":"किसी सामान्य मोंटाना CDL को नवीनीकरण की आवश्यकता होने से पहले कितने समय तक वैध रहता है (21 से 70 वर्ष की आयु के किसी सामान्य चालक के लिए)?","options":["8 वर्ष","5 वर्ष","2 वर्ष","4 वर्ष"],"explanation":"एक मोंटाना वाणिज्यिक चालक लाइसेंस 4 वर्षों के लिए जारी किया जाता है, जो मानक 8-वर्षीय गैर-वाणिज्यिक मोंटाना लाइसेंस से छोटा चक्र है। स्रोत: MDT 'Ten Easy Steps to a CDL,' Step 10; मोंटाना MVD CDL नवीनीकरण पेज।"},"87":{"q":"मोंटाना CDL आवेदक को अपने ड्राइविंग के प्रकार की घोषणा करते समय कितनी स्व-प्रमाणन (self-certification) संचालन श्रेणियों में से चुनना होता है?","options":["दो","चार","तीन","छह"],"explanation":"मोंटाना चार संघीय स्व-प्रमाणन श्रेणियों का उपयोग करता है: non-excepted interstate, excepted interstate, non-excepted intrastate (केवल मोंटाना), और excepted intrastate। स्रोत: मोंटाना MVD CDL Self-Certification Classification and Medical Documentation फॉर्म; MCA 61-5-141।"},"88":{"q":"एक मोंटाना चालक जो राज्य की सीमाएं पार करता है और जिसे सभी संघीय शारीरिक योग्यता मानकों को पूरा करना होता है, वह किस श्रेणी के अंतर्गत स्व-प्रमाणन करता है?","options":["Non-excepted interstate","Excepted interstate","Non-excepted intrastate","Excepted intrastate"],"explanation":"अंतरराज्यीय वाणिज्य में संचालन करने वाला चालक जो 49 CFR Part 391 शारीरिक योग्यता मानकों के अधीन है, वह non-excepted interstate के रूप में स्व-प्रमाणन करता है और उसे एक वर्तमान मेडिकल एग्ज़ामिनर सर्टिफिकेट फाइल में रखना चाहिए। स्रोत: मोंटाना MVD स्व-प्रमाणन फॉर्म; MCA 61-5-141।"},"89":{"q":"कौन सी स्व-प्रमाणन श्रेणी चालक से मोंटाना राज्य के पास एक वैध DOT मेडिकल एग्ज़ामिनर सर्टिफिकेट प्रदान करने और बनाए रखने की अपेक्षा करती है?","options":["Excepted interstate","Excepted intrastate","Non-excepted interstate","Government-fleet excepted"],"explanation":"Non-excepted interstate चालकों को 49 CFR Part 391 को पूरा करना होता है और एक वर्तमान मेडिकल एग्ज़ामिनर सर्टिफिकेट जमा करना होता है; 'excepted' श्रेणियों के लिए फाइल में मेडिकल कार्ड की आवश्यकता नहीं होती। (Non-excepted intrastate के लिए भी एक कार्ड या मोंटाना मेडिकल स्टेटमेंट की आवश्यकता होती है।) स्रोत: मोंटाना MVD स्व-प्रमाणन फॉर्म; MCA 61-5-141।"},"90":{"q":"जब कोई मोंटाना non-excepted CDL धारक एक नया DOT मेडिकल एग्ज़ामिनर सर्टिफिकेट प्राप्त करता है, तो इसे राज्य को कैसे जमा किया जाता है?","options":["इसे केवल चालक के नियोक्ता के पास फाइल किया जाता है","इसे काउंटी MVD को दिया जाता है, जो इसे ड्राइविंग रिकॉर्ड में स्कैन कर लेता है","इसे सीधे वॉशिंगटन में FMCSA राष्ट्रीय कार्यालय को डाक से भेजा जाता है","किसी जमा करने की आवश्यकता नहीं; डॉक्टर का हस्ताक्षर पर्याप्त है"],"explanation":"Non-excepted मोंटाना चालकों को प्राप्त होने पर और प्रत्येक नवीनीकरण पर मेडिकल सर्टिफिकेट अपने काउंटी MVD को जमा करना होता है; MVD एक प्रति ड्राइविंग रिकॉर्ड में स्कैन कर लेता है। स्रोत: MDT 'Ten Easy Steps to a CDL,' Step 4B; MCA 61-5-141।"},"91":{"q":"मोंटाना CDL को वैध बनाए रखने के लिए उपयोग किया जाने वाला एक मानक DOT मेडिकल एग्ज़ामिनर सर्टिफिकेट अधिकतम कितने समय के लिए जारी किया जा सकता है?","options":["12 महीने तक","36 महीने तक","24 महीने तक","6 महीने तक"],"explanation":"एक DOT फिजिकल 24 महीने तक के लिए वैध होता है; कोई परीक्षक किसी मेडिकल स्थिति पर निगरानी रखने के लिए छोटी अवधि का सर्टिफिकेट जारी कर सकता है। स्रोत: MDT 'Ten Easy Steps to a CDL,' Step 2; मोंटाना CDL मेडिकल मार्गदर्शन।"},"92":{"q":"MCA 61-5-141 के अंतर्गत, यदि धारक अपनी समाप्ति तिथि तक एक वर्तमान मेडिकल सर्टिफिकेट जमा करने में विफल रहता है तो मोंटाना CDL का क्या होता है?","options":["संपूर्ण चालक लाइसेंस तुरंत रद्द कर दिया जाता है","अगले 4-वर्षीय नवीनीकरण तक कुछ नहीं बदलता","चालक पर जुर्माना लगता है लेकिन पूर्ण CDL विशेषाधिकार बने रहते हैं","MVD वाणिज्यिक लाइसेंस को घटाकर एक बेस (गैर-CDL) लाइसेंस में बदल देता है"],"explanation":"MCA 61-5-141 विभाग को निर्देश देता है कि यदि फाइल में एक वर्तमान सर्टिफिकेट न हो तो CDLIS रिकॉर्ड को 'not certified' के रूप में चिह्नित करे और वाणिज्यिक लाइसेंस को घटाकर एक बेस लाइसेंस में बदल दे। स्रोत: MCA 61-5-141, Self-certification of operation status।"},"93":{"q":"मोंटाना के स्व-प्रमाणन कानून के अंतर्गत, मेडिकल सर्टिफिकेट समाप्त होने के बाद MVD को CDL घटाने के लिए कितने दिनों के भीतर कार्रवाई करनी चाहिए?","options":["10 दिन","30 दिन","60 दिन","90 दिन"],"explanation":"MCA 61-5-141 के अनुसार विभाग को सर्टिफिकेट के अमान्य होने के 10 दिनों के भीतर कार्रवाई करनी होती है ताकि रिकॉर्ड को not certified के रूप में चिह्नित करे, लाइसेंस को घटाए, और चालक को सूचित करे। स्रोत: MCA 61-5-141।"},"94":{"q":"यदि आवेदक ने अभी तक CDL प्राप्त नहीं किया है, तो पास किए गए मोंटाना CDL लिखित ज्ञान परीक्षा परिणाम कितने समय तक वैध रहते हैं?","options":["पास करने की तिथि से छह महीने","पास करने की तिथि से एक वर्ष","पास करने की तिथि से दो वर्ष","पास करने की तिथि से 180 दिन"],"explanation":"मोंटाना ज्ञान-परीक्षा परिणाम पास करने की तिथि से एक वर्ष तक वैध रहते हैं; यदि उस वर्ष के भीतर CDL प्राप्त नहीं किया जाता, तो सभी लिखित परीक्षाएं फिर से देनी होती हैं। स्रोत: MDT 'Ten Easy Steps to a CDL,' Step 4D।"},"95":{"q":"मोंटाना में, CDL लिखित ज्ञान परीक्षा में विफल होने वाला आवेदक वह परीक्षा फिर से कब दे सकता है?","options":["केवल 7-दिन की प्रतीक्षा अवधि के बाद","केवल 14 दिनों के बाद","अगले दिन","केवल 30 दिनों के बाद"],"explanation":"मोंटाना किसी विफल लिखित ज्ञान परीक्षा को अगले दिन फिर से देने की अनुमति देता है। स्रोत: MDT 'Ten Easy Steps to a CDL,' Step 4D।"},"96":{"q":"परीक्षा के दिन, किसी मोंटाना आवेदक के पास स्किल्स टेस्ट के प्री-ट्रिप वाहन निरीक्षण भाग को पूरा करने के लिए कितना समय होता है?","options":["30 मिनट","60 मिनट","20 मिनट","45 मिनट"],"explanation":"मोंटाना परीक्षा के दिन प्री-ट्रिप निरीक्षण पूरा करने के लिए 45 मिनट आवंटित करता है; ब्रेक जांच अनुचित तरीके से करने पर विफलता होती है। स्रोत: MDT 'Ten Easy Steps to a CDL,' Step 6A।"},"97":{"q":"मोंटाना में एक CDL आवेदक जो पहले से ही एक मानक मोंटाना (गैर-CDL) चालक लाइसेंस रखता है, उसे फिर भी अपॉइंटमेंट पर निम्नलिखित में से कौन सा प्रस्तुत करना होगा?","options":["हर बार एक नया जन्म प्रमाणपत्र","फिर से मोंटाना निवास का प्रमाण","एक वैध DOT फिजिकल (मेडिकल एग्ज़ामिनर) सर्टिफिकेट","एक मोंटाना हाईवे पेट्रोल क्लीयरेंस फॉर्म"],"explanation":"जो आवेदक पहले से ही एक मोंटाना मानक लाइसेंस रखते हैं, उन्हें सोशल सिक्योरिटी नंबर का प्रमाण, अधिकृत उपस्थिति का प्रमाण, और एक वैध DOT फिजिकल (मेडिकल एग्ज़ामिनर) सर्टिफिकेट प्रदान करना होगा; पहचान/निवास का प्रमाण पहले से ही फाइल में था। स्रोत: MDT 'Ten Easy Steps to a CDL,' Required Documents।"},"98":{"q":"राज्य-आंतरिक (केवल मोंटाना) वाणिज्यिक ड्राइविंग बनाम अंतरराज्यीय ड्राइविंग के लिए मोंटाना CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["राज्य-आंतरिक के लिए 21 और अंतरराज्यीय के लिए 25","राज्य-आंतरिक और अंतरराज्यीय दोनों के लिए 18","राज्य-आंतरिक के लिए 16 और अंतरराज्यीय के लिए 18","राज्य-आंतरिक के लिए 18 और अंतरराज्यीय के लिए 21"],"explanation":"मोंटाना के अनुसार आवेदक को मोंटाना के भीतर (राज्य-आंतरिक) वाणिज्यिक वाहन चलाने के लिए कम से कम 18 वर्ष का और अंतरराज्यीय चलाने के लिए कम से कम 21 वर्ष का होना चाहिए। स्रोत: मोंटाना CDL मैनुअल; मोंटाना MVD CDL आवश्यकताएं।"}},"ar":{"0":{"q":"على الطرق السريعة في مونتانا، ما هو الحد الأقصى القانوني لعرض المركبة التجارية وحمولتها بدون تصريح للحجم الزائد؟","options":["8 أقدام و0 بوصة (96 بوصة)","9 أقدام و0 بوصة (108 بوصة)","10 أقدام و0 بوصة (120 بوصة)","8 أقدام و6 بوصات (102 بوصة)"],"explanation":"تحدّ مونتانا إجمالي عرض المركبة الخارجي بـ 102 بوصة (8 أقدام و6 بوصات)، وفقاً للمادة MCA 61-10-102 ودليل السائق الخاص بحجم ووزن وسلامة المركبات التجارية في مونتانا ('الأبعاد القانونية'). تتطلب الحمولات الأعرض من ذلك تصريحاً."},"1":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة، فارغة أو محمّلة، على الطرق السريعة في مونتانا؟","options":["13 قدماً و6 بوصات","14 قدماً","15 قدماً","15 قدماً و6 بوصات"],"explanation":"بموجب المادة MCA 61-10-103 ودليل السائق في مونتانا، لا يجوز أن يتجاوز ارتفاع المركبة (فارغة أو محمّلة) 14 قدماً. وتتطلب الارتفاعات الأكبر تصريحاً للأبعاد الزائدة."},"2":{"q":"بدون تصريح، ما هو الحد الأقصى لطول المقطورة النصفية في تركيبة الجرار الشاحن والمقطورة النصفية في مونتانا؟","options":["48 قدماً","57 قدماً","53 قدماً","60 قدماً"],"explanation":"تحدّد المادة MCA 61-10-104 ودليل السائق في مونتانا الحد الأقصى لطول المقطورة النصفية بـ 53 قدماً (باستثناء الأجزاء غير المصممة لحمل الحمولة). ويمكن لتصريح المدة تمديد ذلك إلى 57 قدماً بموجب المادة MCA 61-10-124."},"3":{"q":"في مونتانا، ما هو الحد الأقصى للوزن الإجمالي المسموح به على محور مفرد بدون تصريح للوزن الزائد؟","options":["20,000 رطل","18,000 رطل","22,400 رطل","34,000 رطل"],"explanation":"وفقاً للمادة MCA 61-10-107 ودليل السائق في مونتانا، لا يجوز أن يتجاوز الوزن الإجمالي على محور واحد أو أكثر تبعد مراكزها عن بعضها بما لا يزيد عن 40 بوصة 20,000 رطل. ويتطابق هذا مع الحد الفيدرالي للمحور المفرد على الطرق السريعة البينولايات."},"4":{"q":"ما هو الحد الأقصى للوزن الإجمالي المسموح به على مجموعة المحاور المزدوجة (الترادفية) في مونتانا بدون تصريح للوزن الزائد؟","options":["32,000 رطل","34,000 رطل","36,000 رطل","40,000 رطل"],"explanation":"تنص المادة MCA 61-10-107 ودليل السائق في مونتانا على أنه لا يجوز لأي محورين متتاليين تبعد مراكزهما عن بعضها بأكثر من 40 بوصة ولكن أقل من 96 بوصة أن يحملا حمولة تتجاوز 34,000 رطل."},"5":{"q":"كيف تعرّف مونتانا 'المحور المزدوج (الترادفي)' لأغراض حدود الوزن؟","options":["محوران تبعد مراكزهما تماماً 40 بوصة","محوران متتاليان تبعد مراكزهما بأكثر من 40 بوصة وأقل من 96 بوصة","أي محورين ضمن مسافة 120 بوصة من بعضهما","محوران تبعد مراكزهما بأكثر من 96 بوصة"],"explanation":"تعرّف المادة MCA 61-10-107 (المذكورة في دليل السائق في مونتانا) المحور المزدوج بأنه محوران متتاليان تبعد مراكزهما بأكثر من 40 بوصة ولكن أقل من 96 بوصة؛ وتقتصر هذه المجموعة على 34,000 رطل."},"6":{"q":"ما هي معادلة الجسر في مونتانا المستخدمة لحساب الحد الأقصى المسموح به للوزن الإجمالي على مجموعة من المحاور؟","options":["W = 1000((LN/(N+1)) + 10N + 20)","W = 250((LN/(N-1)) + 6N + 18)","W = 500((LN/(N+1)) + 12N + 12)","W = 500((LN/(N-1)) + 12N + 36)"],"explanation":"معادلة الجسر في مونتانا (المطابقة لمعادلة الجسر الفيدرالية B) هي W = 500((LN/(N-1)) + 12N + 36)، حيث L هي المسافة بالأقدام بين المحاور الخارجية للمجموعة وN هو عدد المحاور، وفقاً للمادة MCA 61-10-107 ودليل السائق في مونتانا."},"7":{"q":"في مونتانا، متى تتجاوز حدود وزن المحور المفرد والمزدوج (وتحلّ محلها) نتيجة معادلة الجسر؟","options":["لجميع المحاور التي تبعد عن بعضها بأكثر من 120 بوصة","فقط على نظام الطرق السريعة البينولايات","لجميع المحاور التي لا تبعد عن بعضها بأكثر من 96 بوصة","أبداً؛ فمعادلة الجسر هي الحاكمة دائماً"],"explanation":"يوضّح دليل السائق في مونتانا أن حدود وزن المحور المفرد أو المزدوج تحلّ محل حدود معادلة الجسر لجميع المحاور التي لا تبعد عن بعضها بأكثر من 96 بوصة (المادة MCA 61-10-107)."},"8":{"q":"ما هو الحد الأقصى للوزن الإجمالي الذي تسمح به مونتانا لتركيبة مركبة تنقل حمولات قابلة للتقسيم؟","options":["80,000 رطل","105,500 رطل","131,060 رطل","129,000 رطل"],"explanation":"وفقاً للمادة MCA 61-10-107 وجدول الوزن الإجمالي للمركبة في دليل السائق في مونتانا، فإن الحد الأقصى للوزن الإجمالي للحمولات القابلة للتقسيم هو 131,060 رطل."},"9":{"q":"كيف تُحدّ أوزان المحور التوجيهي (الأمامي) بموجب قواعد مونتانا؟","options":["بالسعة المقدّرة من قبل الشركة المصنعة للإطار، بحيث لا تتجاوز 20,000 رطل","بـ 12,000 رطل بالضبط في جميع الحالات","بـ 34,000 رطل مثل المحور المزدوج","لا يوجد حد على المحور التوجيهي"],"explanation":"يشير دليل السائق في مونتانا إلى أن المحاور التوجيهية تقتصر على السعة المقدّرة من قبل الشركة المصنعة والمطبوعة على الجدار الجانبي للإطار، بحيث لا تتجاوز 20,000 رطل (المادة MCA 61-10-107)."},"10":{"q":"بدون تصريح، ما هو الحد الأقصى للطول الإجمالي لتركيبات المركبات غير المحددة بخلاف ذلك على الطرق السريعة في مونتانا؟","options":["65 قدماً","75 قدماً","80 قدماً","70 قدماً"],"explanation":"تحدّ المادة MCA 61-10-104 ودليل السائق في مونتانا هذه التركيبات بـ 75 قدماً إجمالاً (باستثناء التركيبات المسموح لها بطول أكبر، مثل الجرارات التي تسحب مقطورة بطول 53 قدماً، والتي ليس لها حد للطول الإجمالي)."},"11":{"q":"جرار يسحب مقطورة مفردة بطول 53 قدماً (أو أقصر) في مونتانا يخضع لأي قاعدة طول؟","options":["يجب أن يبقى ضمن 65 قدماً إجمالاً","يتطلب دائماً تصريح رحلة واحدة","لا يلزم أي تصريح للطول الإجمالي بغض النظر عن الطول الكلي","يقتصر على 70 قدماً إجمالاً"],"explanation":"ينص دليل السائق في مونتانا على أنه لا يلزم أي تصريح للطول الزائد لجرار يسحب مقطورة بطول 53 قدماً (أو أقصر)، بغض النظر عن الطول الإجمالي للتركيبة (المادة MCA 61-10-104)."},"12":{"q":"أي قسم في وكالة مونتانا يُصدر تصاريح الحجم الزائد والوزن الزائد ورسوم الوزن الإجمالي للمركبة للمركبات التجارية؟","options":["مكتب الترخيص في دورية الطرق السريعة في مونتانا","قسم التصاريح بشعبة خدمات الناقل البري (MCS) التابعة لإدارة النقل في مونتانا (MDT)","مكتب عمدة المقاطعة","الإدارة الفيدرالية لسلامة الناقلين البريين"],"explanation":"وفقاً لدليل السائق في مونتانا، يُصدر قسم التصاريح بشعبة خدمات الناقل البري (MCS) التابعة لإدارة النقل في مونتانا تصاريح الحجم/الوزن؛ ويجوز للناقلين أيضاً إصدارها ذاتياً عبر الإنترنت (ePART / eTRIPS)."},"13":{"q":"حمولة ذات أبعاد زائدة لرحلة واحدة فقط وغير مرخّصة في مونتانا تتطلب أي نوع من التصاريح؟","options":["تصريح مدة دائم فقط","تصريح حصّادة مخصص","لا يلزم تصريح، لأنها نقلة لمرة واحدة","تصريح أبعاد زائدة لرحلة واحدة، يصبح لاغياً عند مغادرة الولاية"],"explanation":"ينص دليل السائق في مونتانا على أن المشغّلين على أساس رحلة مؤقتة يجب أن يحصلوا على تصريح أبعاد زائدة لرحلة واحدة (للحمولات التي يزيد عرضها عن 8'6\"، أو ارتفاعها عن 14'، أو طولها عن 75'، أو الوحدة المفردة التي يزيد طولها عن 55')؛ ويصبح التصريح لاغياً عند مغادرة الولاية."},"14":{"q":"ما هو الحد الأدنى لتأمين المسؤولية الذي تشترطه مونتانا لإصدار تصريح (خاص) للحجم الزائد/الوزن الزائد؟","options":["$300,000 كحد مفرد مجمّع","$500,000 كحد مفرد مجمّع","$1,000,000 كحد مفرد مجمّع لكل حادثة","$750,000 كحد مفرد مجمّع"],"explanation":"تحدّد المتطلبات العامة لتصريح الحجم الزائد في دليل السائق في مونتانا حداً أدنى قدره $1,000,000 كحد مفرد مجمّع للمسؤولية عن الإصابة الجسدية والأضرار في الممتلكات لكل حادثة."},"15":{"q":"تصريح مدة الوزن الشتوي في مونتانا يسمح بكم من الوزن الزائد، وعلى أي الطرق؟","options":["10% زيادة على الطرق السريعة غير البينولايات، من 1 ديسمبر حتى 7 مارس","20% زيادة على جميع الطرق السريعة، طوال العام","10% زيادة على الطرق السريعة البينولايات فقط","15% زيادة على الطرق السريعة غير البينولايات، من 1 نوفمبر حتى 1 أبريل"],"explanation":"ينص دليل السائق في مونتانا على أن تصريح مدة الوزن الشتوي يسمح بزيادة 10% في الوزن على الطرق السريعة غير البينولايات من 1 ديسمبر حتى 7 مارس، ويمكن تعليقه أثناء الذوبان المبكر."},"16":{"q":"يجوز لعملية حصاد مخصصة لغير المقيمين في مونتانا أن تدفع رسم تصريح خاص بدلاً من رسوم الوزن الإجمالي وتصاريح الحجم الزائد بكم لكل وحدة؟","options":["$20 لكل وحدة","$35 لكل وحدة","$105 لكل وحدة","$40 لكل وحدة"],"explanation":"بموجب المادتين MCA 15-24-301 و61-10-130 (والمادة ARM 18.8.426)، ينص دليل السائق في مونتانا على أنه يجوز لعملية الحصاد المخصصة لغير المقيمين أن تدفع رسم تصريح خاص قدره $40 لكل وحدة (يدفع المقيمون 35% من رسوم الوزن الإجمالي بالإضافة إلى $20 لكل وحدة)."},"17":{"q":"على نظام الطرق السريعة البينولايات في مونتانا، ما هو الحد الفيدرالي لوزن المحور المفرد الذي ينطبق أيضاً في مونتانا؟","options":["20,000 رطل","18,000 رطل","21,000 رطل","24,000 رطل"],"explanation":"يشير دليل السائق في مونتانا صراحةً إلى أن الحد الفيدرالي لوزن المحور المفرد على نظام الطرق السريعة البينولايات هو 20,000 رطل، بما يتوافق مع الحد العام للمحور المفرد في مونتانا بموجب المادة MCA 61-10-107."},"18":{"q":"لنقل التبن أو القش العرضي للزراعة، تسمح مونتانا بارتفاع للمركبة حتى أي حد أقصى، وضمن أي مسافة؟","options":["15 قدماً و6 بوصات، لمسافة لا تزيد عن 25 ميلاً","16 قدماً، لمسافة لا تزيد عن 50 ميلاً","14 قدماً و6 بوصات، لمسافة لا تزيد عن 10 أميال","15 قدماً، لمسافة لا تزيد عن 100 ميل"],"explanation":"تنص المادة MCA 61-10-103 على استثناء زراعي: يجوز أن يصل ارتفاع أداة زراعية أو مركبة تنقل التبن أو القش إلى 15 قدماً و6 بوصات إذا كانت تسير لمسافة لا تزيد عن 25 ميلاً بشكل عرضي للزراعة ولا تمرّ تحت عوائق ارتفاعها 17 قدماً أو أقل."},"19":{"q":"حمولة غير قابلة للتقسيم تتجاوز حد معادلة الجسر ولكنها لا تتجاوز أوزان المحور القانونية تُحتسب لها رسوم تصريح في مونتانا على أساس ماذا؟","options":["رسم سنوي ثابت قدره $200 بغض النظر عن المسافة","الوزن الإجمالي المسجّل للمركبة فقط","10% من قيمة الحمولة","مسافة الرحلة بالأميال (مثلاً، $10 حتى 100 ميل، $30 لـ 101-199، $50 لـ 200 ميل فأكثر)"],"explanation":"يحتسب دليل السائق في مونتانا ('الوزن الزائد على الجسر - أوزان المحور القانونية - الحمولات غير القابلة للتقسيم'، المادة MCA 61-10-107) رسماً قدره $10 حتى 100 ميل، و$30 لـ 101-199 ميلاً، و$50 لـ 200 ميل فأكثر."},"20":{"q":"في مونتانا، أي فئة CDL مطلوبة لتشغيل تركيبة من المركبات بتصنيف وزن تركيبي إجمالي (GCWR) يبلغ 26,001 رطل أو أكثر، عندما تتجاوز الوحدة/الوحدات المقطورة 10,000 رطل؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"وفقاً لدليل CDL في مونتانا (التصنيفات، MT-2)، فإن مركبة الفئة A التركيبية لها تصنيف وزن تركيبي إجمالي (GCWR) قدره 11,794 كجم (26,001 رطل) أو أكثر شريطة أن تتجاوز الوحدة/الوحدات المقطورة 4,536 كجم (10,000 رطل). المصدر: دليل CDL في مونتانا، مراجعة يونيو 2026 (MVD/DOJ)."},"21":{"q":"مركبة مستقيمة 'ثقيلة جداً' مفردة في مونتانا بتصنيف وزن إجمالي للمركبة (GVWR) قدره 26,001 رطل أو أكثر ولا تقطر شيئاً يزيد عن 10,000 رطل تتطلب أي فئة CDL؟","options":["الفئة A","الفئة B","الفئة C","الفئة M"],"explanation":"يعرّف دليل CDL في مونتانا (التصنيفات، MT-2) الفئة B بأنها أي مركبة مفردة بتصنيف وزن إجمالي (GVWR) قدره 26,001 رطل أو أكثر، أو هذه المركبة وهي تقطر وحدة لا تزيد عن 10,000 رطل. المصدر: دليل CDL في مونتانا، مراجعة يونيو 2026 (MVD/DOJ)."},"22":{"q":"في مونتانا، مركبة لا تستوفي تعريفات وزن الفئة A أو B ولكنها مصممة لنقل 16 راكباً أو أكثر (بما في ذلك السائق) أو تُستخدم لنقل مواد خطرة تتطلب لافتات تحذيرية تتطلب أي فئة CDL؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"يعرّف دليل CDL في مونتانا (التصنيفات، MT-2) الفئة C بأنها مركبة مفردة أو تركيبة لا تستوفي الفئة A ولا B ولكنها مصممة لحمل 16 راكباً أو أكثر بما في ذلك السائق، أو تُستخدم لنقل مواد خطرة تتطلب لافتات تحذيرية. المصدر: دليل CDL في مونتانا، مراجعة يونيو 2026 (MVD/DOJ)."},"23":{"q":"بموجب قواعد CDL في مونتانا، ما هو الحد الأدنى لعدد الركاب (بما في ذلك السائق) الذي يجب أن تكون المركبة مصممة لحمله قبل أن يصبح تظهير الركاب (P) مطلوباً؟","options":["8 ركاب","10 ركاب","15 راكباً","16 راكباً"],"explanation":"ينص دليل CDL في مونتانا (MT-3) على أن تظهير مركبة الركاب (P) مطلوب لمركبات الفئة A أو B أو C المصممة لنقل 16 راكباً أو أكثر بما في ذلك السائق. المصدر: دليل CDL في مونتانا، مراجعة يونيو 2026 (MVD/DOJ)."},"24":{"q":"أي تظهير CDL في مونتانا مطلوب لتشغيل مركبة تجارية تسحب مقطورات مزدوجة أو ثلاثية؟","options":["تظهير N","تظهير T","تظهير X","تظهير H"],"explanation":"ينص دليل CDL في مونتانا (MT-2/MT-3) على أن تظهير المقطورات المزدوجة/الثلاثية (T) مطلوب للسائقين الذين يسحبون مقطورات مزدوجة أو ثلاثية في الفئة A أو B. المصدر: دليل CDL في مونتانا، مراجعة يونيو 2026 (MVD/DOJ)."},"25":{"q":"وفقاً لدليل CDL في مونتانا، يكون تظهير الصهريج (N) مطلوباً عند نقل مواد سائلة أو غازية في صهريج تبلغ سعته المقدّرة على الأقل كم؟","options":["119 جالوناً","500 جالون","1,000 جالون","3,500 جالون"],"explanation":"يعرّف دليل CDL في مونتانا (MT-3) تظهير مركبة الصهريج (N) بأنه مطلوب لصهريج بسعة مقدّرة قدرها 1,000 جالون أو أكثر، أو لعدة صهاريج بسعة مقدّرة إجمالية قدرها 1,000 جالون. المصدر: دليل CDL في مونتانا، مراجعة يونيو 2026 (MVD/DOJ)."},"26":{"q":"ما هو الحد الأدنى للعمر للتقدم بطلب للحصول على رخصة قيادة تجارية ضمن الولاية (داخل مونتانا فقط)؟","options":["16 عاماً","18 عاماً","19 عاماً","21 عاماً"],"explanation":"ينص دليل CDL في مونتانا (الحد الأدنى لأعمار السائقين، MT-3) على أن المتقدم ضمن الولاية (مونتانا فقط) يجب أن يستوفي مؤهلات مونتانا وأن يكون عمره 18 عاماً على الأقل. المصدر: دليل CDL في مونتانا، مراجعة يونيو 2026 (MVD/DOJ)."},"27":{"q":"ما هو الحد الأدنى للعمر للتقدم بطلب للحصول على رخصة قيادة تجارية بين الولايات في مونتانا؟","options":["18 عاماً","19 عاماً","21 عاماً","25 عاماً"],"explanation":"ينص دليل CDL في مونتانا (الحد الأدنى لأعمار السائقين، MT-3) على أنه للتقدم بطلب رخصة بين الولايات يجب أن يكون عمرك 21 عاماً على الأقل وقادراً على استيفاء مؤهلات الحصول على CDL. المصدر: دليل CDL في مونتانا، مراجعة يونيو 2026 (MVD/DOJ)."},"28":{"q":"قبل إجراء اختبار مهارات CDL (ما قبل الرحلة، والتحكم الأساسي، والطريق) في مونتانا، يجب الاحتفاظ بتصريح المتعلّم التجاري لمدة لا تقل عن كم؟","options":["7 أيام","10 أيام","14 يوماً","30 يوماً"],"explanation":"ينص دليل CDL في مونتانا (تعريف CLP، MT-2) على أنه يجب الاحتفاظ بجميع تصاريح CLP لمدة لا تقل عن 14 يوماً قبل إجراء اختبار ما قبل الرحلة والمهارات الأساسية والطريق (يجوز للسائق الاختبار في اليوم الخامس عشر). ويعكس ذلك قاعدة CLP الفيدرالية. المصدر: دليل CDL في مونتانا، مراجعة يونيو 2026 (MVD/DOJ)؛ 49 CFR 383.25."},"29":{"q":"قبل إصدار CDL في مونتانا بتظهير مواد خطرة (H)، أو تجديده، أو نقله، يقتضي القانون الفيدرالي من السائق اجتياز أي فحص؟","options":["اختبار مخدرات وكحول DOT فقط","تقييم تهديد أمني من TSA (فحص خلفية يستند إلى البصمات)","اختبار جهاز كشف الكذب من FBI","فحص بصر وردود فعل على مستوى الولاية"],"explanation":"ينص دليل CDL في مونتانا (المواد الخطرة، MT-2) على أنه امتثالاً للقانون الفيدرالي، يجب على السائقين الراغبين في الحصول على تظهير HazMat أو نقله أو تجديده أن يكملوا أولاً تقييم تهديد أمني (STA) تجريه TSA، بما في ذلك أخذ البصمات وفحص الخلفية الجنائية. المصدر: دليل CDL في مونتانا، مراجعة يونيو 2026 (MVD/DOJ)؛ 49 CFR 1572."},"30":{"q":"السائق في مونتانا الذي أكمل تقييم تهديد أمني من TSA لتظهير HazMat لا يُطلب منه عموماً إكمال تقييم آخر عند التجديد أو النقل إذا تم التقييم السابق خلال آخر كم عاماً؟","options":["سنة واحدة","سنتان","5 سنوات","7 سنوات"],"explanation":"ينص دليل CDL في مونتانا (MT-2) على أن أولئك الذين سبق أن خضعوا لتقييم تهديد أمني خلال السنتين الماضيتين من التقدم بطلب لتجديد CDL أو نقله قد لا يُطلب منهم إكمال تقييم STA آخر. المصدر: دليل CDL في مونتانا، مراجعة يونيو 2026 (MVD/DOJ)."},"31":{"q":"بموجب قواعد تدريب السائقين المبتدئين (ELDT) الفيدرالية المعتمدة في مونتانا، يجب على المتقدم لأول مرة إكمال ELDT من مزوّد مُدرج أين قبل الاختبار؟","options":["قائمة متعاقدي إدارة النقل في مونتانا","سجل مزوّدي التدريب التابع لـ FMCSA (TPR)","دليل مدارس السائقين التابع لـ AAMVA","أي مدرسة مهنية معتمدة من الولاية"],"explanation":"يقتضي ELDT تدريباً من مزوّد مُدرج في سجل مزوّدي التدريب التابع لـ FMCSA (TPR). وتشير مونتانا إلى هذا المتطلب في دليل CDL الخاص بها (MT-2). المصدر: قاعدة ELDT التابعة لـ FMCSA (49 CFR 380، سارية من 7 فبراير 2022)؛ دليل CDL في مونتانا، مراجعة يونيو 2026 (MVD/DOJ)."},"32":{"q":"تنطبق متطلبات ELDT الفيدرالية على المتقدمين لأول مرة للحصول على CDL من الفئة A أو B وعلى المتقدمين لأول مرة لأي مجموعة من التظهيرات؟","options":["N (الصهريج) وT (المزدوجة/الثلاثية)","P (الركاب)، وS (الحافلة المدرسية)، وH (المواد الخطرة)","T (المزدوجة/الثلاثية) وS (الحافلة المدرسية) فقط","فقط H (المواد الخطرة)"],"explanation":"بموجب قاعدة ELDT التابعة لـ FMCSA (سارية من 7 فبراير 2022)، يلزم التدريب للحصول لأول مرة على رخص CDL من الفئة A/B وللتظهيرات لأول مرة الخاصة بالركاب (P)، والحافلة المدرسية (S)، والمواد الخطرة (H). وقد اعتمدت مونتانا هذه المتطلبات (دليل CDL، MT-2/MT-3). المصدر: 49 CFR 380؛ دليل CDL في مونتانا، مراجعة يونيو 2026 (MVD/DOJ)."},"33":{"q":"أي مما يلي يُعدّ إحدى فئات التصديق الذاتي الأربع التي يجب على المتقدم لـ CDL في مونتانا اختيارها للإشارة إلى نوع التجارة التي يعمل بها؟","options":["بين الولايات غير المستثنى","ناقل متعاقد فيدرالي","ترفيهي بين الولايات","إعفاء تجاري محدود"],"explanation":"يدرج دليل CDL في مونتانا (التصديق الذاتي، MT-3) الفئات الأربع بأنها: بين الولايات غير المستثنى، وبين الولايات المستثنى، وضمن الولاية غير المستثنى، وضمن الولاية المستثنى. المصدر: دليل CDL في مونتانا، مراجعة يونيو 2026 (MVD/DOJ)؛ 49 CFR 383.71."},"34":{"q":"المتقدم لـ CDL في مونتانا الذي يصدّق ذاتياً بأنه 'بين الولايات غير مستثنى' يدلي بأي تصريح بشأن المتطلبات الطبية؟","options":["أنه معفى من حمل شهادة فاحص طبي","أنه يجب أن يستوفي المتطلبات الطبية الفيدرالية (MEC)","أنه يحتاج فقط إلى إعفاء طبي ضمن ولاية مونتانا","أنه لا يحتاج إلى أي تصديق طبي على الإطلاق"],"explanation":"ينص دليل CDL في مونتانا (التصديق الذاتي، MT-3) على أن السائق بين الولايات غير المستثنى يجب أن يستوفي متطلبات شهادة الفاحص الطبي الفيدرالية (MEC). المصدر: دليل CDL في مونتانا، مراجعة يونيو 2026 (MVD/DOJ)؛ 49 CFR 383.71."},"35":{"q":"يجب على جميع المتقدمين للحصول على رخصة قيادة تجارية في مونتانا تقديم وثائق من كم فئة مميزة من الإثبات؟","options":["اثنتان: الهوية والإقامة","ثلاث: الوجود المصرّح به، والهوية، والإقامة في مونتانا","أربع: الهوية، والإقامة، وبطاقة الضمان الاجتماعي، والجنسية","واحدة: وثيقة واحدة متوافقة مع REAL ID"],"explanation":"يقتضي دليل CDL في مونتانا (إثبات الوجود المصرّح به والهوية والإقامة، MT-7/MT-8) تقديم وثائق من ثلاث فئات: إثبات الوجود المصرّح به، وإثبات الهوية، وإثبات الإقامة في مونتانا. المصدر: دليل CDL في مونتانا، مراجعة يونيو 2026 (MVD/DOJ)."},"36":{"q":"فيما يتعلق برقم الضمان الاجتماعي في طلب CDL في مونتانا، ماذا تشترط الولاية؟","options":["يجب أن يتطابق رقم الضمان الاجتماعي مع الرقم المسجّل لدى إدارة الضمان الاجتماعي","لا يلزم رقم ضمان اجتماعي أبداً للحصول على CDL","يُسجّل فقط آخر أربعة أرقام ولا يتم التحقق منها أبداً","إقرار موثّق يحلّ محل رقم الضمان الاجتماعي"],"explanation":"ينص دليل CDL في مونتانا (إثبات رقم الضمان الاجتماعي وتأكيد الهوية، MT-2) على أن الاسم وتاريخ الميلاد ورقم الضمان الاجتماعي المستخدمة في طلب CDL يجب أن تتطابق مع ما هو مسجّل لدى إدارة الضمان الاجتماعي، ويتم التحقق من رقم الضمان الاجتماعي مع الإدارة. المصدر: دليل CDL في مونتانا، مراجعة يونيو 2026 (MVD/DOJ)؛ FMCSR 383.153."},"37":{"q":"إذا واصل سائق تجاري في مونتانا القيادة بعد وضعه خارج الخدمة، فإن أول مخالفة من هذا النوع تؤدي إلى تعليق CDL لمدة كم؟","options":["30 يوماً","90 يوماً","6 أشهر","3 سنوات"],"explanation":"ينص دليل CDL في مونتانا (إسقاط أهلية السائق، MT-5) على أنه إذا قدت بعد وضعك خارج الخدمة، فسيتم تعليق CDL الخاص بك لمدة ستة أشهر للمخالفة الأولى (ولمدة أطول للمخالفات اللاحقة). المصدر: دليل CDL في مونتانا، مراجعة يونيو 2026 (MVD/DOJ)؛ 49 CFR 383.51."},"38":{"q":"رخصة CDL الموسمية المقيّدة في مونتانا لموظفي الخدمات المرتبطة بالزراعة المؤهلين صالحة خلال أي نافذة موسمية في كل سنة تقويمية؟","options":["من 1 يناير حتى 30 يونيو","من 15 مارس حتى 10 سبتمبر","من 1 أبريل حتى 1 أكتوبر","من 1 مايو حتى 30 نوفمبر"],"explanation":"ينص دليل CDL في مونتانا (CDL الموسمية المقيّدة، MT-5) على أن CDL الموسمية صالحة فقط للفترة من 15 مارس حتى 10 سبتمبر من السنة التقويمية وتسمح بالتشغيل ضمن نطاق 150 ميلاً من مكان العمل أو المزرعة. المصدر: دليل CDL في مونتانا، مراجعة يونيو 2026 (MVD/DOJ)."},"39":{"q":"في مونتانا، ما هو تركيز الكحول في الدم (BAC) الذي يُعتبر عنده أو فوقه الشخص قائداً لمركبة تجارية آلية (CMV) بشكل غير قانوني؟","options":["0.08","0.04","0.02","0.10"],"explanation":"تتبع مونتانا المعيار الفيدرالي للمركبات التجارية: قيادة مركبة تجارية بتركيز كحول قدره 0.04 أو أكثر هي مخالفة كبرى. المصدر: MCA 61-8-802 ودليل CDL في مونتانا (القسم 1، إسقاط الأهلية)؛ 49 CFR 383.51."},"40":{"q":"بموجب قانون الموافقة الضمنية في مونتانا، يُعتبر السائق بقيادته أي مركبة في الولاية قد وافق مسبقاً على أي مما يلي؟","options":["فحص الدم أو النفس أو البول للكشف عن الكحول أو المخدرات","تفتيش المركبة بدون مذكرة","فحص طبي سنوي","فحص بصر عند كل توقيف مروري"],"explanation":"ينص قانون الموافقة الضمنية في مونتانا على أن أي شخص يقود مركبة في الولاية قد أعطى موافقته على فحص الدم أو النفس أو البول لتحديد تركيز الكحول أو وجود المخدرات. المصدر: قانون الموافقة الضمنية في مونتانا (MCA 61-8-1016، سابقاً 61-8-402) ودليل CDL في مونتانا."},"41":{"q":"يرتكب حامل CDL في مونتانا أول مخالفة كبرى (مثل القيادة تحت تأثير الكحول DUI) أثناء عدم نقل مواد خطرة. لكم من الوقت تُسقط أهلية CDL؟","options":["6 أشهر","سنة واحدة","3 سنوات","60 يوماً"],"explanation":"تؤدي أول مخالفة كبرى إلى إسقاط أهلية CDL لمدة سنة واحدة. المصدر: MCA 61-8-802(1) ودليل CDL في مونتانا؛ 49 CFR 383.51."},"42":{"q":"إذا وقعت أول مخالفة كبرى لحامل CDL في مونتانا أثناء تشغيل مركبة تجارية تنقل مواد خطرة تتطلب لافتات تحذيرية، فإن فترة إسقاط الأهلية تزداد إلى:","options":["سنة واحدة","سنتان","3 سنوات","مدى الحياة"],"explanation":"عندما تقع أول مخالفة كبرى أثناء تشغيل مركبة تجارية تنقل مواد خطرة تتطلب لافتات تحذيرية، يكون إسقاط الأهلية لمدة 3 سنوات بدلاً من سنة واحدة. المصدر: MCA 61-8-802(1) ودليل CDL في مونتانا؛ 49 CFR 383.51."},"43":{"q":"ما هي فترة إسقاط الأهلية في مونتانا للسائق المدان بمخالفة كبرى ثانية (من حادثة منفصلة) خلال حياته؟","options":["3 سنوات","5 سنوات","10 سنوات","مدى الحياة"],"explanation":"تؤدي المخالفة الكبرى الثانية إلى إسقاط الأهلية مدى الحياة، وإن كان يجوز لمونتانا السماح بإعادة الترخيص بموجب القواعد الفيدرالية بعد فترة لا تقل عن 10 سنوات. المصدر: MCA 61-8-802 ودليل CDL في مونتانا؛ 49 CFR 383.51."},"44":{"q":"يُطلب من سائق مركبة تجارية في مونتانا بشكل قانوني الخضوع لاختبار النفس للكشف عن الكحول فيرفض. كيف يُعامل هذا الرفض لأغراض CDL؟","options":["كمخالفة مرورية خطيرة (عقوبة 60 يوماً)","كمخالفة كبرى، بنفس إسقاط الأهلية المترتب على اختبار فاشل","كمسألة إدارية لا يُبلّغ عنها","كمخالفة لأمر الإيقاف عن الخدمة"],"explanation":"رفض اختبار كحول/مخدرات مطلوب بموجب الموافقة الضمنية هو مخالفة كبرى ويحمل نفس إسقاط الأهلية المترتب على الاختبار بنتيجة 0.04 أو أعلى: سنة واحدة (3 سنوات للمواد الخطرة) لأول رفض، ومدى الحياة للرفض الثاني. المصدر: MCA 61-8-802 ودليل CDL في مونتانا؛ 49 CFR 383.51."},"45":{"q":"سائق مركبة تجارية في مونتانا لديه أي كمية قابلة للكشف من الكحول أقل من 0.04 لا تُسقط أهليته، لكن يجب وضعه خارج الخدمة لمدة كم؟","options":["ساعة واحدة","8 ساعات","24 ساعة","72 ساعة"],"explanation":"يجب وضع سائق مركبة تجارية لديه تركيز كحول قابل للكشف أقل من 0.04 خارج الخدمة لمدة 24 ساعة. المصدر: دليل CDL في مونتانا؛ 49 CFR 392.5 / 383.51."},"46":{"q":"أي مما يلي يُصنّف كمخالفة مرورية خطيرة لحامل CDL في مونتانا؟","options":["القيادة بسرعة 15 ميلاً في الساعة أو أكثر فوق الحد الأقصى للسرعة المعلن","أول قيادة تحت تأثير الكحول DUI في مركبة تجارية","رفض اختبار الكحول","القيادة أثناء تعليق الرخصة بسبب DUI"],"explanation":"الإفراط في السرعة (15 ميلاً في الساعة أو أكثر فوق الحد) هو مخالفة مرورية خطيرة. أما DUI ورفض الاختبار فهما مخالفتان كبريان، وليستا مخالفتين خطيرتين. المصدر: دليل CDL في مونتانا (إسقاط الأهلية)؛ 49 CFR 383.51."},"47":{"q":"كم عدد المخالفات المرورية الخطيرة خلال فترة 3 سنوات التي تؤدي إلى إسقاط أهلية CDL في مونتانا لمدة 60 يوماً؟","options":["واحدة","اثنتان","ثلاث","أربع"],"explanation":"تؤدي المخالفة المرورية الخطيرة الثانية خلال فترة 3 سنوات إلى إسقاط الأهلية لمدة 60 يوماً. المصدر: دليل CDL في مونتانا؛ 49 CFR 383.51."},"48":{"q":"يُدان حامل CDL في مونتانا بثلاث مخالفات مرورية خطيرة خلال فترة 3 سنوات. ما هو الحد الأدنى لإسقاط الأهلية؟","options":["60 يوماً","90 يوماً","120 يوماً","180 يوماً"],"explanation":"تؤدي ثلاث مخالفات مرورية خطيرة في فترة 3 سنوات إلى إسقاط الأهلية لمدة 120 يوماً. المصدر: دليل CDL في مونتانا؛ 49 CFR 383.51."},"49":{"q":"أي من هذه لا يُحتسب كمخالفة مرورية خطيرة لحامل CDL في مونتانا؟","options":["القيادة بمسافة قريبة جداً","تغيير الحارات بشكل غير سليم أو متقطع","القيادة المتهورة","القيادة بسرعة 5 أميال في الساعة فوق الحد الأقصى للسرعة"],"explanation":"تشمل المخالفات الخطيرة القيادة المتهورة، وتغيير الحارات بشكل غير سليم/متقطع، والقيادة بمسافة قريبة جداً، والسرعة الزائدة بمقدار 15 ميلاً في الساعة أو أكثر فوق الحد. أما السرعة البسيطة الزائدة (مثل 5 أميال في الساعة فوق الحد) فليست مخالفة خطيرة. المصدر: دليل CDL في مونتانا؛ 49 CFR 383.51."},"50":{"q":"استخدام هاتف محمول يدوي أثناء قيادة مركبة تجارية يُصنّف، لأغراض CDL في مونتانا، كأي نوع من المخالفات؟","options":["مخالفة كبرى","مخالفة مرورية خطيرة","مخالفة للإيقاف عن الخدمة","مخالفة لمعبر السكة الحديدية"],"explanation":"استخدام هاتف محمول يدوي أثناء قيادة مركبة تجارية هو مخالفة مرورية خطيرة بموجب القاعدة الفيدرالية المطبّقة في مونتانا. المصدر: دليل CDL في مونتانا؛ 49 CFR 392.82 و383.51."},"51":{"q":"الرسائل النصية أثناء قيادة مركبة تجارية محظورة على سائقي CDL في مونتانا. الإدانة الثانية بإرسال الرسائل النصية/استخدام الهاتف اليدوي خلال 3 سنوات تؤدي إلى أي إسقاط للأهلية؟","options":["لا إسقاط للأهلية","60 يوماً","120 يوماً","سنة واحدة"],"explanation":"إرسال الرسائل النصية/استخدام الهاتف اليدوي مخالفة خطيرة. لا تحمل الإدانة الأولى إسقاطاً للأهلية، لكن الإدانة الثانية خلال 3 سنوات تؤدي إلى إسقاط الأهلية لمدة 60 يوماً (120 يوماً للثالثة). المصدر: دليل CDL في مونتانا؛ 49 CFR 392.80/392.82 و383.51."},"52":{"q":"ما هو الحد الأدنى لإسقاط الأهلية لأول مخالفة لمعبر السكة الحديدية مع الطريق لحامل CDL في مونتانا ارتُكبت أثناء قيادة مركبة تجارية؟","options":["30 يوماً","60 يوماً","120 يوماً","سنة واحدة"],"explanation":"تؤدي أول مخالفة لمعبر السكة الحديدية مع الطريق إلى إسقاط الأهلية لمدة لا تقل عن 60 يوماً. المصدر: دليل CDL في مونتانا؛ 49 CFR 383.51."},"53":{"q":"للمخالفة الثانية لمعبر السكة الحديدية خلال فترة 3 سنوات، تُسقط أهلية CDL في مونتانا لمدة لا تقل عن:","options":["60 يوماً","120 يوماً","180 يوماً","سنة واحدة"],"explanation":"تؤدي المخالفة الثانية لمعبر السكة الحديدية في فترة 3 سنوات إلى إسقاط الأهلية لمدة لا تقل عن 120 يوماً. المصدر: دليل CDL في مونتانا؛ 49 CFR 383.51."},"54":{"q":"المخالفة الثالثة لمعبر السكة الحديدية خلال فترة 3 سنوات تُسقط أهلية CDL في مونتانا لمدة لا تقل عن:","options":["120 يوماً","180 يوماً","سنة واحدة","3 سنوات"],"explanation":"تؤدي المخالفة الثالثة لمعبر السكة الحديدية في فترة 3 سنوات إلى إسقاط الأهلية لمدة لا تقل عن سنة واحدة. المصدر: دليل CDL في مونتانا؛ 49 CFR 383.51."},"55":{"q":"يخالف سائق مركبة تجارية في مونتانا أمر الإيقاف عن الخدمة لأول مرة (دون حمل مواد خطرة أو ركاب). ما هو الحد الأدنى لإسقاط الأهلية؟","options":["30 يوماً","90 يوماً","180 يوماً","سنة واحدة"],"explanation":"تؤدي أول إدانة بمخالفة أمر الإيقاف عن الخدمة إلى إسقاط الأهلية لمدة لا تقل عن 180 يوماً. المصدر: دليل CDL في مونتانا؛ 49 CFR 383.51."},"56":{"q":"ما هو الحد الأدنى لإسقاط الأهلية للمخالفة الثانية لأمر الإيقاف عن الخدمة (حوادث منفصلة) خلال فترة 10 سنوات لحامل CDL في مونتانا؟","options":["180 يوماً","سنة واحدة","سنتان","3 سنوات"],"explanation":"تؤدي المخالفة الثانية لأمر الإيقاف عن الخدمة في حوادث منفصلة خلال 10 سنوات إلى إسقاط الأهلية لمدة لا تقل عن سنتين (3 سنوات للثالثة). المصدر: دليل CDL في مونتانا؛ 49 CFR 383.51."},"57":{"q":"إذا خالف سائق مركبة تجارية في مونتانا أمر الإيقاف عن الخدمة لأول مرة أثناء نقل مواد خطرة تتطلب لافتات تحذيرية أو أثناء تشغيل مركبة مصممة لحمل 16 راكباً أو أكثر، فإن الحد الأدنى لإسقاط الأهلية هو:","options":["60 يوماً","180 يوماً","سنة واحدة","سنتان"],"explanation":"تؤدي أول مخالفة لأمر الإيقاف عن الخدمة أثناء نقل مواد خطرة تتطلب لافتات تحذيرية أو حمل 16 راكباً أو أكثر (بما في ذلك السائق) إلى إسقاط الأهلية لمدة لا تقل عن 180 يوماً، مع ما لا يقل عن 3 سنوات للمخالفة اللاحقة. المصدر: دليل CDL في مونتانا؛ 49 CFR 383.51."},"58":{"q":"حامل رخصة CDL في مونتانا يتلقّى تهمة القيادة تحت تأثير الكحول (DUI) في مركبته الشخصية (غير التجارية). كيف يؤثّر ذلك على رخصته CDL؟","options":["ليس له أي تأثير لأنه لم يكن في مركبة تجارية (CMV)","يُعامَل كمخالفة كبرى ويؤدي إلى إلغاء أهلية رخصة CDL","يضيف نقاطًا فقط دون إلغاء الأهلية","يؤدي فقط إلى أمر إيقاف عن الخدمة لمدة 24 ساعة"],"explanation":"المخالفات الكبرى مثل القيادة تحت تأثير الكحول (DUI) تُلغي أهلية رخصة CDL حتى عند ارتكابها في مركبة شخصية؛ المخالفة الأولى تعني فقدان الأهلية لمدة سنة واحدة. المصدر: MCA 61-8-802 ودليل CDL في مونتانا؛ 49 CFR 383.51."},"59":{"q":"على طريق سريع بين الولايات ممول اتحادياً في مونتانا خارج منطقة حضرية، ما السرعة القصوى التي يجوز قانونياً لشاحنة نصف مقطورة محملة (شاحنة تتجاوز سعتها المقدرة 1 طن) أن تسير بها؟","options":["65 mph في جميع الأوقات","80 mph، مثل السيارات تماماً","70 mph في جميع الأوقات","75 mph نهاراً، 65 mph ليلاً"],"explanation":"تحدد مونتانا حداً منفصلاً للشاحنات: تُقيَّد الشاحنة/الجرار الشاحن الذي تتجاوز سعته المقدرة 1 طن بسرعة 70 mph على الطريق السريع بين الولايات، رغم أن السيارات قد تسير بسرعة 80 mph على الطرق الريفية بين الولايات. المصدر: MCA 61-8-312 (حدود السرعة الخاصة بالشاحنات) و61-8-303؛ رُفع بموجب HB393 (2019)."},"60":{"q":"على طريق عام بمسارين في مونتانا ليس طريقاً بين الولايات، السرعة القصوى لشاحنة تتجاوز سعتها المقدرة 1 طن هي:","options":["70 mph نهاراً، 65 mph ليلاً","60 mph نهاراً، 55 mph ليلاً","65 mph، نهاراً وليلاً","55 mph في جميع الأوقات"],"explanation":"على الطرق السريعة التي ليست بين الولايات، يكون حد الشاحنات ثابتاً عند 65 mph نهاراً وليلاً. أما الأرقام القديمة المقسمة 60 نهاراً/55 ليلاً فقد أُلغيت في عام 2019. المصدر: MCA 61-8-312؛ HB393 (2019)."},"61":{"q":"بموجب قاعدة مونتانا الخاصة بمعابر السكك الحديدية للحافلات ومركبات المواد الخطرة الموسومة باللوحات التي يُطلب منها التوقف، حيث لا يوجد خط توقف مرسوم، يجب على السائق التوقف ضمن أي مسافة من أقرب سكة؟","options":["ليس أقرب من 15 قدماً وليس أبعد من 50 قدماً","ليس أقرب من 10 أقدام وليس أبعد من 40 قدماً","ليس أقرب من 25 قدماً وليس أبعد من 75 قدماً","ليس أقرب من 5 أقدام وليس أبعد من 30 قدماً"],"explanation":"تتبع مونتانا قاعدة الـ 15 إلى 50 قدماً: يجب على المركبات المطلوب منها التوقف أن تقف ليس أقرب من 15 قدماً وليس أبعد من 50 قدماً من أقرب سكة لأقرب مسار. المصدر: دليل CDL في مونتانا، القسم 2.15 (معابر السكك الحديدية مع الطرق)."},"62":{"q":"أي المركبات التجارية يجب أن تتوقف دائماً توقفاً كاملاً عند معبر السكة الحديدية مع الطريق في مونتانا (في غياب إشارة خضراء أو توجيه من الشرطة)؟","options":["جميع المركبات المركبة التي تتجاوز 26,001 رطلاً","فقط تركيبات المقطورات الثلاثية","أي شاحنة مسجلة خارج الولاية","الحافلات الناقلة للركاب والمركبات المطلوب وسمها بلوحات للمواد الخطرة"],"explanation":"ينص دليل مونتانا على أن جميع المركبات الناقلة للركاب (الحافلات) والمركبات الموسومة بلوحات المواد الخطرة مطلوب منها التوقف عند المعبر؛ أما الشاحنات المحملة العادية فلا يُطلب منها ذلك ما لم تتطلبه الحمولة أو القانون. المصدر: دليل CDL في مونتانا، القسمان 2.15.2 و2.15.4."},"63":{"q":"بموجب قانون الحافلات المدرسية في مونتانا، عندما تتوقف حافلة مدرسية على الطريق وأضواؤها الحمراء وامضة، يجب على السائق المقترب أن يتوقف على مسافة لا تقل عن نحو كم تقريباً من الحافلة؟","options":["20 قدماً","50 قدماً","30 قدماً","10 أقدام"],"explanation":"تتطلب مونتانا من السائقين المقتربين من أي اتجاه التوقف على مسافة لا تقل عن نحو 30 قدماً من حافلة مدرسية تعرض أضواء حمراء وامضة، والبقاء متوقفين حتى تنطفئ الأضواء الحمراء. المصدر: MCA 61-8-351 (مقابلة أو تجاوز حافلة مدرسية)."},"64":{"q":"على طريق سريع في مونتانا ذي مسارات منفصلة (مثل طريق مقسوم يكون فيه الاتجاه المعاكس على مسار منفصل مادياً)، يجب على السائق الذي يقابل حافلة مدرسية متوقفة على المسار الآخر أن:","options":["يتوقف، لأن جميع حركة المرور المقتربة يجب أن تتوقف دائماً","يتوقف فقط إذا كان الحاجز الأوسط أضيق من 30 قدماً","لا يتوقف — المركبات على مسار مختلف لا يلزمها التوقف","يبطئ إلى 10 mph لكن لا يلزمه التوقف توقفاً كاملاً"],"explanation":"استثناء مونتانا: لا يلزم السائق على طريق سريع ذي مسارات منفصلة أن يتوقف عند مقابلة أو تجاوز حافلة مدرسية موجودة على مسار مختلف. ويرتبط الاستثناء بـ«المسارات المنفصلة»، وليس مجرد خط مركزي مرسوم. المصدر: MCA 61-8-351."},"65":{"q":"عندما تُفعِّل حافلة مدرسية في مونتانا أضواءها الكهرمانية (الصفراء) الوامضة فقط، يُطلب من السائق المقترب أن:","options":["يبطئ إلى سرعة معقولة ويكون مستعداً للتوقف","يتوقف توقفاً كاملاً على مسافة لا تقل عن 30 قدماً فوراً","يحافظ على سرعته لأن الأضواء الكهرمانية لا تحمل أي واجب","يتوقف فقط إذا كان الأطفال ظاهرين على جانب الطريق"],"explanation":"يعني الوميض الكهرماني أن الحافلة تستعد للتوقف؛ ويتطلب قانون مونتانا من السائقين الإبطاء إلى سرعة معقولة والاستعداد للتوقف. وينشأ واجب التوقف عند تفعيل الأضواء الحمراء. المصدر: MCA 61-8-351."},"66":{"q":"بموجب قانون التنحي جانباً (Move Over) في مونتانا، عند الاقتراب من مركبة طوارئ أو مركبة عامل طرق متوقفة على طريق بين الولايات وعندما يكون تغيير المسار ممكناً، يجب على السائق تخفيض السرعة إلى ما لا يقل عن كم تحت الحد المعلن؟","options":["10 mph تحت الحد المعلن","30 mph تحت الحد المعلن","20 mph تحت الحد المعلن","5 mph تحت الحد المعلن"],"explanation":"يتطلب MCA 61-8-388 تخفيض السرعة إلى 20 mph تحت الحد المعلن على طريق بين الولايات عندما يكون تغيير المسار ممكناً (والانتقال إلى مسار غير مجاور). وإذا كان تغيير المسار غير آمن، يجب على السائق الإبطاء إلى نصف الحد المعلن. المصدر: MCA 61-8-388."},"67":{"q":"بموجب قانون التنحي جانباً في مونتانا، على طريق سريع تابع للولاية أو طريق مقاطعة حيث يكون تغيير المسار ممكناً، يكون تخفيض السرعة المطلوب عند تجاوز مركبة طوارئ متوقفة لا يقل عن:","options":["20 mph تحت الحد المعلن","15 mph تحت الحد المعلن","10 mph تحت الحد المعلن","30 mph تحت الحد المعلن"],"explanation":"على طريق سريع تابع للولاية أو طريق مقاطعة، يتطلب MCA 61-8-388 الإبطاء إلى 30 mph تحت الحد المعلن عندما يكون تغيير المسار ممكناً؛ وإذا كان تغيير المسار غير آمن، يجب الإبطاء إلى نصف الحد المعلن. المصدر: MCA 61-8-388."},"68":{"q":"بموجب قانون التنحي جانباً في مونتانا، إذا كان السائق غير قادر على تغيير المسار بأمان عند الاقتراب من مركبة طوارئ متوقفة، فإلى أي سرعة يجب أن يخفض؟","options":["نصف الحد الأقصى المعلن للسرعة","20 mph بغض النظر عن الحد المعلن","توقف كامل حتى يخلو المكان","10 mph تحت الحد المعلن"],"explanation":"عندما لا يمكن تغيير المسار بأمان، يتطلب MCA 61-8-388 التخفيض إلى نصف الحد الأقصى المعلن للسرعة مع المتابعة بحذر. المصدر: MCA 61-8-388."},"69":{"q":"على طريق سريع متعدد المسارات في مونتانا، يكون المطلب الأساسي لقانون التنحي جانباً عند الاقتراب من مركبة طوارئ متوقفة (حيث لا يوجد حد سرعة مؤقت معلن) هو أن:","options":["تتوقف توقفاً كاملاً في المسار الأيمن","تنتقل إلى مسار غير مجاور للمركبة المتوقفة، إذا أمكن فعل ذلك بأمان","تطلق بوقك باستمرار أثناء التجاوز","تقود على الكتف لإعطاء أقصى مساحة"],"explanation":"يوجّه MCA 61-8-388 السائقين على طريق سريع متعدد المسارات إلى إخلاء المسار المجاور لمركبة الطوارئ أو عامل الطرق المتوقفة عندما يكون ذلك آمناً؛ وإذا لم يكن ذلك ممكناً، فالإبطاء كما هو مطلوب والتجاوز بحذر. المصدر: MCA 61-8-388."},"70":{"q":"إذا اضطر سائق CDL في مونتانا إلى التوقف على كتف الطريق، فخلال كم دقيقة يجب وضع أجهزة التحذير؟","options":["خلال 5 دقائق","خلال 10 دقائق","خلال 15 دقيقة","خلال 30 دقيقة"],"explanation":"يجب على الشاحنة أو الحافلة المتوقفة أن تضع أجهزة التحذير الطارئة خلال 10 دقائق من التوقف على الطريق أو الكتف. المصدر: دليل CDL في مونتانا، القسم 2.5 (التواصل / أجهزة التحذير)."},"71":{"q":"عندما يتوقف سائق CDL في مونتانا على طريق باتجاه واحد أو طريق مقسوم، أين تُوضع أجهزة التحذير الثلاثة؟","options":["10 أقدام و50 قدماً و150 قدماً نحو حركة المرور المقتربة","10 أقدام و100 قدم و200 قدم نحو حركة المرور المقتربة","10 أقدام، و100 قدم أمام المركبة و100 قدم خلفها","15 قدماً و50 قدماً و100 قدم نحو حركة المرور المقتربة"],"explanation":"على طريق باتجاه واحد أو طريق مقسوم، ضع أجهزة التحذير على مسافات 10 أقدام و100 قدم و200 قدم نحو حركة المرور المقتربة. المصدر: دليل CDL في مونتانا، القسم 2.5 (وضع أجهزة التحذير)."},"72":{"q":"على طريق غير مقسوم باتجاهين في مونتانا ينقل حركة المرور في كلا الاتجاهين، تُوضع المثلثات العاكسة الثلاثة لمركبة تجارية متوقفة عند:","options":["ضمن 10 أقدام من المركبة، و100 قدم إلى الأمام و100 قدم إلى الخلف","10 أقدام و100 قدم و200 قدم، جميعها خلف المركبة","50 قدماً و100 قدم و200 قدم نحو حركة المرور القادمة فقط","ضمن 10 أقدام، و200 قدم إلى الأمام و200 قدم إلى الخلف"],"explanation":"على طريق بمسارين باتجاهين أو طريق غير مقسوم، ضع جهازاً واحداً ضمن 10 أقدام من المركبة وجهازاً على بعد 100 قدم أماماً وآخر على بعد 100 قدم خلفاً، في المسار/الكتف الذي توقفت فيه. المصدر: دليل CDL في مونتانا، القسم 2.5."},"73":{"q":"كم عدد المثلثات العاكسة الحمراء التي يجب أن تحملها مركبة CDL في مونتانا كأجهزة تحذير طارئة مطلوبة؟","options":["اثنان","ثلاثة","أربعة","ستة"],"explanation":"معدات التحذير المطلوبة هي ثلاثة مثلثات عاكسة حمراء (أو بدائل مثل 6 شعلات أو 3 شعلات احتراق سائلة). المصدر: دليل CDL في مونتانا، القسم 2.1 (فحص المركبة) والقسم 2.5."},"74":{"q":"على طريق في مونتانا حيث يحجب تل أو منعطف رؤية مركبة تجارية متوقفة ضمن 500 قدم، ينبغي على السائق أن:","options":["يضع المثلثات الثلاثة جميعها ضمن 10 أقدام من المصد","يحرّك المثلث الخلفي إلى الوراء على الطريق أبعد من العائق ليحصل المرور على تحذير","يترك المثلثات في مواضعها القياسية ويعتمد على أضواء التحذير الوامضة","يضع مثلثاً على بُعد 500 قدم تماماً أمام العائق"],"explanation":"إذا منع تل أو منعطف أو عائق السائقين من رؤية المركبة ضمن 500 قدم، فحرّك جهاز التحذير الخلفي إلى الوراء أبعد من العائق ليحصل المرور المقترب على تحذير في الوقت المناسب. المصدر: دليل CDL في مونتانا، القسم 2.5."},"75":{"q":"ينبغي على سائق حافلة مدرسية في مونتانا يقترب من معبر سكة حديدية أن يفعّل أضواء الخطر في الحافلة على مسافة تقريبية كم قبل المعبر؟","options":["نحو 50 قدماً قبل المعبر","نحو 500 قدم قبل المعبر","فقط بعد التوقف عند المعبر","نحو 200 قدم قبل المعبر"],"explanation":"تستدعي إجراءات الحافلات المدرسية في مونتانا تفعيل أضواء الخطر على بُعد نحو 200 قدم قبل المعبر، ثم التوقف على مسافة 15 إلى 50 قدماً من أقرب سكة. المصدر: دليل CDL في مونتانا، القسم 10 (الحافلات المدرسية)، إجراءات المعبر."},"76":{"q":"على طريق بين الولايات في مونتانا ضمن منطقة حضرية يبلغ تعدادها 50,000 نسمة أو أكثر، يكون حد السرعة لمركبات الركاب:","options":["80 mph في جميع الأوقات","75 mph نهاراً، 65 mph ليلاً","55 mph في جميع الأوقات","65 mph في جميع الأوقات"],"explanation":"بينما تسمح الطرق الريفية بين الولايات للسيارات بـ 80 mph، ينخفض الحد إلى 65 mph على أقسام الطريق بين الولايات الواقعة ضمن منطقة حضرية يبلغ تعدادها 50,000 نسمة أو أكثر. المصدر: MCA 61-8-303 (قيود السرعة)."},"77":{"q":"حيث ينطبق قانون التنحي جانباً، تتطلب مونتانا أيضاً من السائقين الامتثال لأي مما يلي إذا وُجد في الموقع؟","options":["توجيهات منظّم المرور أو لوحة حد سرعة مؤقت معلنة","فقط تعليمات المرسل عبر الراديو","لا شيء إضافي بمجرد تغيير مسار واحد","توقف كامل إلزامي عند كل موقع طوارئ"],"explanation":"يتطلب MCA 61-8-388 من السائقين اتباع توجيهات أي منظّم مرور أو لوحة حد سرعة مؤقت معلنة؛ ولا تنطبق التخفيضات القانونية بالـ mph إلا عند عدم وجود حد مؤقت معلن. المصدر: MCA 61-8-388."},"78":{"q":"رخصة CDL من الفئة A في مونتانا تُصدر بعد اختبار مهارات في تركيبة موصولة بخطاف جر (pintle hook) وليس بعجلة خامسة، تحمل أي قيد؟","options":["قيد «K» يقصر السائق على القيادة داخل الولاية فقط","قيد «L» للمركبات بلا فرامل هوائية","قيد «Z» لأنظمة الفرامل الهوائية الجزئية","قيد «O» يحظر تشغيل تركيبة جرار/نصف مقطورة بعجلة خامسة"],"explanation":"تضع مونتانا قيد «O» على رخصة الفئة A عندما يُجرى اختبار المهارات في تركيبة موصولة بخطاف جر أو وصلة أخرى غير العجلة الخامسة، ما يمنع تشغيل جرار/نصف مقطورة بعجلة خامسة. المصدر: دليل CDL في مونتانا (قسم قيود الرخصة/التصديقات)."},"79":{"q":"أي جهة في مونتانا تُصدر فعلياً رخصة القيادة التجارية (CDL) وتعالج الطلب في مكتب المقاطعة؟","options":["الإدارة الاتحادية لسلامة ناقلي البضائع (FMCSA)","شعبة المركبات الآلية في مونتانا (MVD)","وزارة النقل في مونتانا (MDT)","دورية الطرق السريعة في مونتانا"],"explanation":"في مونتانا تُصدر رخصة CDL من قبل شعبة المركبات الآلية (MVD)، ويُنهي المتقدمون العملية في مكتب رخص القيادة بالمقاطعة. تدير MDT (النقل) برنامج اختبار المهارات وELDT، لكن الرخصة نفسها تُصدر من MVD. المصدر: صفحات CDL لشعبة MVD في مونتانا و«عشر خطوات سهلة للحصول على CDL» من MDT."},"80":{"q":"بعد اجتيازك اختبار مهارات CDL في مونتانا، أين يجب أن تذهب لإصدار الرخصة التجارية فعلياً؟","options":["إلى ممتحن مهارات MDT الذي يطبعها على الفور","إلى موقع سجل مزودي التدريب التابع لـ FMCSA","العودة إلى مكتب MVD بالمقاطعة لإصدار الرخصة","تُرسل تلقائياً بالبريد دون الحاجة إلى زيارة أخرى"],"explanation":"تنص «عشر خطوات سهلة للحصول على CDL» من MDT على أن الممتحن يرسل نتائج اختبار المهارات إلى MVD، لكن يجب على المتقدم العودة إلى MVD بالمقاطعة لإصدار الرخصة التجارية الجديدة. المصدر: «عشر خطوات سهلة للحصول على CDL» من MDT، الخطوة 10."},"81":{"q":"بموجب القواعد الاتحادية المعتمدة في مونتانا، كم يجب أن تحتفظ بتصريح المتعلم التجاري (CLP) قبل أن يحق لك إجراء اختبار مهارات CDL (اختبار الطريق)؟","options":["14 يوماً على الأقل","7 أيام على الأقل","30 يوماً على الأقل","60 يوماً على الأقل"],"explanation":"تتطلب قواعد FMCSA المطبقة في مونتانا الاحتفاظ بتصريح CLP لمدة 14 يوماً كحد أدنى قبل إجراء اختبار المهارات، حتى عندما يكون حامل CDL الحالي مجرد مُرقٍّ لرخصته. المصدر: «عشر خطوات سهلة للحصول على CDL» من MDT، الخطوتان 4F و9."},"82":{"q":"لكم تكون مدة صلاحية تصريح المتعلم التجاري (CLP) في مونتانا؟","options":["90 يوماً","60 يوماً","سنة واحدة","180 يوماً"],"explanation":"يكون تصريح CLP في مونتانا صالحاً لمدة 180 يوماً ويجوز تجديده مرة واحدة قبل انتهائه. المصدر: «الحصول على CDL جديد في مونتانا» من شعبة MVD."},"83":{"q":"كم مرة يجوز تجديد تصريح CLP في مونتانا قبل انتهائه؟","options":["مرة واحدة","لا يمكن تجديده","مرتان","ثلاث مرات"],"explanation":"تسمح مونتانا بتجديد تصريح CLP الذي مدته 180 يوماً مرة واحدة قبل انتهائه. المصدر: «الحصول على CDL جديد في مونتانا» من شعبة MVD."},"84":{"q":"قبل أن يتمكن متقدم لأول مرة من الفئة A أو الفئة B من إجراء اختبار المهارات في مونتانا، ما التدريب الذي يجب إكماله وتسجيله في سجل مزودي التدريب التابع لـ FMCSA؟","options":["دورة قيادة دفاعية معتمدة من المقاطعة","تدريب السائق المبتدئ (ELDT)","برنامج مرافقة في القيادة مع دورية الطرق السريعة في مونتانا","صف تصديق الفرامل الهوائية"],"explanation":"منذ 7 فبراير 2022، يُشترط تدريب ELDT من مزود مدرج في سجل مزودي التدريب التابع لـ FMCSA قبل أن يتمكن المتقدم المؤهل من إجراء اختبار مهارات CDL. وMDT نفسها مزود تدريب مسجل. المصدر: «عشر خطوات سهلة للحصول على CDL» من MDT، الخطوة 5؛ صفحة ELDT لـ MDT."},"85":{"q":"يُجرى اختبار مهارات CDL في مونتانا على ثلاثة أجزاء. أي مجموعة تسمّي بشكل صحيح تلك الأجزاء الثلاثة؟","options":["الاختبار التحريري، وفحص النظر، والقيادة على الطريق","فحص ما قبل الرحلة، واختبار الفرامل الهوائية، والقيادة الليلية","فحص ما قبل الرحلة، والتحكم الأساسي بالمركبة، والقيادة على الطريق","الرجوع للخلف، والوصل، واختبار تصديق تحريري"],"explanation":"مثل جميع الولايات، يتكون اختبار المهارات ذو الأجزاء الثلاثة في مونتانا من فحص المركبة ما قبل الرحلة، ومناورات التحكم الأساسي بالمركبة (الرجوع للخلف)، واختبار القيادة على الطريق. المصدر: دليل CDL في مونتانا؛ «عشر خطوات سهلة للحصول على CDL» من MDT، الخطوات 6-9."},"86":{"q":"لكم تكون مدة صلاحية رخصة CDL القياسية في مونتانا قبل وجوب تجديدها (لسائق نموذجي تتراوح أعماره بين 21 و70)؟","options":["8 سنوات","5 سنوات","سنتان","4 سنوات"],"explanation":"تُصدر رخصة القيادة التجارية في مونتانا لمدة 4 سنوات، وهي دورة أقصر من رخصة مونتانا غير التجارية القياسية التي مدتها 8 سنوات. المصدر: «عشر خطوات سهلة للحصول على CDL» من MDT، الخطوة 10؛ صفحة تجديد CDL لشعبة MVD في مونتانا."},"87":{"q":"كم عدد فئات التصديق الذاتي للتشغيل التي يجب على متقدم CDL في مونتانا الاختيار من بينها عند إعلان نوع قيادته؟","options":["اثنتان","أربع","ثلاث","ست"],"explanation":"تستخدم مونتانا فئات التصديق الذاتي الاتحادية الأربع: بين الولايات غير المستثناة، وبين الولايات المستثناة، وداخل الولاية غير المستثناة (مونتانا فقط)، وداخل الولاية المستثناة. المصدر: نموذج تصنيف التصديق الذاتي لـ CDL والوثائق الطبية لشعبة MVD في مونتانا؛ MCA 61-5-141."},"88":{"q":"السائق في مونتانا الذي يعبر حدود الولايات ويجب أن يستوفي جميع معايير التأهيل البدني الاتحادية يصدّق ذاتياً تحت أي فئة؟","options":["بين الولايات غير المستثناة","بين الولايات المستثناة","داخل الولاية غير المستثناة","داخل الولاية المستثناة"],"explanation":"السائق العامل في التجارة بين الولايات الخاضع لمعايير التأهيل البدني في 49 CFR Part 391 يصدّق ذاتياً بوصفه «بين الولايات غير مستثنى» ويجب أن يحتفظ بشهادة فاحص طبي سارية في الملف. المصدر: نموذج التصديق الذاتي لشعبة MVD في مونتانا؛ MCA 61-5-141."},"89":{"q":"أي فئة من التصديق الذاتي تتطلب من السائق تقديم شهادة فاحص طبي DOT سارية والحفاظ عليها لدى ولاية مونتانا؟","options":["بين الولايات المستثناة","داخل الولاية المستثناة","بين الولايات غير المستثناة","أسطول حكومي مستثنى"],"explanation":"يجب على سائقي «بين الولايات غير المستثناة» استيفاء 49 CFR Part 391 وتقديم شهادة فاحص طبي سارية؛ أما الفئات «المستثناة» فلا تتطلب بطاقة طبية في الملف. (كما يتطلب «داخل الولاية غير المستثنى» بطاقة أو بياناً طبياً من مونتانا.) المصدر: نموذج التصديق الذاتي لشعبة MVD في مونتانا؛ MCA 61-5-141."},"90":{"q":"عندما يحصل حامل CDL غير المستثنى في مونتانا على شهادة فاحص طبي DOT جديدة، كيف تُقدَّم إلى الولاية؟","options":["تُودَع فقط لدى صاحب عمل السائق","تُعطى لمكتب MVD بالمقاطعة، الذي يمسحها ضوئياً في سجل القيادة","تُرسل مباشرة بالبريد إلى مكتب FMCSA الوطني في واشنطن","لا حاجة لأي تقديم؛ توقيع الطبيب كافٍ"],"explanation":"يجب على سائقي مونتانا غير المستثنين تقديم الشهادة الطبية إلى مكتب MVD بالمقاطعة عند الحصول عليها وعند كل تجديد؛ ويمسح MVD نسخة ضوئياً في سجل القيادة. المصدر: «عشر خطوات سهلة للحصول على CDL» من MDT، الخطوة 4B؛ MCA 61-5-141."},"91":{"q":"شهادة فاحص طبي DOT القياسية المستخدمة لإبقاء رخصة CDL في مونتانا سارية يجوز إصدارها لمدة أقصاها كم؟","options":["حتى 12 شهراً","حتى 36 شهراً","حتى 24 شهراً","حتى 6 أشهر"],"explanation":"يكون الفحص الطبي DOT سارياً لمدة تصل إلى 24 شهراً؛ ويجوز للفاحص إصدار شهادة أقصر لمراقبة حالة طبية. المصدر: «عشر خطوات سهلة للحصول على CDL» من MDT، الخطوة 2؛ إرشادات CDL الطبية في مونتانا."},"92":{"q":"بموجب MCA 61-5-141، ماذا يحدث لرخصة CDL في مونتانا إذا أخفق حاملها في تقديم شهادة طبية سارية قبل تاريخ انتهائها؟","options":["تُلغى رخصة القيادة الكاملة فوراً","لا يتغير شيء حتى التجديد التالي كل 4 سنوات","يُغرَّم السائق لكنه يحتفظ بكامل امتيازات CDL","يخفض MVD الرخصة التجارية إلى رخصة أساسية (غير CDL)"],"explanation":"يوجّه MCA 61-5-141 الإدارة إلى وسم سجل CDLIS بأنه «غير مصدّق» وتخفيض الرخصة التجارية إلى رخصة أساسية إذا لم تكن هناك شهادة سارية في الملف. المصدر: MCA 61-5-141، التصديق الذاتي على حالة التشغيل."},"93":{"q":"بموجب قانون التصديق الذاتي في مونتانا، خلال كم يوماً يجب على MVD التصرف لتخفيض رخصة CDL بعد انقضاء الشهادة الطبية؟","options":["10 أيام","30 يوماً","60 يوماً","90 يوماً"],"explanation":"يتطلب MCA 61-5-141 من الإدارة التصرف خلال 10 أيام من تحوّل الشهادة إلى غير سارية لوسم السجل بأنه غير مصدّق وتخفيض الرخصة وإخطار السائق. المصدر: MCA 61-5-141."},"94":{"q":"لكم تظل نتائج اختبار المعرفة التحريري المجتاز لـ CDL في مونتانا سارية إذا لم يحصل المتقدم بعد على رخصة CDL؟","options":["ستة أشهر من تاريخ الاجتياز","سنة واحدة من تاريخ الاجتياز","سنتان من تاريخ الاجتياز","180 يوماً من تاريخ الاجتياز"],"explanation":"تبقى نتائج اختبار المعرفة في مونتانا سارية لمدة سنة واحدة من تاريخ الاجتياز؛ وإذا لم يُحصل على CDL خلال تلك السنة، يجب إعادة جميع الاختبارات التحريرية. المصدر: «عشر خطوات سهلة للحصول على CDL» من MDT، الخطوة 4D."},"95":{"q":"في مونتانا، متى يجوز لمتقدم أخفق في اختبار المعرفة التحريري لـ CDL أن يحاول ذلك الاختبار مرة أخرى؟","options":["فقط بعد فترة انتظار مدتها 7 أيام","فقط بعد 14 يوماً","في اليوم التالي","فقط بعد 30 يوماً"],"explanation":"تسمح مونتانا بإعادة اختبار المعرفة التحريري المخفق في اليوم التالي. المصدر: «عشر خطوات سهلة للحصول على CDL» من MDT، الخطوة 4D."},"96":{"q":"في يوم الاختبار، كم من الوقت يتاح لمتقدم في مونتانا لإكمال جزء فحص المركبة ما قبل الرحلة من اختبار المهارات؟","options":["30 دقيقة","60 دقيقة","20 دقيقة","45 دقيقة"],"explanation":"تخصص مونتانا 45 دقيقة لإكمال فحص ما قبل الرحلة في يوم الاختبار؛ وأداء فحص الفرامل بشكل غير صحيح يؤدي إلى الرسوب. المصدر: «عشر خطوات سهلة للحصول على CDL» من MDT، الخطوة 6A."},"97":{"q":"متقدم لـ CDL في مونتانا يحمل بالفعل رخصة قيادة قياسية في مونتانا (غير CDL) يجب أن يقدم رغم ذلك أياً مما يلي في الموعد؟","options":["شهادة ميلاد جديدة في كل مرة","إثبات الإقامة في مونتانا مرة أخرى","شهادة فحص طبي DOT (فاحص طبي) سارية","نموذج تصريح من دورية الطرق السريعة في مونتانا"],"explanation":"يجب على المتقدمين الذين يحملون بالفعل رخصة قياسية في مونتانا تقديم إثبات رقم الضمان الاجتماعي، وإثبات الحضور المصرّح به، وشهادة فحص طبي DOT (فاحص طبي) سارية؛ أما إثبات الهوية/الإقامة فكان موجوداً بالفعل في الملف. المصدر: «عشر خطوات سهلة للحصول على CDL» من MDT، الوثائق المطلوبة."},"98":{"q":"ما الحد الأدنى للعمر للحصول على رخصة CDL في مونتانا للقيادة التجارية داخل الولاية (مونتانا فقط) مقابل القيادة بين الولايات؟","options":["21 داخل الولاية و25 بين الولايات","18 لكل من داخل الولاية وبين الولايات","16 داخل الولاية و18 بين الولايات","18 داخل الولاية و21 بين الولايات"],"explanation":"تتطلب مونتانا أن يكون المتقدم 18 عاماً على الأقل لقيادة مركبة تجارية داخل الولاية (داخل مونتانا) و21 عاماً على الأقل للقيادة بين الولايات. المصدر: دليل CDL في مونتانا؛ متطلبات CDL لشعبة MVD في مونتانا."}}};
